def _write_modules(tmp_dir: pathlib.Path) -> None:
    """Write all embedded module files to a temporary directory."""
    for name, code in _EMBEDDED_MODULES.items():
        (tmp_dir / name).write_text(code)


def _load_module(path: pathlib.Path, mod_name: str) -> types.ModuleType:
    spec = importlib.util.spec_from_file_location(mod_name, path)
    if spec is None or spec.loader is None:
        raise ImportError(f"Cannot load {path}")
    mod = importlib.util.module_from_spec(spec)
    sys.modules[mod_name] = mod
    spec.loader.exec_module(mod)  # type: ignore[attr-defined]
    return mod


def _run_module(name: str, path: pathlib.Path) -> tuple[int, int]:
    """
    Run a module's self-test by importing it and calling standard test hooks.
    Returns (pass_count, fail_count).
    """
    mod_name = name.replace(".py", "").replace("-", "_")
    mod = _load_module(path, mod_name)

    passes = 0
    fails = 0

    # Standard hook 1: run_self_tests()
    if hasattr(mod, "run_self_tests"):
        result = mod.run_self_tests()
        if isinstance(result, int):
            fails += result
        # passes are approximated from doctest output

    # Standard hook 2: run_integration_tests()
    if hasattr(mod, "run_integration_tests"):
        result = mod.run_integration_tests()
        if isinstance(result, int):
            fails += result

    # Standard hook 3: run_self_tests() (v14–v17 pattern)
    if hasattr(mod, "_pass") and hasattr(mod, "_fail"):
        passes += getattr(mod, "_pass", 0)
        fails += getattr(mod, "_fail", 0)

    return passes, fails


def _run_all() -> None:
    print("=" * 70)
    print("OUROBOROS_RUN_ALL.py — Ouroboros Thesis v14 through v19.0")
