    print(f"Running {len(_MODULE_FILES)} modules...")
    print("=" * 70)

    with tempfile.TemporaryDirectory() as tmp_str:
        tmp_dir = pathlib.Path(tmp_str)
        _write_modules(tmp_dir)

        total_pass = 0
        total_fail = 0
        results = []

        for name in _MODULE_FILES:
            path = tmp_dir / name
            doi = _MODULE_DOIS.get(name, "—")
            t0 = time.time()
            print(f"\n  [{name}]")
            try:
                _, fails = _run_module(name, path)
                elapsed = time.time() - t0
                if fails == 0:
                    status = "GREEN"
                    total_pass += 1
                else:
                    status = f"RED ({fails} fail)"
                    total_fail += fails
                print(f"    Status: {status}  DOI: {doi}  ({elapsed:.2f}s)")
                results.append((name, status))
            except Exception as e:
                print(f"    ERROR: {e}")
                total_fail += 1
                results.append((name, f"ERROR: {e}"))

    print("\n" + "=" * 70)
    print("RESULTS TABLE")
    print("=" * 70)
    for name, status in results:
        pad = " " * (45 - len(name))
        print(f"  {name}{pad}{status}")
    print("=" * 70)
    print(f"  Modules: {len(_MODULE_FILES)} total")
    print(f"  GREEN:   {len([r for r in results if 'GREEN' in r[1]])}")
    print(f"  RED/ERR: {len([r for r in results if 'GREEN' not in r[1]])}")
    print(f"  Total failures: {total_fail}")
    print("=" * 70)

    if total_fail == 0:
        print("\nGREEN — all modules pass")
    else:
        print(f"\nRED — {total_fail} failure(s) across modules")

    sys.exit(0 if total_fail == 0 else 1)


