from __future__ import annotations

import math
import sys
import time
from dataclasses import dataclass
from pathlib import Path

# Number of Λ-axes — fixed by the thesis.
LAMBDA_AXES_COUNT: int = 9


# ─────────────────────────────────────────────────────────────────────
# A3 NORMALIZATION — geometric mean over 9 Λ-axes
# ─────────────────────────────────────────────────────────────────────
# Aczel 1966 functional-equation closure form.  In the doctrine
# setting, geometric mean is chosen over arithmetic mean because it
# is invariant under axis-wise scaling and collapses to 0 if any
# single axis hits 0 — a single non-compliant axis fails the gate.

def a3_normalize(axes: list[float]) -> float:
    if len(axes) != LAMBDA_AXES_COUNT:
        raise ValueError(f"A3 expects {LAMBDA_AXES_COUNT} axes, got {len(axes)}")
    if any(a < 0.0 or a > 1.0 for a in axes):
        raise ValueError("each axis must be in [0,1]")
    if any(a == 0.0 for a in axes):
        return 0.0  # one bad axis collapses the gate
    # geometric mean = exp( mean of logs )
    return math.exp(sum(math.log(a) for a in axes) / LAMBDA_AXES_COUNT)


# ─────────────────────────────────────────────────────────────────────
# HUKLLA HALT-ELIGIBILITY — read-only safety predicate
# ─────────────────────────────────────────────────────────────────────
# A decision trace records which canonical-state keys it READ and
# which it WROTE.  HUKLLA says: a trace is halt-eligible iff its
# write set is empty.  This is the read-only safety predicate.

@dataclass(frozen=True)
class DecisionTrace:
    span_id: int
    reads:  tuple[str, ...]    # canonical-state keys read
    writes: tuple[str, ...]    # canonical-state keys written

def hukLLA_halt_eligible(t: DecisionTrace) -> bool:
    return len(t.writes) == 0


# ─────────────────────────────────────────────────────────────────────
# OVERWATCH READ-ONLY INVARIANT
# ─────────────────────────────────────────────────────────────────────
# A composite trace (e.g. multi-agent span composition) is read-only
# iff every individual trace inside it is read-only.

def overwatch_read_only(traces: list[DecisionTrace]) -> bool:
    return all(hukLLA_halt_eligible(t) for t in traces)


# ─────────────────────────────────────────────────────────────────────
# DPI BOUND (Cover-Thomas 2006, Theorem 2.8.1)
# ─────────────────────────────────────────────────────────────────────
# For any deterministic function f:
#                    H( f(X) )  ≤  H(X)
# Receipt-chain operators that compress a fine-grained distribution
# to a coarser one cannot INCREASE Shannon entropy — they can at most
# preserve it (when f is a bijection).

def shannon_entropy_bits(probs: list[float]) -> float:
    return -sum(p * math.log2(p) for p in probs if p > 0)

def dpi_bound_satisfied(input_probs: list[float],
                        output_probs: list[float]) -> bool:
    # The bound: H(output) <= H(input), modulo numeric slack.
    return shannon_entropy_bits(output_probs) <= shannon_entropy_bits(input_probs) + 1e-9


# ─────────────────────────────────────────────────────────────────────
# CROSS-COMPONENT COMPOSITE INVARIANT
# ─────────────────────────────────────────────────────────────────────
# HUKLLA ∧ OVERWATCH ∧ DPI on a composite span.

def doctrine_cross_invariant(traces: list[DecisionTrace],
                              input_probs: list[float],
                              output_probs: list[float]) -> bool:
    return (overwatch_read_only(traces)
            and dpi_bound_satisfied(input_probs, output_probs))


# ─────────────────────────────────────────────────────────────────────
# SELF-TESTS
# ─────────────────────────────────────────────────────────────────────

_pass = 0
_fail = 0

def _check(cond: bool, label: str) -> None:
    global _pass, _fail
    mark = "\\033[92mok  \\033[0m" if cond else "\\033[91mFAIL\\033[0m"
    print(f"  {mark}  {label}")
    _pass += int(cond)
    _fail += int(not cond)


def run_self_tests() -> None:
    print("\\n=== A3 normalization ===")
    _check(abs(a3_normalize([1.0]*LAMBDA_AXES_COUNT) - 1.0) < 1e-12,
           "A3 of all-ones = 1.0")
    _check(a3_normalize([0.5]*LAMBDA_AXES_COUNT) == 0.5,
           "A3 of all-0.5 = 0.5 (geometric-mean preserves uniform)")
    _check(a3_normalize([0.0] + [1.0]*8) == 0.0,
           "A3 with one zero axis collapses to 0")
    try:
        a3_normalize([1.0]*8)
        _check(False, "A3 wrong axis count should raise")
    except ValueError:
        _check(True, "A3 wrong axis count raises")
    try:
        a3_normalize([1.5]*9)
        _check(False, "A3 axis > 1 should raise")
    except ValueError:
        _check(True, "A3 axis > 1 raises")

    print("\\n=== HUKLLA halt-eligibility ===")
    _check(hukLLA_halt_eligible(DecisionTrace(1, ("k",), ())),
           "read-only trace is halt-eligible")
    _check(not hukLLA_halt_eligible(DecisionTrace(1, (), ("k",))),
           "write-bearing trace is NOT halt-eligible")
    _check(hukLLA_halt_eligible(DecisionTrace(1, ("a","b","c"), ())),
           "multi-read trace still halt-eligible")

    print("\\n=== OVERWATCH read-only invariant ===")
    _check(overwatch_read_only([
                DecisionTrace(1, ("a",), ()),
                DecisionTrace(2, ("b",), ())]),
           "all-read-only composite is read-only")
    _check(not overwatch_read_only([
                DecisionTrace(1, ("a",), ()),
                DecisionTrace(2, (), ("b",))]),
           "one writer fails composite")
    _check(overwatch_read_only([]),
           "empty composite is vacuously read-only")

    print("\\n=== DPI bound (Cover-Thomas) ===")
    # Uniform on 4 symbols has entropy log2(4) = 2 bits.
    _check(abs(shannon_entropy_bits([0.25]*4) - 2.0) < 1e-9,
           "uniform 4-symbol entropy = 2 bits")
    # Coarsening 4 → 2 (merge pairs) gives entropy <= 1 bit.
    _check(dpi_bound_satisfied([0.25]*4, [0.5, 0.5]),
           "DPI: 4-symbol uniform → 2-symbol uniform satisfies bound")
    # Inverting the direction VIOLATES the bound (the function would
    # have to add randomness, not deterministic).
    _check(not dpi_bound_satisfied([0.5, 0.5], [0.25]*4),
           "DPI: 2-symbol → 4-symbol VIOLATES bound (caught)")
    _check(dpi_bound_satisfied([1.0], [1.0]),
           "DPI: degenerate identity satisfies bound")

    print("\\n=== Cross-component composite invariant ===")
    _check(doctrine_cross_invariant(
                [DecisionTrace(1, ("a",), ())],
                [0.25]*4, [0.5, 0.5]),
           "holds on read-only + DPI-OK")
    _check(not doctrine_cross_invariant(
                [DecisionTrace(1, (), ("a",))],
                [0.25]*4, [0.5, 0.5]),
           "fails when OVERWATCH fails (writer present)")
    _check(not doctrine_cross_invariant(
                [DecisionTrace(1, ("a",), ())],
                [0.5, 0.5], [0.25]*4),
           "fails when DPI fails (entropy gain)")


