from __future__ import annotations

import math
import sys
import time
from dataclasses import dataclass
from pathlib import Path


# ─────────────────────────────────────────────────────────────────────
# BRAID + REIDEMEISTER R1 IDENTITY
# ─────────────────────────────────────────────────────────────────────
# A braid is a finite tuple of cosignature "strands" — non-zero integers
# encode real cosignatures; 0 encodes an "identity twist" that can be
# inserted or removed in pairs without changing the audit equivalence
# class.  Under a geometric-mean Λ-gate, R1-identity moves are
# invariants because 0-strands are excluded from the geometric mean.

@dataclass(frozen=True)
class Braid:
    strands: tuple[int, ...]

def reidemeister_r1_identity_add(b: Braid, at: int = 0) -> Braid:
    """Insert an identity-twist pair (0,0) at position `at`."""
    return Braid(strands=b.strands[:at] + (0, 0) + b.strands[at:])

def reidemeister_r1_identity_remove(b: Braid, at: int = 0) -> Braid:
    """Remove an identity-twist pair (0,0) at position `at`, if present."""
    if (at + 1 < len(b.strands)
            and b.strands[at] == 0
            and b.strands[at + 1] == 0):
        return Braid(strands=b.strands[:at] + b.strands[at + 2:])
    return b

def braid_lambda_gate(b: Braid) -> float:
    """Geometric mean of strand magnitudes.  0-strands are excluded
    (they are identity twists).  Empty / all-zero braid returns 1.0
    by convention."""
    nonzero = [abs(s) for s in b.strands if s != 0]
    if not nonzero:
        return 1.0
    return math.exp(sum(math.log(s) for s in nonzero) / len(nonzero))


# ─────────────────────────────────────────────────────────────────────
# CATONI 2007 PAC-BAYES BOUND
# ─────────────────────────────────────────────────────────────────────
# Bound on the true risk R(Q) of a posterior Q given:
#   - empirical_risk  R̂(Q)
#   - kl_divergence   KL(Q||P) for prior P
#   - n_samples       N
#   - confidence      δ
#
# Slack term: sqrt( (KL + log(2/δ)) / (2N) )
# At low empirical risk this is strictly tighter than McAllester 1999.

def catoni_pac_bayes_bound(empirical_risk: float,
                            kl_divergence: float,
                            n_samples: int,
                            confidence_delta: float) -> float:
    if not (0.0 <= empirical_risk <= 1.0):
        raise ValueError("empirical_risk must be in [0,1]")
    if kl_divergence < 0.0:
        raise ValueError("KL divergence must be non-negative")
    if n_samples <= 0:
        raise ValueError("n_samples must be positive")
    if not (0.0 < confidence_delta < 1.0):
        raise ValueError("confidence_delta must be in (0,1)")
    slack = math.sqrt(
        (kl_divergence + math.log(2.0 / confidence_delta))
        / (2.0 * n_samples)
    )
    return min(1.0, empirical_risk + slack)


# ─────────────────────────────────────────────────────────────────────
# KHIPU DAG  — directed-acyclic receipt-DAG with cycle detection
# ─────────────────────────────────────────────────────────────────────
# Khipu is the directed-acyclic generalization of the linear receipt
# bus.  Each receipt has zero or more parent receipts (the "knots"
# it descends from).  Cycle detection is standard DFS coloring:
# WHITE (unseen), GRAY (in stack), BLACK (finished).
# A back-edge to a GRAY node is a cycle.

@dataclass(frozen=True)
class KhipuReceipt:
    rid: int
    parents: tuple[int, ...]
    payload: int

def khipu_dag_is_acyclic(receipts: list[KhipuReceipt]) -> bool:
    by_id = {r.rid: r for r in receipts}
    color: dict[int, int] = {}   # 0 white, 1 gray, 2 black

    def dfs(node: int) -> bool:
        c = color.get(node, 0)
        if c == 1:
            return False      # back-edge → cycle
        if c == 2:
            return True       # already finished, no cycle below
        color[node] = 1
        r = by_id.get(node)
        if r is not None:
            for p in r.parents:
                if not dfs(p):
                    return False
        color[node] = 2
        return True

    return all(dfs(r.rid) for r in receipts)


# ─────────────────────────────────────────────────────────────────────
# SELF-TESTS
# ─────────────────────────────────────────────────────────────────────

_pass = 0
_fail = 0

def _check(cond: bool, label: str) -> None:
    global _pass, _fail
    mark = "\\033[92mok  \\033[0m" if cond else "\\033[91mFAIL\\033[0m"
    print(f"  {mark}  {label}")
    _pass += int(cond)
    _fail += int(not cond)


def run_self_tests() -> None:
    print("\\n=== Audit-Reidemeister R1-identity invariance ===")
    b0 = Braid(strands=(1, 2, 3))
    b1 = reidemeister_r1_identity_add(b0, at=1)
    _check(b1.strands == (1, 0, 0, 2, 3), "R1 identity-add inserts (0,0)")
    _check(abs(braid_lambda_gate(b0) - braid_lambda_gate(b1)) < 1e-12,
           "Λ-gate invariant under R1 identity-add")
    b2 = reidemeister_r1_identity_remove(b1, at=1)
    _check(b2 == b0, "R1 identity-remove inverts identity-add")
    _check(abs(braid_lambda_gate(b0) - braid_lambda_gate(b2)) < 1e-12,
           "Λ-gate invariant after round-trip add+remove")
    # Multiple identities chained
    b3 = reidemeister_r1_identity_add(reidemeister_r1_identity_add(b0, 0), 2)
    _check(abs(braid_lambda_gate(b0) - braid_lambda_gate(b3)) < 1e-12,
           "Λ-gate invariant under repeated R1 moves")

    print("\\n=== Catoni 2007 PAC-Bayes bound ===")
    # Low empirical risk + small KL + many samples → small slack
    bound_low = catoni_pac_bayes_bound(empirical_risk=0.05,
                                        kl_divergence=0.1,
                                        n_samples=10_000,
                                        confidence_delta=0.05)
    # High empirical risk + large KL + few samples → large slack
    bound_high = catoni_pac_bayes_bound(empirical_risk=0.5,
                                         kl_divergence=10.0,
                                         n_samples=100,
                                         confidence_delta=0.05)
    _check(bound_low < bound_high, "low-risk regime is tighter")
    _check(0.05 <= bound_low <= 1.0, "bound stays in [emp, 1]")
    _check(bound_high <= 1.0, "bound clamped at 1.0")
    # Edge cases
    try:
        catoni_pac_bayes_bound(1.5, 0.1, 100, 0.05)
        _check(False, "rejects empirical_risk > 1")
    except ValueError:
        _check(True, "rejects empirical_risk > 1")
    try:
        catoni_pac_bayes_bound(0.1, -1.0, 100, 0.05)
        _check(False, "rejects negative KL")
    except ValueError:
        _check(True, "rejects negative KL")
    try:
        catoni_pac_bayes_bound(0.1, 0.1, 0, 0.05)
        _check(False, "rejects n_samples = 0")
    except ValueError:
        _check(True, "rejects n_samples = 0")
    try:
        catoni_pac_bayes_bound(0.1, 0.1, 100, 1.5)
        _check(False, "rejects confidence outside (0,1)")
    except ValueError:
        _check(True, "rejects confidence outside (0,1)")

    print("\\n=== Khipu DAG cycle detection ===")
    # Linear chain 1 ← 2 ← 3 → acyclic
    chain = [KhipuReceipt(1, (), 0xAA),
             KhipuReceipt(2, (1,), 0xBB),
             KhipuReceipt(3, (2,), 0xCC)]
    _check(khipu_dag_is_acyclic(chain), "linear chain is acyclic")
    # Branching DAG (4 ← 2, 4 ← 3, 2 ← 1, 3 ← 1) → acyclic
    branching = [
        KhipuReceipt(1, (), 0x01),
        KhipuReceipt(2, (1,), 0x02),
        KhipuReceipt(3, (1,), 0x03),
        KhipuReceipt(4, (2, 3), 0x04),
    ]
    _check(khipu_dag_is_acyclic(branching), "diamond DAG is acyclic")
    # Self-loop: receipt 1 lists itself as parent → cyclic
    self_loop = [KhipuReceipt(1, (1,), 0xAA)]
    _check(not khipu_dag_is_acyclic(self_loop), "self-loop detected")
    # 2-cycle: 1 ← 2 and 2 ← 1 → cyclic
    two_cycle = [
        KhipuReceipt(1, (2,), 0xAA),
        KhipuReceipt(2, (1,), 0xBB),
    ]
    _check(not khipu_dag_is_acyclic(two_cycle), "2-cycle detected")
    # Empty list → vacuously acyclic
    _check(khipu_dag_is_acyclic([]), "empty Khipu is acyclic")


