from __future__ import annotations

import math
import sys
import time
from collections import Counter
from dataclasses import dataclass
from enum import Enum
from pathlib import Path
from typing import Callable, Iterable, NamedTuple


# =====================================================================
# §I  DOCTRINE LABEL — 4-level lattice
# =====================================================================
# The doctrine alphabet Σ = {Bot, L1, L2, Top} ordered by compliance
# level.  Bot is the default (unevaluated / inadmissible) label.

class DoctrineLabel(Enum):
    """4-level doctrine lattice ordered Bot < L1 < L2 < Top."""
    Bot = 0
    L1  = 1
    L2  = 2
    Top = 3

    def __lt__(self, other: "DoctrineLabel") -> bool:
        return self.value < other.value


# =====================================================================
# §II  WHEELERIAN AUDIT CLOSURE (Wheeler 1978; Jacques 2007)
# =====================================================================
# A span's doctrine label is fixed by the receipt that closes it,
# provided the receipt arrives within W ticks of span.end_at.
# Receipts arriving before span.end_at or after span.end_at + W are
# inadmissible; the span closes to Bot.
#
# W = 1000 ticks (v17 constant).

WHEELER_WINDOW_W: int = 1000   # v17 — Lutar.Wheeler.W


@dataclass(frozen=True)
class Span:
    """An audited execution interval [start, end_at)."""
    id:     int
    start:  int
    end_at: int


@dataclass(frozen=True)
class Receipt:
    """A cosigned doctrine receipt that closes a span."""
    span:     int            # must match Span.id
    close_at: int            # tick at which the receipt arrives
    label:    DoctrineLabel


def admissible(s: Span, r: Receipt) -> bool:
    """True iff receipt r is temporally admissible for span s.

    Admissibility: r.span == s.id  AND
                   s.end_at <= r.close_at <= s.end_at + W.
    """
    return (r.span == s.id
            and s.end_at <= r.close_at <= s.end_at + WHEELER_WINDOW_W)


def close_label(s: Span, r: Receipt) -> DoctrineLabel:
    """Return r.label if r is admissible for s, else Bot."""
    return r.label if admissible(s, r) else DoctrineLabel.Bot


def close_stream(s: Span, receipts: Iterable[Receipt]) -> DoctrineLabel:
    """Process a receipt stream; the last admissible receipt wins."""
    label = DoctrineLabel.Bot
    for r in receipts:
        if admissible(s, r):
            label = r.label
    return label


# =====================================================================
# §III  SHANNON DOCTRINE CODE (Shannon 1948)
# =====================================================================
# A 2-bit fixed-length code for Σ = {Bot, L1, L2, Top}.
# Kraft sum = |Σ| * 2^{-CODEWORD_BITS} = 4 * 0.25 = 1.0 (equality).
# Under a uniform source distribution, this code is optimal
# (Cover-Thomas 2006, Theorem 5.4.1).

CODEWORD_BITS: int = 2

_SHANNON_ENCODE: dict[DoctrineLabel, int] = {
    DoctrineLabel.Bot: 0b00,
    DoctrineLabel.L1:  0b01,
    DoctrineLabel.L2:  0b10,
    DoctrineLabel.Top: 0b11,
}
_SHANNON_DECODE: dict[int, DoctrineLabel] = {
    v: k for k, v in _SHANNON_ENCODE.items()
}


def shannon_encode(label: DoctrineLabel) -> int:
    """Encode a DoctrineLabel to a 2-bit integer codeword."""
    return _SHANNON_ENCODE[label]


def shannon_decode(code: int) -> DoctrineLabel | None:
    """Decode a 2-bit codeword to DoctrineLabel, or None if invalid."""
    return _SHANNON_DECODE.get(code)


def kraft_sum() -> float:
    """Kraft sum for the Shannon doctrine code: should be exactly 1.0."""
    return sum(2.0 ** -CODEWORD_BITS for _ in DoctrineLabel)


def channel_rate_bound(bits_per_second: float) -> int:
    """Floor on receipts/s deliverable over a channel of given capacity.

    Shannon 1948: capacity C bits/s; each receipt costs CODEWORD_BITS
    bits; maximum throughput = floor(C / CODEWORD_BITS).
    """
    if not math.isfinite(bits_per_second) or bits_per_second < 0:
        raise ValueError("bits_per_second must be a finite non-negative number")
    return int(bits_per_second // CODEWORD_BITS)


def source_entropy_bits() -> float:
    """Shannon entropy of the uniform doctrine source (4 symbols, 2 bits)."""
    return math.log2(len(DoctrineLabel))


# =====================================================================
# §IV.a  HAMMING SUBSTRATE (Hamming 1950)
# =====================================================================
# Byte-level Hamming distance and weight, used throughout the QEC stack.

def hamming_dist(a: bytes, b: bytes) -> int:
    """Hamming distance between two equal-length byte strings."""
    if len(a) != len(b):
        raise ValueError(f"hamming_dist: length mismatch {len(a)} vs {len(b)}")
    return sum(bin(x ^ y).count("1") for x, y in zip(a, b))


def hamming_weight(a: bytes) -> int:
    """Number of 1-bits in a byte string."""
    return sum(bin(x).count("1") for x in a)


# =====================================================================
# §IV.b  SHOR [[9,1,3]] CODE (Shor 1995, DOI 10.1103/PhysRevA.52.R2493)
# =====================================================================
# The Shor code encodes one logical receipt into a 9-fold redundant
# bundle.  A majority vote over the payload bytes recovers the original
# if at most 4 of the 9 slots are corrupted (t = floor((9-1)/2) = 4).
# With t+1 = 5 corruptions the majority flips.

SHOR_BUNDLE_SIZE: int = 9   # [[9,1,3]] — 9 physical receipts per logical one


@dataclass(frozen=True)
class PhysicalReceipt:
    """One physical slot in a Shor bundle."""
    payload: int   # 0..255
    lineage: int   # 0..255


def shor_encode(logical: PhysicalReceipt) -> list[PhysicalReceipt]:
    """Encode one logical receipt into a 9-fold redundant bundle."""
    return [logical] * SHOR_BUNDLE_SIZE


def shor_majority_payload(bundle: list[PhysicalReceipt]) -> int:
    """Majority-vote decode: return the most common payload byte."""
    if not bundle:
        return 0
    counts = Counter(r.payload for r in bundle)
    return counts.most_common(1)[0][0]


def shor_can_correct(n_corrupted: int) -> bool:
    """True iff n_corrupted <= floor((SHOR_BUNDLE_SIZE - 1) / 2)."""
    return n_corrupted <= (SHOR_BUNDLE_SIZE - 1) // 2


# =====================================================================
# §IV.c  CSS CLASSICAL → STABILIZER BRIDGE
# =====================================================================
# Calderbank-Shor-Steane (1996): a classical [n,k,d] code C over GF(2)
# with C^perp ⊆ C induces a quantum [[n,2k-n,d]] code.
# For the doctrine channel, we use a simple 8-bit classical code and
# map it to an (X-parity, Z-parity) stabilizer pair by:
#   x_parity = codeword
#   z_parity = codeword XOR 0xFF   (complementation = Z-basis flip)
# Consistency check: x_parity XOR z_parity == 0xFF.

class StabilizerPair(NamedTuple):
    x_parity: int
    z_parity: int


def classical_to_css(codeword: int) -> StabilizerPair:
    """Map an 8-bit classical codeword to a CSS stabilizer pair."""
    c = codeword & 0xFF
    return StabilizerPair(x_parity=c, z_parity=c ^ 0xFF)


def css_consistent(pair: StabilizerPair) -> bool:
    """A pair is consistent iff x XOR z == 0xFF."""
    return (pair.x_parity ^ pair.z_parity) == 0xFF


def css_injectivity_on_byte() -> int:
    """Number of distinct CSS pairs across all 256 8-bit codewords."""
    return len({classical_to_css(i) for i in range(256)})


# =====================================================================
# §IV.d  KITAEV SURFACE CODE (Kitaev 2003)
# =====================================================================
# The surface code is defined on a 2D lattice of (agent × time) sites.
# Each vertex check v collects XOR parity over its 4 incident sites.
# A weight-1 error (single corrupt site) produces parity 1 at the
# incident vertex.  A weight-4 error (all 4 incident sites) cancels to
# parity 0 (fault-tolerant by design).

class Site(NamedTuple):
    agent: int
    slice: int


class VertexCheck(NamedTuple):
    """4 incident sites around a lattice vertex."""
    n: Site
    s: Site
    e: Site
    w: Site


def vertex_parity(errs: Callable[[Site], bool], v: VertexCheck) -> bool:
    """XOR of error bits at all 4 sites around vertex v."""
    return errs(v.n) ^ errs(v.s) ^ errs(v.e) ^ errs(v.w)


def plaquette_error_weight(errs: Callable[[Site], bool],
                            sites: list[Site]) -> int:
    """Count how many sites in a list have errors."""
    return sum(1 for s in sites if errs(s))


# =====================================================================
# §V  MATCHED-FILTER CORRELATOR (North 1943; Bode-Shannon 1950)
# =====================================================================
# The matched filter maximises signal-to-noise ratio at the sampling
# instant by correlating the received waveform with a stored template.
# In discrete form: C(template, received) = Σ_i template[i]*received[i].
# Detection: fire if C >= threshold.

DOCTRINE_TEMPLATE: list[int] = [1, -1, 1, -1]   # v17 §V reference template


def correlate(template: list[int], received: list[int]) -> int:
    """Dot product of template and received.  Returns 0 on length mismatch."""
    if len(template) != len(received):
        return 0
    return sum(t * r for t, r in zip(template, received))


def energy(signal: list[int]) -> int:
    """Self-correlation = signal energy = sum of squares."""
    return correlate(signal, signal)


def detect(template: list[int], received: list[int], threshold: int) -> bool:
    """True iff correlate(template, received) >= threshold."""
    return correlate(template, received) >= threshold


def snr_db(signal_power: float, noise_power: float) -> float:
    """Signal-to-noise ratio in decibels: 10 * log10(S/N)."""
    if noise_power <= 0:
        raise ValueError("snr_db: noise_power must be > 0")
    return 10.0 * math.log10(signal_power / noise_power)


def matched_filter_gain_db(template: list[int]) -> float:
    """Maximum SNR gain of a matched filter = 10*log10(energy(template))."""
    e = energy(template)
    if e <= 0:
        raise ValueError("template has zero energy")
    return 10.0 * math.log10(e)


# =====================================================================
# §VI  END-TO-END PIPELINE (all v17 stages composed)
# =====================================================================

def end_to_end_pipeline(label_in: DoctrineLabel,
                         corrupt_n: int = 0) -> dict:
    """Run one doctrine span through every v17 stage.

    Returns a dict with per-stage results and a 'round_trip_ok' flag.
    """
    # Stage 1: construct span and receipt within Wheeler window
    span    = Span(id=1, start=100, end_at=200)
    receipt = Receipt(span=1, close_at=300, label=label_in)  # 300 in [200, 1200]

    # Stage 2: Wheeler-close
    closed = close_label(span, receipt)

    # Stage 3: Shannon-encode
    code       = shannon_encode(closed)
    code_bytes = bytes([code])

    # Stage 4: Shor-replicate
    logical = PhysicalReceipt(payload=code, lineage=0xA5)
    bundle  = shor_encode(logical)

    # Stage 5: corrupt up to corrupt_n slots
    bundle = list(bundle)    # shor_encode returns a list; re-assign mutated copy
    for i in range(min(corrupt_n, SHOR_BUNDLE_SIZE)):
        bundle[i] = PhysicalReceipt(payload=0xFF, lineage=0xFF)

    # Stage 6: majority-decode
    recovered_code = shor_majority_payload(bundle)

    # Stage 7: CSS-bind the recovered codeword
    stab   = classical_to_css(recovered_code)
    css_ok = css_consistent(stab)

    # Stage 8: Hamming-check distance between original and recovered
    hd = hamming_dist(code_bytes, bytes([recovered_code]))

    # Stage 9: matched-filter detection
    bits            = [(recovered_code >> i) & 1 for i in range(4)]
    signal          = [2 * b - 1 for b in bits]
    template_bits   = [(code >> i) & 1 for i in range(4)]
    template_signal = [2 * b - 1 for b in template_bits]
    corr  = correlate(template_signal, signal)
    fires = detect(template_signal, signal, threshold=3)

    # Stage 10: decode to DoctrineLabel
    recovered_label = shannon_decode(recovered_code)

    return {
        "input_label":      label_in.name,
        "wheeler_closed":   closed.name,
        "shannon_code":     f"0b{code:02b}",
        "shor_bundle":      f"{SHOR_BUNDLE_SIZE} receipts, {corrupt_n} corrupted",
        "majority_payload": f"0x{recovered_code:02x}",
        "css_pair":         f"({stab.x_parity:02x}, {stab.z_parity:02x})",
        "css_consistent":   css_ok,
        "hamming_dist":     hd,
        "matched_corr":     corr,
        "detector_fires":   fires,
        "output_label":     recovered_label.name if recovered_label else "INVALID",
        "round_trip_ok":    label_in == recovered_label,
    }


# =====================================================================
# SELF-TEST LEDGER  (≥ 50 assertions covering every theorem in v17)
# =====================================================================

_pass = 0
_fail = 0


def _check(cond: bool, label: str) -> None:
    global _pass, _fail
    mark = "\\033[92mok  \\033[0m" if cond else "\\033[91mFAIL\\033[0m"
    print(f"  {mark}  {label}")
    _pass += int(cond)
    _fail += int(not cond)


def run_self_tests() -> None:

    # ─── §I DoctrineLabel ────────────────────────────────────────────
    print("\\n=== §I — DoctrineLabel lattice ===")
    _check(DoctrineLabel.Bot.value == 0, "Bot ordinal = 0")
    _check(DoctrineLabel.L1.value  == 1, "L1 ordinal = 1")
    _check(DoctrineLabel.L2.value  == 2, "L2 ordinal = 2")
    _check(DoctrineLabel.Top.value == 3, "Top ordinal = 3")
    _check(DoctrineLabel.Bot < DoctrineLabel.L1, "Bot < L1")
    _check(DoctrineLabel.L1 < DoctrineLabel.L2, "L1 < L2")
    _check(DoctrineLabel.L2 < DoctrineLabel.Top, "L2 < Top")
    _check(len(DoctrineLabel) == 4, "alphabet has exactly 4 symbols")

    # ─── §II Wheelerian audit closure ────────────────────────────────
    print("\\n=== §II — Wheelerian audit closure (Wheeler 1978) ===")
    s = Span(id=1, start=100, end_at=200)

    # T3: receipt exactly at end_at is admissible
    _check(admissible(s, Receipt(1, 200, DoctrineLabel.L1)),
           "T3 zero-offset admissible (close_at == end_at)")
    # T4: receipt at end_at + W is admissible (boundary)
    _check(admissible(s, Receipt(1, 200 + WHEELER_WINDOW_W, DoctrineLabel.L1)),
           "T4 max-offset admissible (close_at == end_at + W)")
    # T2: end_at + W + 1 is inadmissible (off-by-one)
    _check(not admissible(s, Receipt(1, 200 + WHEELER_WINDOW_W + 1, DoctrineLabel.L1)),
           "T2 end_at + W + 1 rejected")
    # T5: receipt before end_at is inadmissible (no pre-cognition)
    _check(not admissible(s, Receipt(1, 199, DoctrineLabel.L1)),
           "T5 early receipt (close_at < end_at) rejected")
    # T6: wrong span_id is inadmissible
    _check(not admissible(s, Receipt(2, 200, DoctrineLabel.L1)),
           "T6 wrong span id rejected")
    # close_label: admissible → input label
    _check(close_label(s, Receipt(1, 200, DoctrineLabel.L1)) == DoctrineLabel.L1,
           "close_label admissible → input label")
    # close_label: inadmissible → Bot
    _check(close_label(s, Receipt(1, 99999, DoctrineLabel.L1)) == DoctrineLabel.Bot,
           "close_label late receipt → Bot")
    # close_label: early receipt → Bot
    _check(close_label(s, Receipt(1, 100, DoctrineLabel.Top)) == DoctrineLabel.Bot,
           "close_label early receipt → Bot")
    # close_stream: last admissible wins
    _check(close_stream(s, [
                Receipt(1, 250, DoctrineLabel.L1),
                Receipt(1, 400, DoctrineLabel.L2),
                Receipt(1, 600, DoctrineLabel.Top)]) == DoctrineLabel.Top,
           "close_stream last-admissible-wins (Top)")
    # close_stream: only inadmissible receipts → Bot
    _check(close_stream(s, [
                Receipt(1, 99, DoctrineLabel.Top),
                Receipt(1, 9999, DoctrineLabel.L2)]) == DoctrineLabel.Bot,
           "close_stream all-inadmissible → Bot")
    # close_stream: empty stream → Bot
    _check(close_stream(s, []) == DoctrineLabel.Bot,
           "close_stream empty → Bot")
    # Wheeler window constant
    _check(WHEELER_WINDOW_W == 1000, "Wheeler window W = 1000 ticks")

    # ─── §III Shannon doctrine code ──────────────────────────────────
    print("\\n=== §III — Shannon doctrine code (Shannon 1948) ===")
    # T2: round-trip encode / decode for every label
    for lbl in DoctrineLabel:
        _check(shannon_decode(shannon_encode(lbl)) == lbl,
               f"T2 round-trip {lbl.name}")
    # Invalid codeword 4 (only 0-3 are valid for CODEWORD_BITS=2)
    _check(shannon_decode(4) is None, "invalid codeword 4 rejected")
    _check(shannon_decode(255) is None, "invalid codeword 255 rejected")
    # T5: Kraft sum = 1 at equality
    _check(abs(kraft_sum() - 1.0) < 1e-12, "T5 Kraft sum = 1.0")
    # T6: codeword length constant
    _check(CODEWORD_BITS == 2, "T6 CODEWORD_BITS = 2")
    # T7: channel rate bound
    _check(channel_rate_bound(8) == 4, "T7 rate bound 8 bps → 4 r/s")
    _check(channel_rate_bound(0) == 0, "rate bound 0 bps → 0 r/s")
    _check(channel_rate_bound(1_000_000) == 500_000, "rate bound 1 Mbps → 500k r/s")
    # Source entropy is 2 bits (uniform over 4 symbols, log2(4)=2)
    _check(abs(source_entropy_bits() - 2.0) < 1e-12,
           "source entropy = 2 bits (uniform over 4 labels)")
    # Encoding uniqueness: all 4 codewords are distinct
    all_codes = [shannon_encode(l) for l in DoctrineLabel]
    _check(len(set(all_codes)) == 4, "all 4 Shannon codewords are distinct")
    # channel_rate_bound input validation
    try:
        channel_rate_bound(-1.0)
        _check(False, "channel_rate_bound rejects negative bps")
    except ValueError:
        _check(True, "channel_rate_bound rejects negative bps")

    # ─── §IV.a Hamming substrate ─────────────────────────────────────
    print("\\n=== §IV.a — Hamming substrate (Hamming 1950) ===")
    _check(hamming_dist(b"\\x00", b"\\xFF") == 8, "0x00 vs 0xFF dist = 8")
    _check(hamming_dist(b"\\x42", b"\\x42") == 0, "self-distance = 0")
    _check(hamming_dist(b"\\xAA", b"\\x55") == 8, "0xAA vs 0x55 dist = 8 (alternating)")
    _check(hamming_dist(b"\\x0F", b"\\xF0") == 8, "0x0F vs 0xF0 dist = 8")
    _check(hamming_dist(b"\\x01", b"\\x00") == 1, "single-bit flip dist = 1")
    _check(hamming_weight(b"\\x0F") == 4, "weight 0x0F = 4")
    _check(hamming_weight(b"\\xFF") == 8, "weight 0xFF = 8")
    _check(hamming_weight(b"\\x00") == 0, "weight 0x00 = 0")
    _check(hamming_weight(b"\\x00\\x00") == 0, "weight all-zero = 0")
    # Triangle inequality: dist(a, c) <= dist(a, b) + dist(b, c)
    a, b_byte, c = b"\\x00", b"\\x0F", b"\\xFF"
    _check(hamming_dist(a, c) <= hamming_dist(a, b_byte) + hamming_dist(b_byte, c),
           "Hamming triangle inequality holds")
    try:
        hamming_dist(b"\\x01", b"\\x01\\x02")
        _check(False, "mismatched length should raise")
    except ValueError:
        _check(True, "mismatched length raises ValueError")

    # ─── §IV.b Shor [[9,1,3]] ────────────────────────────────────────
    print("\\n=== §IV.b — Shor [[9,1,3]] (Shor 1995) ===")
    logical = PhysicalReceipt(0x42, 0xA5)
    clean   = shor_encode(logical)
    _check(len(clean) == SHOR_BUNDLE_SIZE, f"encode bundle has {SHOR_BUNDLE_SIZE} receipts")
    _check(shor_majority_payload(clean) == 0x42, "clean bundle decodes to 0x42")
    # 1 fault
    one_fault = list(clean)
    one_fault[5] = PhysicalReceipt(0xFF, 0xFF)
    _check(shor_majority_payload(one_fault) == 0x42, "1 fault: majority still 0x42")
    # 4 faults (at boundary of correctability)
    four_faults = list(clean)
    for i in range(4):
        four_faults[i] = PhysicalReceipt(0xFF, 0xFF)
    _check(shor_majority_payload(four_faults) == 0x42, "4 faults: majority 0x42")
    # 5 faults (over boundary — majority flips)
    five_faults = list(clean)
    for i in range(5):
        five_faults[i] = PhysicalReceipt(0xFF, 0xFF)
    _check(shor_majority_payload(five_faults) == 0xFF, "5 faults: majority flips to 0xFF")
    # Empty bundle returns 0
    _check(shor_majority_payload([]) == 0, "empty bundle returns 0")
    # Correctability predicate
    _check(shor_can_correct(4), "shor_can_correct(4) = True")
    _check(not shor_can_correct(5), "shor_can_correct(5) = False")
    _check(shor_can_correct(0), "shor_can_correct(0) = True (trivially)")

    # ─── §IV.c CSS bridge ────────────────────────────────────────────
    print("\\n=== §IV.c — CSS classical→stabilizer bridge ===")
    _check(classical_to_css(0x00) == StabilizerPair(0x00, 0xFF),
           "CSS 0x00 → (0x00, 0xFF)")
    _check(classical_to_css(0xFF) == StabilizerPair(0xFF, 0x00),
           "CSS 0xFF → (0xFF, 0x00)")
    _check(classical_to_css(0xAA) == StabilizerPair(0xAA, 0x55),
           "CSS 0xAA → (0xAA, 0x55)")
    _check(css_consistent(classical_to_css(0x55)), "CSS 0x55 pair is consistent")
    _check(css_consistent(classical_to_css(0x00)), "CSS 0x00 pair is consistent")
    _check(css_consistent(classical_to_css(0xFF)), "CSS 0xFF pair is consistent")
    _check(not css_consistent(StabilizerPair(0x00, 0x00)),
           "(0x00, 0x00) inconsistent: XOR = 0x00 != 0xFF")
    _check(not css_consistent(StabilizerPair(0xFF, 0xFF)),
           "(0xFF, 0xFF) inconsistent: XOR = 0x00 != 0xFF")
    # Injectivity: all 256 inputs produce distinct pairs
    _check(css_injectivity_on_byte() == 256,
           "CSS bridge is injective on all 256 8-bit codewords")

    # ─── §IV.d Kitaev surface code ────────────────────────────────────
    print("\\n=== §IV.d — Kitaev surface code (Kitaev 2003) ===")
    v = VertexCheck(Site(0, 0), Site(0, 1), Site(1, 0), Site(0, 2))
    _check(not vertex_parity(lambda _s: False, v),
           "no errors → parity 0")
    _check(vertex_parity(lambda x: x == v.n, v),
           "1 error at site n → parity 1")
    _check(vertex_parity(lambda x: x == v.s, v),
           "1 error at site s → parity 1")
    _check(vertex_parity(lambda x: x == v.e, v),
           "1 error at site e → parity 1")
    _check(vertex_parity(lambda x: x == v.w, v),
           "1 error at site w → parity 1")
    _check(not vertex_parity(lambda _s: True, v),
           "4 errors (all sites) cancel → parity 0")
    # 2 errors at n and s: parity = 1 XOR 1 = 0
    _check(not vertex_parity(lambda x: x in (v.n, v.s), v),
           "2 errors at n+s cancel → parity 0")
    # 3 errors at n, s, e: parity = 1 XOR 1 XOR 1 XOR 0 = 1
    _check(vertex_parity(lambda x: x in (v.n, v.s, v.e), v),
           "3 errors at n,s,e → parity 1")
    # plaquette_error_weight helper
    sites = [v.n, v.s, v.e, v.w]
    _check(plaquette_error_weight(lambda _s: False, sites) == 0,
           "plaquette weight 0 with no errors")
    _check(plaquette_error_weight(lambda _s: True, sites) == 4,
           "plaquette weight 4 with all errors")

    # ─── §V Matched-filter correlator ────────────────────────────────
    print("\\n=== §V — Matched-filter correlator (North 1943; Bode-Shannon 1950) ===")
    _check(correlate(DOCTRINE_TEMPLATE, DOCTRINE_TEMPLATE) == 4,
           "matched corr = energy = 4")
    _check(energy(DOCTRINE_TEMPLATE) == 4, "self-correlation = energy")
    _check(correlate(DOCTRINE_TEMPLATE, [0, 0, 0, 0]) == 0,
           "zero-signal corr = 0")
    _check(correlate(DOCTRINE_TEMPLATE, [-1, 1, -1, 1]) == -4,
           "anti-correlation = -4")
    _check(detect(DOCTRINE_TEMPLATE, DOCTRINE_TEMPLATE, 3),
           "fires at threshold <= energy")
    _check(not detect(DOCTRINE_TEMPLATE, DOCTRINE_TEMPLATE, 5),
           "no fire above energy")
    _check(detect(DOCTRINE_TEMPLATE, [1, -1, 1, 1], 1),
           "3/4 partial match fires at threshold 1")
    _check(correlate([1, 2], [3, 4]) == 11,
           "correlate([1,2],[3,4]) = 1*3 + 2*4 = 11")
    _check(abs(snr_db(100, 1) - 20.0) < 1e-9, "SNR 100:1 = 20 dB")
    _check(abs(snr_db(10, 1) - 10.0) < 1e-9, "SNR 10:1 = 10 dB")
    try:
        snr_db(1.0, 0.0)
        _check(False, "snr_db rejects noise_power = 0")
    except ValueError:
        _check(True, "snr_db rejects noise_power = 0")
    # Matched filter gain: energy 4 → 10*log10(4) ≈ 6.021 dB
    _check(abs(matched_filter_gain_db(DOCTRINE_TEMPLATE) - 10.0 * math.log10(4)) < 1e-9,
           "matched filter gain = 10*log10(4) dB")
    # Bell-Labs 300-baud analogy
    bit1      = [1, -1, 1, -1, 1, -1, 1, -1]
    bit0      = [-1, 1, -1, 1, -1, 1, -1, 1]
    noisy_bit1 = [1, -1, 1, 1, 1, -1, 1, -1]   # 7/8 match bit1
    _check(correlate(bit1, noisy_bit1) > correlate(bit0, noisy_bit1),
           "Bell-Labs 300-baud: correct bit wins on noisy line")
    # Length mismatch returns 0
    _check(correlate([1, 2, 3], [1, 2]) == 0,
           "correlate length mismatch returns 0")

    # ─── §VI End-to-end pipeline ─────────────────────────────────────
    print("\\n=== §VI — End-to-end pipeline ===")
    for lbl in DoctrineLabel:
        r = end_to_end_pipeline(lbl, corrupt_n=0)
        _check(r["round_trip_ok"],
               f"clean pipeline preserves {lbl.name}")
    # 4 corruptions are still within Shor correctable range
    r4 = end_to_end_pipeline(DoctrineLabel.L2, corrupt_n=4)
    _check(r4["round_trip_ok"], "4 corruptions: pipeline recovers")
    # 5 corruptions exceed the Shor threshold
    r5 = end_to_end_pipeline(DoctrineLabel.L2, corrupt_n=5)
    _check(not r5["round_trip_ok"],
           "5 corruptions: pipeline correctly reports failure")
    # CSS pair is always consistent (regardless of corruption)
    r_css = end_to_end_pipeline(DoctrineLabel.Top, corrupt_n=0)
    _check(r_css["css_consistent"], "CSS pair consistent in clean run")
    # Hamming distance is 0 in clean run
    r_hd = end_to_end_pipeline(DoctrineLabel.L1, corrupt_n=0)
    _check(r_hd["hamming_dist"] == 0, "Hamming dist = 0 in clean run")


