from __future__ import annotations

import hashlib
import math
import sys
from typing import List, Tuple

# numpy is used only in gauss_forecast; import lazily so stdlib-only
# environments that skip numpy still run the non-forecast functions.
try:
    import numpy as np
    _HAS_NUMPY = True
except ImportError:
    _HAS_NUMPY = False

# ─────────────────────────────────────────────────────────────────────
# §XVII.III — class_number
# ─────────────────────────────────────────────────────────────────────

def class_number(witness_pair_hashes: List[Tuple[str, str]]) -> int:
    """Count the number of Hamming-distance equivalence classes of witness diversity.

    Doctrine reference: V17 §XVII obligation III — Gauß form class-number
    witness-diversity.  Source: Disquisitiones Arithmeticae (1801) §223–§307;
    ouroboros-gauss classNumber (@workspace/ouroboros-gauss).

    Each witness pair (internal_hash, external_hash) is projected to a
    256-bit binary vector via XOR.  Two pairs belong to the same
    equivalence class when their Hamming distance from the zero vector
    (i.e. popcount(xor)) falls in the same decile bucket of
    [0, 256].  The number of non-empty buckets is the returned count.

    Parameters
    ----------
    witness_pair_hashes:
        List of (internal_sha256_hex, external_sha256_hex) tuples.

    Returns
    -------
    int
        Number of distinct Hamming-distance equivalence classes (≥ 1
        when the input is non-empty, 0 when empty).

    Examples
    --------
    >>> class_number([])
    0
    >>> h1 = "a" * 64
    >>> h2 = "b" * 64
    >>> class_number([(h1, h2)]) >= 1
    True
    >>> # Two identical pairs → same class
    >>> r = class_number([(h1, h2), (h1, h2)])
    >>> r >= 1
    True
    """
    if not witness_pair_hashes:
        return 0

    occupied: set[int] = set()
    for internal_hex, external_hex in witness_pair_hashes:
        # XOR the 32-byte digests
        a = int(internal_hex[:64], 16)
        b = int(external_hex[:64], 16)
        xor_val = a ^ b
        # popcount — number of differing bits
        hamming = bin(xor_val).count("1")
        # Bucket into 10 decile classes: [0..25], [26..51], …, [230..256]
        bucket = min(hamming * 10 // 257, 9)
        occupied.add(bucket)

    return len(occupied)


# ─────────────────────────────────────────────────────────────────────
# §XVII.IV — gauss_forecast
# ─────────────────────────────────────────────────────────────────────

def gauss_forecast(history: List[float], horizon: int = 1) -> List[float]:
    """Least-squares linear regression over a residual trace, with multi-step projection.

    Doctrine reference: V17 §XVII obligation IV — Gauß least-squares
    trace forecasting.  Source: Gauß, Theoria combinationis observationum
    erroribus minimis obnoxiae (1823); Hannoversche Landesvermessung
    (Cod. Ms. Gauß, Geodäsie 165–170).  TypeScript counterpart:
    ouroboros-loop gaussForecast.

    Fits a linear model y = slope * t + intercept to the log-residual
    history (matching the TypeScript implementation: log-space fit,
    exp-space projection).  Returns `horizon` successive projections.

    Parameters
    ----------
    history:
        Sequence of non-negative residual values (Λ-axis measurements or
        witness-distance trace).  Must have ≥ 1 element.
    horizon:
        Number of future steps to project.  Default 1.

    Returns
    -------
    list[float]
        List of `horizon` projected values (in original, non-log space).

    Examples
    --------
    >>> r = gauss_forecast([5.0, 5.0, 5.0], horizon=1)
    >>> abs(r[0] - 5.0) < 0.01
    True
    >>> # Exponentially decaying trace projects below initial value
    >>> d = gauss_forecast([1.0, 0.5, 0.25, 0.125], horizon=1)
    >>> d[0] < 0.125
    True
    >>> # Multi-step horizon returns correct length
    >>> len(gauss_forecast([1.0, 2.0, 4.0], horizon=3))
    3
    """
    if not history:
        raise ValueError("gauss_forecast: history must be non-empty")

    n = len(history)
    eps = 1e-12

    if n == 1:
        # Degenerate: no slope information
        return [max(history[0], eps)] * horizon

    # Fit in log-space (matching TypeScript implementation)
    xs = list(range(n))
    ys = [math.log(max(v, eps)) for v in history]

    mean_x = sum(xs) / n
    mean_y = sum(ys) / n

    num = sum((xs[i] - mean_x) * (ys[i] - mean_y) for i in range(n))
    den = sum((xs[i] - mean_x) ** 2 for i in range(n))

    slope = num / den if den != 0 else 0.0
    intercept = mean_y - slope * mean_x

    # Project horizon steps beyond the last observed index
    projections: List[float] = []
    for h in range(1, horizon + 1):
        t = n - 1 + h  # next index after last observation
        projections.append(math.exp(slope * t + intercept))

    return projections


# ─────────────────────────────────────────────────────────────────────
# §XVII.V — bekenstein_cascade
# ─────────────────────────────────────────────────────────────────────

def bekenstein_cascade(trace: List[int], capacity_bits: float) -> List[bool]:
    """For each step, return whether the output byte-count fits within the Bekenstein bound.

    Doctrine reference: V17 §XVII obligation V — Bekenstein-bounded cascade.
    Physical source: Bekenstein (1981) Phys. Rev. D 23, 287.
    SZL canonical form: TH6 DPI bound — ouroboros/runtime/bekenstein
    trackTransit / bekensteinBound.

    The SZL software-analogy form of the Bekenstein bound is:
        bound(sizeBytes) = sizeBytes * 8  bits

    For each element ``bytes_out`` in ``trace``, this function returns
    whether ``bytes_out * 8 ≤ capacity_bits``.

    Parameters
    ----------
    trace:
        Sequence of integer byte-counts (output sizes per cascade step).
    capacity_bits:
        Bekenstein capacity budget in bits.

    Returns
    -------
    list[bool]
        Element i is True iff trace[i] * 8 ≤ capacity_bits.

    Examples
    --------
    >>> bekenstein_cascade([10, 50, 100], 800)
    [True, True, True]
    >>> bekenstein_cascade([10, 50, 101], 800)
    [True, True, False]
    >>> bekenstein_cascade([], 1000)
    []
    """
    return [step * 8 <= capacity_bits for step in trace]


# ─────────────────────────────────────────────────────────────────────
# §XVII.VI — dual_witness_verdict
# ─────────────────────────────────────────────────────────────────────

def dual_witness_verdict(internal: str, external: str) -> dict:
    """Verify that two SHA-256 witnesses are consistent (non-empty, hex-formatted).

    Doctrine reference: V17 §XVII obligation VI — dual-witness verdict.
    TypeScript counterpart: ouroboros-adapters dualWitnessVerdict.

    The TypeScript runtime produces ``internalWitness`` as
    SHA-256(salt:req_shape) and ``externalWitness`` as
    SHA-256(salt:res_shape).  Because request-shape and response-shape
    differ by construction, the two witnesses are expected to differ for
    any normal completion (verdict == "DIVERGE").  A "MATCH" verdict
    (both equal) indicates a degenerate or synthetic case.

    This Python equivalent performs the same structural check without
    live transport: it validates that both inputs are valid 64-character
    SHA-256 hex strings and classifies the relationship.

    Parameters
    ----------
    internal:
        64-char lowercase hex string — internal witness digest.
    external:
        64-char lowercase hex string — external witness digest.

    Returns
    -------
    dict with keys:
        ``verdict``  — "DIVERGE" | "MATCH" | "INVALID"
        ``internal_valid``  — bool
        ``external_valid``  — bool
        ``hamming_bits``    — int (bit-level Hamming distance, or -1 if invalid)

    Examples
    --------
    >>> r = dual_witness_verdict("a" * 64, "b" * 64)
    >>> r["verdict"]
    'DIVERGE'
    >>> r2 = dual_witness_verdict("a" * 64, "a" * 64)
    >>> r2["verdict"]
    'MATCH'
    >>> r3 = dual_witness_verdict("not-hex", "a" * 64)
    >>> r3["verdict"]
    'INVALID'
    """
    def is_valid_sha256_hex(s: str) -> bool:
        if len(s) != 64:
            return False
        try:
            int(s, 16)
            return True
        except ValueError:
            return False

    int_valid = is_valid_sha256_hex(internal)
    ext_valid = is_valid_sha256_hex(external)

    if not int_valid or not ext_valid:
        return {
            "verdict": "INVALID",
            "internal_valid": int_valid,
            "external_valid": ext_valid,
            "hamming_bits": -1,
        }

    a = int(internal, 16)
    b = int(external, 16)
    hamming = bin(a ^ b).count("1")

    verdict = "MATCH" if internal == external else "DIVERGE"
    return {
        "verdict": verdict,
        "internal_valid": True,
        "external_valid": True,
        "hamming_bits": hamming,
    }


