from __future__ import annotations

import math
import random
from collections import deque
from typing import Iterator


# ---------------------------------------------------------------------------
# 1. GraphLambda -- Lambda on small audit graphs
# ---------------------------------------------------------------------------

class GraphLambda:
    """
    Pure-Python noncomputable analog of Lutar.GraphLambda (Lean 4).

    An audit graph G = (V, E) where:
      - V = list of vertex indices 0..n-1
      - adjacency[i] = list of j such that there is an edge i -> j
      - axis_scores[i] = list of 9 floats in [0,1], one per governance axis

    Lambda_graph(G) = min over all vertices v of Lambda(axis_scores[v])
    Lambda(scores)  = geometric mean of the 9 axis scores (the A3 normalisation
                 from v14, DOI 10.5281/zenodo.20424992)

    Upstream: graph2nn relational graph (You et al. 2020, arXiv:2007.06559);
              v14 Lambda-gate geometric mean (10.5281/zenodo.20424992).
    """

    def __init__(
        self,
        adjacency: list[list[int]],
        axis_scores: list[list[float]],
    ) -> None:
        """
        Args:
            adjacency: adjacency list; adjacency[i] = [j, ...] means edge i->j.
            axis_scores: axis_scores[i] = [s0, ..., s8], each in [0,1].

        >>> gl = GraphLambda([[1], []], [[0.5]*9, [0.8]*9])
        >>> round(gl.vertex_lambda(0), 6)
        0.5
        >>> round(gl.vertex_lambda(1), 6)
        0.8
        >>> round(gl.evaluate(), 6)
        0.5
        """
        n = len(adjacency)
        if len(axis_scores) != n:
            raise ValueError(
                f"adjacency has {n} vertices but axis_scores has {len(axis_scores)}"
            )
        self.adjacency = adjacency
        self.axis_scores = axis_scores
        self.n = n

    def vertex_lambda(self, v: int) -> float:
        """
        Lambda at a single vertex: geometric mean of its 9 axis scores.

        Extends v14 A3 normalisation (DOI 10.5281/zenodo.20424992) to
        per-vertex computation in an audit graph.

        >>> gl = GraphLambda([[]], [[0.0]*9])
        >>> gl.vertex_lambda(0)
        0.0
        >>> gl = GraphLambda([[]], [[1.0]*9])
        >>> round(gl.vertex_lambda(0), 10)
        1.0
        >>> gl = GraphLambda([[]], [[0.25]*9])
        >>> round(gl.vertex_lambda(0), 6)
        0.25
        """
        scores = self.axis_scores[v]
        if not scores:
            return 0.0
        product = math.prod(max(0.0, min(1.0, s)) for s in scores)
        return product ** (1.0 / len(scores))

    def evaluate(self) -> float:
        """
        Lambda_graph: minimum vertex_lambda over all vertices.

        If the graph has no vertices, returns 1.0 (neutral element for min).

        >>> gl = GraphLambda([[1, 2], [2], []], [[0.9]*9, [0.7]*9, [0.4]*9])
        >>> round(gl.evaluate(), 6)
        0.4
        >>> GraphLambda([], []).evaluate()
        1.0
        >>> gl2 = GraphLambda([[]], [[0.6]*9])
        >>> round(gl2.evaluate(), 6)
        0.6
        """
        if self.n == 0:
            return 1.0
        return min(self.vertex_lambda(v) for v in range(self.n))


# ---------------------------------------------------------------------------
# 2. lambda_on_graph -- graph-extended Lambda with optional position weighting
# ---------------------------------------------------------------------------

def lambda_on_graph(
    adjacency: list[list[int]],
    axis_scores: list[list[float]],
    anchor_indices: list[int] | None = None,
) -> float:
    """
    Compute graph-extended Lambda = Lambda_graph(G).

    If anchor_indices is provided, applies position-aware weighting:
    each vertex's Lambda is scaled by 1/(1 + mean_sp_dist_to_anchors),
    extending P-GNN anchor-distance encoding (You et al. 2019, arXiv:1906.04817)
    to governance Lambda evaluation.

    Args:
        adjacency:     adjacency list (directed or undirected).
        axis_scores:   per-vertex 9-axis scores in [0,1].
        anchor_indices: optional list of vertex indices used as anchors.

    Returns:
        Scalar Lambda_graph value in [0,1].

    >>> round(lambda_on_graph([[1],[]], [[0.8]*9,[0.6]*9]), 6)
    0.6
    >>> round(lambda_on_graph([[1],[2],[]], [[1.0]*9,[0.9]*9,[0.5]*9]), 6)
    0.5
    >>> # With anchor at vertex 0, vertex 2 is distance 2 from anchor -> scaled
    >>> val = lambda_on_graph([[1],[2],[]], [[1.0]*9,[1.0]*9,[1.0]*9], anchor_indices=[0])
    >>> val < 1.0  # position weighting reduces value for distant vertices
    True
    """
    gl = GraphLambda(adjacency, axis_scores)
    if anchor_indices is None:
        return gl.evaluate()

    # Build undirected adjacency for SP distance (treat edges as undirected)
    n = gl.n
    undirected: list[set[int]] = [set() for _ in range(n)]
    for u, nbrs in enumerate(adjacency):
        for v in nbrs:
            undirected[u].add(v)
            undirected[v].add(u)

    def bfs_dist(src: int) -> list[int]:
        """BFS shortest-path distances from src (undirected)."""
        dist = [-1] * n
        dist[src] = 0
        q: deque[int] = deque([src])
        while q:
            u = q.popleft()
            for w in undirected[u]:
                if dist[w] == -1:
                    dist[w] = dist[u] + 1
                    q.append(w)
        return dist

    anchor_dists: list[list[int]] = [bfs_dist(a) for a in anchor_indices]

    vertex_lambdas: list[float] = []
    for v in range(n):
        base = gl.vertex_lambda(v)
        # mean distance to anchors; unreachable anchors treated as n (diameter upper bound)
        dists_to_v = [
            d[v] if d[v] >= 0 else n
            for d in anchor_dists
        ]
        mean_dist = sum(dists_to_v) / max(1, len(dists_to_v))
        # Position scale factor: 1/(1 + mean_dist) -- monotone, in (0,1]
        scale = 1.0 / (1.0 + mean_dist)
        vertex_lambdas.append(base * scale)

    return min(vertex_lambdas) if vertex_lambdas else 1.0


# ---------------------------------------------------------------------------
# 3. is_lambda_isomorphism_invariant -- verify Innovation I
# ---------------------------------------------------------------------------

def is_lambda_isomorphism_invariant(
    adj1: list[list[int]],
    adj2: list[list[int]],
    scores1: list[list[float]],
    scores2: list[list[float]],
    perm: list[int],
) -> bool:
    """
    Verify that Lambda_graph is invariant under graph isomorphism sigma.

    sigma is given as perm: perm[i] = j means vertex i in G1 maps to vertex j in G2.
    Checks:
      1. perm is a bijection on {0, ..., n-1}.
      2. scores2[perm[v]] ~= scores1[v] for all v (grade preservation).
      3. edge(u,v) in G1 <-> edge(perm[u], perm[v]) in G2 (adjacency preservation).
      4. Lambda_graph(G1) ~= Lambda_graph(G2) (the invariance itself).

    Extends v15 Reidemeister invariance to graph automorphisms (Innovation I).
    Upstream: graph automorphism formalism, Diestel Graph Theory para 1.4.

    Args:
        adj1, adj2:     adjacency lists for G1, G2.
        scores1, scores2: per-vertex axis scores.
        perm:           permutation list, perm[i] = image of vertex i under sigma.

    Returns:
        True if all four checks pass (with floating-point tolerance 1e-9).

    >>> # Identity permutation on a 2-vertex graph
    >>> is_lambda_isomorphism_invariant(
    ...     [[1],[]], [[1],[]], [[0.5]*9,[0.7]*9], [[0.5]*9,[0.7]*9], [0,1])
    True
    >>> # Swap vertices 0 and 1 (automorphism of a symmetric graph)
    >>> is_lambda_isomorphism_invariant(
    ...     [[1],[0]], [[1],[0]], [[0.6]*9,[0.6]*9], [[0.6]*9,[0.6]*9], [1,0])
    True
    >>> # Non-isomorphism: grades differ
    >>> is_lambda_isomorphism_invariant(
    ...     [[1],[]], [[1],[]], [[0.5]*9,[0.7]*9], [[0.9]*9,[0.3]*9], [0,1])
    False
    """
    n = len(adj1)
    if len(adj2) != n or len(scores1) != n or len(scores2) != n:
        return False
    if sorted(perm) != list(range(n)):
        return False  # not a bijection

    tol = 1e-9

    # Check grade preservation: scores2[perm[v]] ~= scores1[v]
    for v in range(n):
        s1 = scores1[v]
        s2 = scores2[perm[v]]
        if len(s1) != len(s2):
            return False
        if any(abs(a - b) > tol for a, b in zip(s1, s2)):
            return False

    # Check adjacency preservation
    adj2_sets = [set(nbrs) for nbrs in adj2]
    for u in range(n):
        for v in adj1[u]:
            if perm[v] not in adj2_sets[perm[u]]:
                return False

    # Check Lambda_graph invariance
    lam1 = GraphLambda(adj1, scores1).evaluate()
    lam2 = GraphLambda(adj2, scores2).evaluate()
    return abs(lam1 - lam2) <= tol


# ---------------------------------------------------------------------------
# 4. gcpn_propose -- GCPN-styled audit-graph synthesis (Innovation V)
# ---------------------------------------------------------------------------

def gcpn_propose(
    start_adj: list[list[int]],
    start_scores: list[list[float]],
    capacity_bits: int,
    n_steps: int,
    rng_seed: int = 42,
) -> list[tuple[list[list[int]], list[list[float]]]]:
    """
    Minimal GCPN-styled propose-and-reject loop.

    Extends GCPN's policy-gradient RL loop (You et al. 2018, NeurIPS,
    arXiv:1806.02473) to audit-graph synthesis:
    - Instead of a GCN policy, uses a random-walk proposal.
    - Instead of chemical valency constraints, uses the DPI capacity floor:
        Lambda_graph >= 1/capacity_bits.
    - Each accepted graph is appended to the output list.

    This is a SKELETON (no actual RL training). The random-walk proposal
    samples actions uniformly; a real GCPN would replace this with a
    policy network (GCN) trained via PPO.

    Args:
        start_adj:     initial adjacency list.
        start_scores:  initial axis scores (9 floats per vertex in [0,1]).
        capacity_bits: DPI capacity bound; floor = 1/capacity_bits.
        n_steps:       number of proposal steps.
        rng_seed:      RNG seed for reproducibility.

    Returns:
        List of (adjacency, scores) pairs for graphs that passed the constraint.
        Length <= n_steps (rejected proposals are excluded).

    >>> graphs = gcpn_propose([[1],[]], [[0.9]*9,[0.8]*9], capacity_bits=10, n_steps=5, rng_seed=0)
    >>> isinstance(graphs, list)
    True
    >>> all(isinstance(g, tuple) and len(g) == 2 for g in graphs)
    True
    >>> # All returned graphs must satisfy Lambda_graph >= 1/capacity_bits
    >>> all(GraphLambda(adj, sc).evaluate() >= 1/10 - 1e-9 for adj, sc in graphs)
    True
    """
    rng = random.Random(rng_seed)
    capacity_floor = 1.0 / max(1, capacity_bits)

    import copy
    adj = copy.deepcopy(start_adj)
    scores = copy.deepcopy(start_scores)

    accepted: list[tuple[list[list[int]], list[list[float]]]] = []

    for _ in range(n_steps):
        action = rng.choice(["add_vertex", "add_edge", "terminate"])

        new_adj = copy.deepcopy(adj)
        new_scores = copy.deepcopy(scores)

        if action == "add_vertex":
            # Propose a new vertex with random axis scores in [0.5, 1.0]
            # (biased toward passing the gate)
            new_vertex_scores = [rng.uniform(0.5, 1.0) for _ in range(9)]
            new_idx = len(new_adj)
            new_adj.append([])
            new_scores.append(new_vertex_scores)
            # Optionally connect to a random existing vertex
            if new_idx > 0:
                src = rng.randrange(new_idx)
                new_adj[src].append(new_idx)

        elif action == "add_edge" and len(adj) >= 2:
            u = rng.randrange(len(adj))
            v = rng.randrange(len(adj))
            if u != v and v not in new_adj[u]:
                new_adj[u].append(v)

        else:
            # terminate or degenerate: accept current state as-is
            new_adj = copy.deepcopy(adj)
            new_scores = copy.deepcopy(scores)

        # Constraint check (GCPN hard-constraint analog):
        lam = GraphLambda(new_adj, new_scores).evaluate()
        if lam >= capacity_floor - 1e-12:
            adj = new_adj
            scores = new_scores
            accepted.append((copy.deepcopy(adj), copy.deepcopy(scores)))

    return accepted


# ---------------------------------------------------------------------------
# 5. graphrnn_canonicalise -- BFS-canonical ordering (Innovation IV)
# ---------------------------------------------------------------------------

def graphrnn_canonicalise(adjacency: list[list[int]]) -> list[int]:
    """
    BFS-canonical ordering of an undirected graph's vertices.

    Extends GraphRNN's BFS ordering (You et al. 2018, ICML, arXiv:1802.08773)
    from generative sequence modelling to audit-fiber receipt canonicalisation.

    The ordering resolves the n! permutation symmetry of the adjacency matrix
    by running BFS from the vertex with the lowest degree (ties broken by index).
    This is one canonical root selection rule; GraphRNN uses a random root,
    but for audit purposes we fix the root deterministically.

    The output is a list [sigma(0), sigma(1), ..., sigma(n-1)] where sigma(i)
    is the vertex discovered at BFS step i.

    Innovation IV: the BFS-canonical Lambda_graph invariance (see gnn_szl_graft_design.md)
    follows because Lambda_graph = min over vertex gate values, which is independent
    of vertex ordering.

    Args:
        adjacency: undirected adjacency list (edges may be directed; we symmetrise).

    Returns:
        BFS-ordered list of vertex indices (length = n).

    >>> graphrnn_canonicalise([[1, 2], [0, 2], [0, 1]])  # triangle; start at 0
    [0, 1, 2]
    >>> graphrnn_canonicalise([[1], [0, 2], [1]])  # path; start at degree-1 vertex
    [0, 1, 2]
    >>> graphrnn_canonicalise([[], [], []])  # disconnected; each component BFS-ed
    [0, 1, 2]
    """
    n = len(adjacency)
    if n == 0:
        return []

    # Symmetrise: treat as undirected
    undirected: list[set[int]] = [set() for _ in range(n)]
    for u, nbrs in enumerate(adjacency):
        for v in nbrs:
            undirected[u].add(v)
            undirected[v].add(u)

    # Choose BFS root: vertex with minimum degree (ties broken by index)
    root = min(range(n), key=lambda v: (len(undirected[v]), v))

    visited = [False] * n
    order: list[int] = []
    queue: deque[int] = deque([root])
    visited[root] = True

    while queue:
        u = queue.popleft()
        order.append(u)
        # Visit neighbours in sorted order for determinism
        for v in sorted(undirected[u]):
            if not visited[v]:
                visited[v] = True
                queue.append(v)

    # Handle disconnected components: process unvisited vertices
    for v in range(n):
        if not visited[v]:
            visited[v] = True
            sub_queue: deque[int] = deque([v])
            while sub_queue:
                u = sub_queue.popleft()
                order.append(u)
                for w in sorted(undirected[u]):
                    if not visited[w]:
                        visited[w] = True
                        sub_queue.append(w)

    return order


