from __future__ import annotations

import math
import sys
from dataclasses import dataclass, field
from typing import Callable, Optional

# ---------------------------------------------------------------------------
# Shared types — mirror Lean 4 shared primitives
# ---------------------------------------------------------------------------

LambdaVec = tuple[float, ...]   # length-9 tuple of floats in [0, 1]
AxisVec   = tuple[float, ...]   # length-9 tuple of axis parameters

_N_AXES = 9


def _norm_l2(v: LambdaVec) -> float:
    """L2 norm of a LambdaVec."""
    return math.sqrt(sum(x * x for x in v))


def _agg_lambda(lv: LambdaVec) -> float:
    """Aggregate Λ score: L2 norm normalised to [0, 1] over 9 axes."""
    return _norm_l2(lv) / math.sqrt(_N_AXES)


# ---------------------------------------------------------------------------
# 1.  Lutar.SelfRefactoring
#     Upstream: standardgalactic/yarncrawler  commit 8c5a0f45
#     License:  Apache-2.0
