#     upstream (yarncrawler.tex §9) constrains only Markov-blanket preservation,
#     not governance Λ-boundedness.
# ---------------------------------------------------------------------------

@dataclass
class SelfRefactorAuditGraph:
    """Pure-Python pendant of ``Lutar.SelfRefactoring.AuditGraph``.

    An audit graph G = (vertices, edges, weight) where each vertex carries
    a LambdaVec (9-axis Λ contribution).  Self-refactoring rewrites are
    modelled as endofunctors φ: G → G.

    Upstream citation:
      standardgalactic/yarncrawler commit 8c5a0f45
      manuscript/yarncrawler.tex §3 "Yarncrawler as Self-Refactoring Polycompiler"
      — scalar update rule: Φ_i(t+1) = Φ_i(t) + Σ_j w_ij Δ_ij(t)
      — Markov blanket factorisation: X_t ⊥ E_t | (S_t, A_t)

    SZL adds the Λ-gate: φ is admissible only if agg_lambda(φ(G)) ≤ lambda_max.
    """

    vertices: list[int]
    edges: dict[tuple[int, int], float]      # (u, v) → edge weight w_uv
    weight: dict[int, LambdaVec]             # vertex → 9-axis Λ vec

    def aggregate_lambda(self) -> float:
        """Aggregate Λ score across the graph: RMS of per-vertex L2 norms.

        >>> g = SelfRefactorAuditGraph(
        ...     vertices=[0, 1],
        ...     edges={(0, 1): 0.5},
        ...     weight={0: (0.9,)*9, 1: (0.8,)*9},
        ... )
        >>> round(g.aggregate_lambda(), 4)
        0.8515
        >>> g2 = SelfRefactorAuditGraph(vertices=[], edges={}, weight={})
        >>> g2.aggregate_lambda()
        0.0
        >>> g3 = SelfRefactorAuditGraph(
        ...     vertices=[0],
        ...     edges={},
        ...     weight={0: (1.0,)*9},
        ... )
        >>> round(g3.aggregate_lambda(), 6)
        1.0
        """
        if not self.vertices:
            return 0.0
        scores = [_agg_lambda(self.weight[v]) for v in self.vertices]
        return math.sqrt(sum(s * s for s in scores) / len(scores))

    def apply_endofunctor(
        self,
        phi: Callable[["SelfRefactorAuditGraph"], "SelfRefactorAuditGraph"],
    ) -> "SelfRefactorAuditGraph":
        """Apply endofunctor φ to produce a new audit graph."""
        return phi(self)


def lambda_stable_under_endofunctor(
    graph: SelfRefactorAuditGraph,
    phi: Callable[[SelfRefactorAuditGraph], SelfRefactorAuditGraph],
    lambda_max: float,
    n_iters: int = 50,
) -> bool:
    """Check Λ-stability of an audit graph under repeated endofunctor application.

    Implements the main theorem of ``Lutar.SelfRefactoring``:

      selfRefactoring_lambda_stable:
        if phi is Λ-gate-preserving (agg_lambda(phi(G)) ≤ lambda_max
        whenever agg_lambda(G) ≤ lambda_max) and the initial graph is
        sub-threshold, then every iterate phi^n G is sub-threshold.

    The SZL innovation over the upstream yarncrawler is the Λ-gate: the
    upstream functor P: W → M preserves only Markov-blanket factorisation;
    SZL requires it also to be Λ-non-expanding.

    Args:
        graph:      initial audit graph G
        phi:        endofunctor (self-refactoring rewrite)
        lambda_max: governance Λ ceiling
        n_iters:    number of iterations to check (finite approximation)

    Returns:
        True  iff aggregate_lambda(phi^k G) ≤ lambda_max for k = 0..n_iters

    >>> # Identity endofunctor: always stable
    >>> g = SelfRefactorAuditGraph(
    ...     vertices=[0, 1],
    ...     edges={(0, 1): 1.0},
    ...     weight={0: (0.5,)*9, 1: (0.6,)*9},
    ... )
    >>> lambda_stable_under_endofunctor(g, lambda x: x, 1.0)
    True

    >>> # Endofunctor that inflates weights above Λ_max: unstable
    >>> def inflate(g):
    ...     return SelfRefactorAuditGraph(
    ...         vertices=g.vertices,
    ...         edges=g.edges,
    ...         weight={v: (1.0,)*9 for v in g.vertices},
    ...     )
    >>> lambda_stable_under_endofunctor(
    ...     SelfRefactorAuditGraph(
    ...         vertices=[0], edges={}, weight={0: (0.4,)*9}
    ...     ),
    ...     inflate, 0.5,
    ... )
    False

    >>> # Damping endofunctor: always contracts — stable at any ceiling
    >>> def damp(g):
    ...     return SelfRefactorAuditGraph(
    ...         vertices=g.vertices,
    ...         edges=g.edges,
    ...         weight={v: tuple(x * 0.9 for x in g.weight[v]) for v in g.vertices},
    ...     )
    >>> lambda_stable_under_endofunctor(
    ...     SelfRefactorAuditGraph(
    ...         vertices=[0], edges={}, weight={0: (0.8,)*9}
    ...     ),
    ...     damp, 0.9,
    ... )
    True
    """
    current = graph
    for _ in range(n_iters + 1):
        if current.aggregate_lambda() > lambda_max + 1e-9:
            return False
        current = phi(current)
    return True


