@dataclass
class ResonanceFunctor:
    """Fixed-point iterator on governance policies.

    Models the Resonance Chamber from standardgalactic/resonant-architecture:
      - FSI (False-Structure Intolerance): reject policies that violate
        lambda_bounds (the constitutional veto).
      - OMEF (Ontologically Modulated Executive Function): gate iteration
        to the declared purpose.

    The functor R: Policy → Policy is iterated until fixed-point or max_iter.
    Upstream citation:
      standardgalactic/resonant-architecture commit 2e1cdec1
      structural_AI_computing/Janus_Structural-Computing-White-Paper_v2_4_2025-10-20.pdf
      DOI 10.5281/zenodo.17399831

    Axiom A13 (design requirement, not proved): R distributes over policyJoin.
    This enables CRDT-mergeability across air-gap instances.
    """

    lambda_bounds: LambdaVec                  # per-axis Λ upper bounds
    purpose: str                              # OMEF purpose gate
    tol: float = 1e-6                         # convergence tolerance

    def _fsi_veto(self, policy: dict[str, float]) -> bool:
        """False-Structure Intolerance: veto policy if any axis violates bound.

        Returns True if policy is admissible (no veto), False if vetoed.

        >>> rf = ResonanceFunctor(lambda_bounds=(0.9,)*9, purpose="audit")
        >>> rf._fsi_veto({"a0": 0.8, "a1": 0.85})
        True
        >>> rf._fsi_veto({"a0": 0.95})  # violates bound
        False
        >>> ResonanceFunctor((1.0,)*9, "test")._fsi_veto({})
        True
        """
        for i, (key, val) in enumerate(policy.items()):
            axis = i % _N_AXES
            if val > self.lambda_bounds[axis] + 1e-9:
                return False
        return True

    def step(self, policy: dict[str, float]) -> dict[str, float]:
        """One application of R: enforce Λ bounds (FSI), gate to purpose.

        Each axis value is projected to [0, lambda_bounds[axis]].
        """
        out: dict[str, float] = {}
        for i, (key, val) in enumerate(policy.items()):
            axis = i % _N_AXES
            out[key] = min(val, self.lambda_bounds[axis])
        return out

    def iterate(
        self, policy: dict[str, float], max_iter: int = 100
    ) -> dict[str, float]:
        """Iterate R until fixed-point or max_iter.

        >>> rf = ResonanceFunctor(lambda_bounds=(0.9,)*9, purpose="audit")
        >>> p = {"a0": 1.0, "a1": 0.7}
        >>> fp = rf.iterate(p)
        >>> fp["a0"]
        0.9
        >>> fp["a1"]
        0.7
        """
        current = dict(policy)
        for _ in range(max_iter):
            nxt = self.step(current)
            # Check convergence: L-inf distance
            if all(abs(nxt.get(k, 0) - current.get(k, 0)) < self.tol
                   for k in set(nxt) | set(current)):
                return nxt
            current = nxt
        return current


def is_resonance_fixed_point(
    policy: dict[str, float],
    axes: LambdaVec,
    max_iter: int = 100,
    tol: float = 1e-6,
) -> bool:
    """Test whether policy is a fixed point of the Λ-resonance functor.

    Implements ``Lutar.Resonance.isResonanceFixedPoint``:
      A policy π is a resonance fixed-point iff R(π) = π.

    Args:
        policy:   dict of clause-name → Λ value
        axes:     9-axis Λ upper-bound vector (the governance contract)
        max_iter: iteration budget for Kleene ascent verification
        tol:      convergence tolerance

    Returns:
        True if policy is already at its Kleene fixed-point.

    >>> is_resonance_fixed_point({"a0": 0.8, "a1": 0.7}, (0.9,)*9)
    True
    >>> is_resonance_fixed_point({"a0": 1.0}, (0.9,)*9)
    False
    >>> is_resonance_fixed_point({}, (0.9,)*9)
    True
    """
    rf = ResonanceFunctor(lambda_bounds=axes, purpose="governance")
    applied = rf.step(policy)
    return all(
        abs(applied.get(k, 0) - policy.get(k, 0)) < tol
        for k in set(applied) | set(policy)
    )


def policy_join(pi1: dict[str, float], pi2: dict[str, float]) -> dict[str, float]:
    """CRDT semilattice join of two policies.

    join(π₁, π₂) takes the pointwise max over shared keys and includes
    all keys from both (union).  This is the join operation required by
    ``Lutar.Resonance.resonance_crdt_mergeable``.

    The theorem ``resonance_crdt_mergeable`` states: if π₁ and π₂ are both
    resonance fixed-points AND R distributes over policyJoin (Axiom A13),
    then policyJoin(π₁, π₂) is also a resonance fixed-point.

    >>> p1 = {"a0": 0.7, "a1": 0.8}
    >>> p2 = {"a0": 0.6, "a2": 0.5}
    >>> policy_join(p1, p2) == {"a0": 0.7, "a1": 0.8, "a2": 0.5}
    True
    >>> policy_join({}, {"x": 0.3}) == {"x": 0.3}
    True
    >>> policy_join({"x": 0.9}, {"x": 0.7}) == {"x": 0.9}
    True
    """
    result: dict[str, float] = {}
    for k in set(pi1) | set(pi2):
        result[k] = max(pi1.get(k, 0.0), pi2.get(k, 0.0))
    return result


