# 3.  Lutar.Crosslinking
#     Upstream: standardgalactic/kitbash  commit 57714555  (NO LICENSE)
#     Graft: IDEAS ONLY — fresh Python formulation, no copied code or TeX.
#     Upstream idea: constraint-closure consistency operator C: A → A has a
#     unique fixed-point when contractive (kitbash/thesis/constraint_closure.tex §5).
#     SZL innovation: lifts single-space closure to multi-module graph;
#     cross-module Λ-bound is monotone under Λ-non-expanding patches;
#     connects to v16 Knot Calculus via Reidemeister R1/R2/R3 patch types.
# ---------------------------------------------------------------------------

@dataclass
class ModuleRecord:
    """A single SZL module with its Λ-score and declared dependencies."""
    name: str
    lambda_score: LambdaVec            # 9-axis Λ score
    depends: list[str] = field(default_factory=list)


def crosslink_lambda_bound(
    modules: list[ModuleRecord],
    patch: ModuleRecord,
) -> dict[str, float]:
    """Compute cross-module Λ-bound after applying a patch to one module.

    Implements ``Lutar.Crosslinking.crosslink_lambda_bound_monotone``:

      If the patch is Λ-non-expanding (agg_lambda(patch) ≤ agg_lambda(original)),
      then for every dependent module Mⱼ, the Λ bound of Mⱼ is unchanged.
      Cross-module Λ pressure is monotone non-increasing under such patches.

    The upstream kitbash idea (constraint_closure.tex §5): the consistency
    operator C is contractive; its unique fixed-point satisfies all projection
    constraints.  SZL lifts: C acts on the module graph, not a single space.

    Args:
        modules: list of all modules in the dependency graph
        patch:   the new version of one module after patching

    Returns:
        dict mapping each module name to its post-patch aggregate Λ score.
        The patched module gets patch.lambda_score; all others are unchanged.

    >>> m0 = ModuleRecord("Core",    (0.8,)*9, [])
    >>> m1 = ModuleRecord("Audit",   (0.7,)*9, ["Core"])
    >>> m2 = ModuleRecord("Lambda",  (0.9,)*9, ["Core", "Audit"])
    >>> patch = ModuleRecord("Core", (0.75,)*9, [])   # Λ-non-expanding
    >>> result = crosslink_lambda_bound([m0, m1, m2], patch)
    >>> round(result["Core"], 4)
    0.75
    >>> round(result["Audit"], 4)
    0.7
    >>> round(result["Lambda"], 4)
    0.9

    >>> # Λ-expanding patch: allowed but flagged
    >>> patch_bad = ModuleRecord("Core", (1.0,)*9, [])
    >>> result2 = crosslink_lambda_bound([m0, m1, m2], patch_bad)
    >>> result2["Core"] > result2["Audit"]
    True

    >>> # Empty module list: patch is still added (no existing modules to compare)
    >>> result_empty = crosslink_lambda_bound([], ModuleRecord("X", (0.5,)*9, []))
    >>> result_empty["X"] < 1.0
    True
    """
    module_map = {m.name: m for m in modules}
    # Apply the patch
    updated = dict(module_map)
    updated[patch.name] = patch

    result: dict[str, float] = {}
    for name, mod in updated.items():
        result[name] = _agg_lambda(mod.lambda_score)
    return result


def reidemeister_patch(
    modules: list[ModuleRecord],
    patch_type: str,
    target_name: str,
    *,
    merge_with: Optional[str] = None,
    new_lambda: Optional[LambdaVec] = None,
) -> list[ModuleRecord]:
    """Apply a Reidemeister-type patch to the module graph.

    The three patch types are Λ-admissible by construction:
      R1 (loop removal):    delete an isolated module (no dependents),
                            reducing graph clutter without reducing coverage.
      R2 (merge):           merge two logically equivalent modules into one,
                            taking the pointwise max of their Λ vectors.
      R3 (permutation):     update the Λ score of a module without changing
                            its dependency structure.

    This is the generalisation of Knot Calculus Reidemeister moves to
    multi-module fiber bundles, extending the v16 knot+PACBayes work.

    Upstream idea: kitbash top-level-ontology-draft-02.tex — objects as
    stabilised low-entropy invariants; Reidemeister moves preserve the
    knot type (= module invariant).

    Args:
        modules:     current module graph
        patch_type:  "R1", "R2", or "R3"
        target_name: name of the primary module to act on
        merge_with:  (R2 only) name of the module to merge with target
        new_lambda:  (R3 only) new Λ vector for the target module

    Returns:
        Updated module graph after the patch.

    >>> m0 = ModuleRecord("Isolated", (0.3,)*9, [])
    >>> m1 = ModuleRecord("Active",   (0.7,)*9, [])
    >>> # R1: remove isolated module
    >>> result = reidemeister_patch([m0, m1], "R1", "Isolated")
    >>> [m.name for m in result]
    ['Active']

    >>> # R3: update Λ score
    >>> result2 = reidemeister_patch([m0, m1], "R3", "Active",
    ...                              new_lambda=(0.6,)*9)
    >>> result2[1].lambda_score[0]
    0.6

    >>> # R2: merge two modules
    >>> ma = ModuleRecord("A", (0.7,)*9, [])
    >>> mb = ModuleRecord("B", (0.8,)*9, [])
    >>> result3 = reidemeister_patch([ma, mb], "R2", "A", merge_with="B")
    >>> len(result3)
    1
    >>> result3[0].lambda_score[0]
    0.8
    """
    module_map = {m.name: m for m in modules}

    if patch_type == "R1":
        # Remove isolated target (no other module depends on it)
        dependents = [
            m for m in modules
            if target_name in m.depends and m.name != target_name
        ]
        if dependents:
            # Not isolated — skip for safety
            return list(modules)
        return [m for m in modules if m.name != target_name]

    elif patch_type == "R2":
        if merge_with is None or merge_with not in module_map:
            return list(modules)
        t = module_map[target_name]
        s = module_map[merge_with]
        merged_lambda = tuple(max(a, b) for a, b in zip(t.lambda_score, s.lambda_score))
        merged_deps = list(set(t.depends + s.depends) - {target_name, merge_with})
        merged = ModuleRecord(target_name, merged_lambda, merged_deps)
        remaining = [m for m in modules if m.name not in {target_name, merge_with}]
        return remaining + [merged]

    elif patch_type == "R3":
        if new_lambda is None:
            return list(modules)
        result = []
        for m in modules:
            if m.name == target_name:
                result.append(ModuleRecord(m.name, new_lambda, m.depends))
            else:
                result.append(m)
        return result

    return list(modules)


