def structural_lambda_derivative(
    axes: AxisVec,
    perturbation: AxisVec,
    h: float = 1e-4,
    lambda_fn: Optional[Callable[[AxisVec], LambdaVec]] = None,
) -> list[float]:
    """Compute the directional structural derivative of the Λ map.

    Implements ``Lutar.Calculus.Structural.structuralLambdaDerivative``:

      ∂Λᵢ/∂axesⱼ ≈ [Λ(axes + h·eⱼ) - Λ(axes - h·eⱼ)] / (2h)

    Upstream citation (MIT):
      standardgalactic/calculus commit 2636d233
      Calculus - main text.tex §1.4: "The derivative is the coefficient of
      the best local linear model."  f'(x) = lim_{h→0} [f(x+h)-f(x)]/h.
      kernel-memory.tex: TK[f](t) = ∫₀ᵗ K(t,τ) F(f(τ)) dτ — memory as default.

    SZL instantiation: the directional derivative of Λ along ``perturbation``
    gives the governance sensitivity: how much Λ changes per unit shift in
    axis parameters in the given direction.

    The DPO regulariser is: penalise training updates that increase
    ||J_Λ||_F (Frobenius norm of the full Jacobian), as high Frobenius
    norm implies governance fragility.

    Args:
        axes:        current 9-axis parameter vector
        perturbation: direction vector (length 9) for directional derivative
        h:           finite-difference step size
        lambda_fn:   Λ map (axes → LambdaVec); defaults to identity-like mock

    Returns:
        List of 9 floats: directional derivative ∂Λᵢ/∂perturbation for each axis i.

    >>> # Identity Λ map: derivative equals perturbation vector
    >>> identity_lambda = lambda a: a
    >>> axes = (0.5,) * 9
    >>> perturb = (1.0,) + (0.0,) * 8
    >>> d = structural_lambda_derivative(axes, perturb, lambda_fn=identity_lambda)
    >>> abs(d[0] - 1.0) < 1e-3
    True
    >>> abs(d[1]) < 1e-3
    True

    >>> # Constant Λ map: zero derivative everywhere
    >>> const_lambda = lambda a: (0.7,) * 9
    >>> d2 = structural_lambda_derivative(axes, perturb, lambda_fn=const_lambda)
    >>> all(abs(x) < 1e-6 for x in d2)
    True

    >>> # Doubling Λ map: derivative = 2 * perturbation
    >>> double_lambda = lambda a: tuple(2.0 * x for x in a)
    >>> d3 = structural_lambda_derivative(axes, perturb, lambda_fn=double_lambda)
    >>> abs(d3[0] - 2.0) < 1e-3
    True
    """
    if lambda_fn is None:
        # Default: clipped identity (Λ is identity on axes, clipped to [0,1])
        def lambda_fn(a: AxisVec) -> LambdaVec:
            return tuple(min(1.0, max(0.0, x)) for x in a)

    # Normalise perturbation to unit vector
    pnorm = math.sqrt(sum(p * p for p in perturbation))
    if pnorm < 1e-12:
        return [0.0] * _N_AXES
    p_unit = tuple(p / pnorm for p in perturbation)

    axes_plus  = tuple(axes[i] + h * p_unit[i] for i in range(_N_AXES))
    axes_minus = tuple(axes[i] - h * p_unit[i] for i in range(_N_AXES))

    lv_plus  = lambda_fn(axes_plus)
    lv_minus = lambda_fn(axes_minus)

    deriv = [(lv_plus[i] - lv_minus[i]) / (2.0 * h) for i in range(_N_AXES)]
    return deriv


def lambda_jacobian(
    axes: AxisVec,
    h: float = 1e-4,
    lambda_fn: Optional[Callable[[AxisVec], LambdaVec]] = None,
) -> list[list[float]]:
    """Compute the full 9×9 Jacobian J_Λ of the Λ map.

    J_Λ[i][j] = ∂Λᵢ/∂axesⱼ

    Returns a 9×9 matrix (list of lists).
    Used as the substrate for the DPO fragility regulariser.
    """
    basis = [tuple(1.0 if k == j else 0.0 for k in range(_N_AXES))
             for j in range(_N_AXES)]
    jacobian = []
    for j in range(_N_AXES):
        col = structural_lambda_derivative(axes, basis[j], h=h, lambda_fn=lambda_fn)
        jacobian.append(col)
    # jacobian[j][i] = ∂Λᵢ/∂axesⱼ → transpose to get J[i][j]
    return [[jacobian[j][i] for j in range(_N_AXES)] for i in range(_N_AXES)]


def lambda_fragility(
    axes: AxisVec,
    h: float = 1e-4,
    lambda_fn: Optional[Callable[[AxisVec], LambdaVec]] = None,
) -> float:
    """Frobenius norm of the Λ Jacobian — governance fragility score.

    High fragility = small axis perturbation causes large Λ change.
    Used as DPO regulariser: penalise ||J_Λ||_F > fragility_max.

    >>> # Constant Λ map: zero Jacobian, zero fragility
    >>> frag = lambda_fragility((0.5,)*9, lambda_fn=lambda a: (0.7,)*9)
    >>> frag < 1e-6
    True
    >>> # Identity Λ map: diagonal Jacobian of 1s, fragility = sqrt(9) = 3.0
    >>> frag2 = lambda_fragility((0.5,)*9, lambda_fn=lambda a: a)
    >>> abs(frag2 - 3.0) < 0.01
    True
    >>> # Partial identity (first axis only): fragility = 1.0
    >>> def partial(a):
    ...     return (a[0],) + (0.0,) * 8
    >>> frag3 = lambda_fragility((0.5,)*9, lambda_fn=partial)
    >>> abs(frag3 - 1.0) < 0.01
    True
    """
    J = lambda_jacobian(axes, h=h, lambda_fn=lambda_fn)
    total = sum(J[i][j] ** 2 for i in range(_N_AXES) for j in range(_N_AXES))
    return math.sqrt(total)


