# ---------------------------------------------------------------------------
# S1  AXIS VECTOR AND LAMBDA-GATE  (Thesis v11 S3.1, lutar-lean/Lutar/Invariant.lean)
# ---------------------------------------------------------------------------

AxisScore = float  # must be in [0, 1]
Weight = float     # must be >= 0; weights must sum to 1.0


@dataclass(frozen=True)
class AxisVector:
    """
    Nine-axis trust vector for a single tool call.

    Each axis x_i in [0, 1]. Weights w_i >= 0, sum(w_i) = 1.
    Formula: Lambda = prod(x_i ** w_i)  (weighted geometric mean)
    Source: Ouroboros Thesis v11 S3.1, DOI 10.5281/zenodo.20119582.

    >>> v = AxisVector(scores=(1.0,)*9, weights=(1/9,)*9)
    >>> abs(v.compute() - 1.0) < 1e-9
    True
    >>> v2 = AxisVector(scores=(0.5,) + (1.0,)*8, weights=(1.0,) + (0.0,)*8)
    >>> abs(v2.compute() - 0.5) < 1e-9
    True
    >>> AxisVector(scores=(0.0,) + (1.0,)*8, weights=(1.0,) + (0.0,)*8).compute()
    0.0
    """
    scores: tuple[float, ...]   # (x1, ..., x9) -- one per governance axis
    weights: tuple[float, ...]  # (w1, ..., w9) -- non-negative, sum to 1

    def __post_init__(self) -> None:
        if len(self.scores) != 9:
            raise ValueError(f"Expected 9 axis scores, got {len(self.scores)}")
        if len(self.weights) != 9:
            raise ValueError(f"Expected 9 weights, got {len(self.weights)}")
        if any(s < 0 or s > 1 for s in self.scores):
            raise ValueError("All axis scores must be in [0, 1]")
        if any(w < 0 for w in self.weights):
            raise ValueError("All weights must be non-negative")
        w_sum = sum(self.weights)
        if abs(w_sum - 1.0) > 1e-9:
            raise ValueError(f"Weights must sum to 1.0, got {w_sum}")

    def compute(self) -> float:
        """
        Compute Lambda = prod(x_i ** w_i).

        Returns the scalar Lambda in [0, 1].

        >>> AxisVector(scores=(1.0,)*9, weights=(1/9,)*9).compute()
        1.0
        >>> round(AxisVector(scores=(0.9,)*9, weights=(1/9,)*9).compute(), 4)
        0.9
        >>> AxisVector(scores=(0.0,) + (1.0,)*8, weights=(1.0,) + (0.0,)*8).compute()
        0.0
        """
        result = 1.0
        for x, w in zip(self.scores, self.weights):
            if w == 0.0:
                continue
            if x == 0.0:
                return 0.0
            result *= x ** w
        return result


# Default equal weights (Lambda_9 uniform)
_DEFAULT_WEIGHTS: tuple[float, ...] = tuple(1 / 9 for _ in range(9))

# Axis labels per a11oy-code spec S5.1
AXIS_LABELS = (
    "moralGrounding",         # 1 -- hard floor 0.95
    "measurabilityHonesty",   # 2 -- hard floor 0.95
    "reversibility",          # 3 -- 1.0 = read-only, lower for destructive
    "scopeBoundedness",       # 4 -- within authorised scope
    "convergenceSignal",      # 5 -- moves task toward closure
    "auditTrailIntegrity",    # 6 -- produces auditable trace
    "doctrineCompliance",     # 7 -- doctrine-v6 compliant
    "stakeholderTransparency",# 8 -- operator would recognise as authorised
    "informationBoundedness", # 9 -- DPI capacity respected
)


def lambda_gate(
    scores: Sequence[float],
    weights: Sequence[float] | None = None,
    threshold: float = 0.90,
    moral_floor: float = 0.95,
    measurable_floor: float = 0.95,
) -> tuple[float, bool, str | None]:
    """
    Evaluate the 9-axis Lambda-gate for a proposed tool call.

    Returns (lambda_score, admitted, failing_axis_label | None).

    Source: Ouroboros Thesis v11 S3.1 + a11oy-code spec S5.2.
    DOI: 10.5281/zenodo.20119582

    >>> lambda_gate((1.0,)*9)
    (1.0, True, None)
    >>> lam, ok, axis = lambda_gate((0.8,) + (1.0,)*8)
    >>> ok
    False
    >>> axis
    'moralGrounding'
    >>> lam2, ok2, _ = lambda_gate((0.0,) + (1.0,)*8)
    >>> ok2
    False
    """
    w = tuple(weights) if weights is not None else _DEFAULT_WEIGHTS
    vec = AxisVector(scores=tuple(scores), weights=w)
    lambda_score = vec.compute()

    # Hard floors on axes 1 and 2
    if scores[0] < moral_floor:
        return lambda_score, False, AXIS_LABELS[0]
    if scores[1] < measurable_floor:
        return lambda_score, False, AXIS_LABELS[1]

    # Global threshold
    if lambda_score < threshold:
        worst_idx = min(range(9), key=lambda i: scores[i])
        return lambda_score, False, AXIS_LABELS[worst_idx]

    return lambda_score, True, None


# ---------------------------------------------------------------------------
# S2  DPI CAPACITY BOUND -- BEKENSTEIN GATE  (Thesis v11 S3.3)
# ---------------------------------------------------------------------------

_HBAR = 1.054571817e-34  # J.s
_C = 2.99792458e8        # m/s


def bekenstein_bound(radius_m: float, energy_J: float) -> float:
    """
    Compute the Bekenstein information bound in bits.

    I_max = (2*pi*r*E) / (hbar * c * ln(2))

    Source: Bekenstein (1981); applied in Thesis v11 S3.3.
    DOI: 10.5281/zenodo.20119582

    >>> bekenstein_bound(0.0, 1.0)
    0.0
    >>> bekenstein_bound(1.0, 0.0)
    0.0
    >>> bekenstein_bound(1e-3, 1e-3) > 1e20
    True
    """
    if radius_m <= 0 or energy_J <= 0:
        return 0.0
    return (2 * math.pi * radius_m * energy_J) / (_HBAR * _C * math.log(2))


def dpi_check(
    info_bits: int,
    max_bits_per_call: int = 2_000_000,
) -> tuple[bool, str]:
    """
    Check whether a tool call's information volume respects the DPI capacity bound.

    Returns (admitted: bool, reason: str).

    Source: a11oy-code spec S7; Thesis v11 S3.3.
    DOI: 10.5281/zenodo.20119582

    >>> dpi_check(1_000_000)
    (True, 'DPI admitted: 1000000 bits <= 2000000 cap')
    >>> dpi_check(3_000_000)
    (False, 'DPI exceeded: 3000000 bits > 2000000 cap')
    >>> dpi_check(0)
    (True, 'DPI admitted: 0 bits <= 2000000 cap')
    """
    if info_bits <= max_bits_per_call:
        return True, f"DPI admitted: {info_bits} bits <= {max_bits_per_call} cap"
    return False, f"DPI exceeded: {info_bits} bits > {max_bits_per_call} cap"


