# S3  DUAL-WITNESS RECEIPT  (Thesis v11 S3.4)
# ---------------------------------------------------------------------------

Verdict = Literal["MATCH", "DIVERGE"]


@dataclass(frozen=True)
class DualWitnessReceipt:
    """
    Immutable dual-witness receipt for a single Edit/Write operation.

    Source: Ouroboros Thesis v11 S3.4. DOI: 10.5281/zenodo.20119582.
    """
    edit_id: str
    session_id: str
    path: str
    sha256_internal: str
    sha256_external: str
    verdict: Verdict
    timestamp_ms: int
    receipt_sha: str

    @classmethod
    def build(
        cls,
        session_id: str,
        path: str,
        content_bytes: bytes,
        external_bytes: bytes | None = None,
    ) -> "DualWitnessReceipt":
        """
        Construct a DualWitnessReceipt.

        If external_bytes is None, simulates the attestation service by
        re-hashing content_bytes (standalone/dry-run mode -> MATCH).

        >>> r = DualWitnessReceipt.build("sess-1", "/tmp/x.py", b"hello")
        >>> r.verdict
        'MATCH'
        >>> r.sha256_internal == r.sha256_external
        True
        >>> r2 = DualWitnessReceipt.build("sess-1", "/tmp/x.py", b"hello", b"world")
        >>> r2.verdict
        'DIVERGE'
        >>> len(r2.receipt_sha) == 64
        True
        """
        sha_int = hashlib.sha256(content_bytes).hexdigest()
        ext = external_bytes if external_bytes is not None else content_bytes
        sha_ext = hashlib.sha256(ext).hexdigest()
        verdict: Verdict = "MATCH" if sha_int == sha_ext else "DIVERGE"
        edit_id = str(uuid.uuid4())
        ts = int(time.time() * 1000)
        canonical = f"{edit_id}|{session_id}|{path}|{sha_int}|{sha_ext}|{verdict}|{ts}"
        receipt_sha = hashlib.sha256(canonical.encode()).hexdigest()
        return cls(
            edit_id=edit_id,
            session_id=session_id,
            path=path,
            sha256_internal=sha_int,
            sha256_external=sha_ext,
            verdict=verdict,
            timestamp_ms=ts,
            receipt_sha=receipt_sha,
        )


# ---------------------------------------------------------------------------
# S4  LAMBDA RECEIPT (KHIPU PENDANT)
# ---------------------------------------------------------------------------

@dataclass(frozen=True)
class LambdaReceipt:
    """
    Receipt-cord (khipu pendant) produced by the Lambda-gate on each tool call.

    Source: a11oy-code spec S5.3; Ouroboros runtime v6.3.0.
    DOI: 10.5281/zenodo.20162352
    """
    session_id: str
    turn: int
    tool_name: str
    lambda_vector: tuple[float, ...]
    lambda_score: float
    gate_decision: Literal["admit", "halt"]
    failing_axis: str | None
    timestamp_ms: int
    receipt_sha: str

    @classmethod
    def build(
        cls,
        session_id: str,
        turn: int,
        tool_name: str,
        lambda_vector: tuple[float, ...],
        lambda_score: float,
        admitted: bool,
        failing_axis: str | None,
    ) -> "LambdaReceipt":
        """
        Build a LambdaReceipt from gate evaluation results.

        >>> r = LambdaReceipt.build("s1", 0, "Read", (1.0,)*9, 1.0, True, None)
        >>> r.gate_decision
        'admit'
        >>> r.failing_axis is None
        True
        >>> r2 = LambdaReceipt.build("s1", 1, "Edit", (0.8,)+(1.0,)*8, 0.8, False, "moralGrounding")
        >>> r2.gate_decision
        'halt'
        >>> r2.failing_axis
        'moralGrounding'
        """
        decision: Literal["admit", "halt"] = "admit" if admitted else "halt"
        ts = int(time.time() * 1000)
        canonical = f"{session_id}|{turn}|{tool_name}|{lambda_score}|{decision}|{ts}"
        receipt_sha = hashlib.sha256(canonical.encode()).hexdigest()
        return cls(
            session_id=session_id,
            turn=turn,
            tool_name=tool_name,
            lambda_vector=lambda_vector,
            lambda_score=lambda_score,
            gate_decision=decision,
            failing_axis=failing_axis,
            timestamp_ms=ts,
            receipt_sha=receipt_sha,
        )


# ---------------------------------------------------------------------------
# S5  HUKLLA HALT STATE  (Thesis v14 HUKLLA, DOI 10.5281/zenodo.20424992)
# ---------------------------------------------------------------------------

@dataclass
class HUKLLAState:
    """
    HUKLLA halt eligibility tracker per session.

    Source: Thesis v14 HUKLLA. DOI: 10.5281/zenodo.20424992.

    >>> s = HUKLLAState()
    >>> s.record_halt("Edit")
    False
    >>> s.record_halt("Edit")
    False
    >>> s.record_halt("Edit")
    True
    """
    consecutive_halts: dict[str, int] = field(default_factory=dict)
    session_halt_requested: bool = False
    SESSION_HALT_THRESHOLD: int = 3

    def record_halt(self, tool_name: str) -> bool:
        """
        Record a halt for tool_name. Returns True if session halt is now triggered.

        >>> s = HUKLLAState()
        >>> s.record_halt("Bash")
        False
        >>> s.record_halt("Bash")
        False
        >>> s.record_halt("Bash")
        True
        """
        self.consecutive_halts[tool_name] = (
            self.consecutive_halts.get(tool_name, 0) + 1
        )
        if self.consecutive_halts[tool_name] >= self.SESSION_HALT_THRESHOLD:
            self.session_halt_requested = True
            return True
        return False

    def record_admit(self, tool_name: str) -> None:
        """
        Reset the consecutive halt counter for tool_name on a successful admit.

        >>> s = HUKLLAState()
        >>> _ = s.record_halt("Edit"); _ = s.record_halt("Edit")
        >>> s.record_admit("Edit")
        >>> s.consecutive_halts.get("Edit", 0)
        0
        """
        self.consecutive_halts[tool_name] = 0

    def reset(self) -> None:
        """
        Operator-level reset. Clears all halt counts and session-halt flag.

        >>> s = HUKLLAState()
        >>> _ = [s.record_halt("Edit") for _ in range(3)]
        >>> s.session_halt_requested
        True
        >>> s.reset()
        >>> s.session_halt_requested
        False
        """
        self.consecutive_halts.clear()
        self.session_halt_requested = False


