@dataclass
class OTELSpan:
    """
    Minimal stub for OTEL span emission.

    In production, replaced by the VSP-OTEL exporter:
    github.com/szl-holdings/vsp-otel

    Span names follow the a11oy.* convention in a11oy_code_spec.md S7.2.

    >>> span = OTELSpan("a11oy.gate.lambda", {"lambda_score": 0.95})
    >>> span.name
    'a11oy.gate.lambda'
    >>> span.attrs["lambda_score"]
    0.95
    >>> span2 = OTELSpan("a11oy.tool.edit", {"path": "/tmp/x.py", "verdict": "MATCH"})
    >>> span2.attrs["verdict"]
    'MATCH'
    >>> span3 = OTELSpan("a11oy.gate.huklla", {"tool_name": "Edit", "halt_count": 3})
    >>> span3.attrs["halt_count"]
    3
    """
    name: str
    attrs: dict[str, Any]
    timestamp_ms: int = field(default_factory=lambda: int(time.time() * 1000))

    def emit(self, *, dry_run: bool = True) -> None:
        """Emit span to OTEL pipeline (prints in dry-run mode)."""
        if dry_run:
            print(f"[OTEL] {self.name} {self.attrs}")


