class ToolCall(NamedTuple):
    """Represents a single tool call request from the model."""
    call_id: str
    tool_name: str
    inputs: dict[str, Any]
    axis_scores: tuple[float, ...]  # 9 scores, assessed by caller
    estimated_info_bits: int        # estimated I/O volume in bits


class ToolResult(NamedTuple):
    """Represents the result of a single tool execution."""
    call_id: str
    tool_name: str
    output: Any
    error: str | None
    lambda_receipt: LambdaReceipt | None
    witness_receipt: DualWitnessReceipt | None


# ---------------------------------------------------------------------------
# S8  AGENT LOOP CORE
# ---------------------------------------------------------------------------

@dataclass
class A11oyCodeSession:
    """
    a11oy-code agent session state.

    Source: a11oy-code spec S3 agent loop. DOI: 10.5281/zenodo.19944926.

    >>> sess = A11oyCodeSession()
    >>> len(sess.session_id) > 0
    True
    >>> sess.turn
    0
    >>> sess.lambda_threshold
    0.9
    """
    session_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    turn: int = 0
    receipts: list[LambdaReceipt] = field(default_factory=list)
    huklla: HUKLLAState = field(default_factory=HUKLLAState)
    turn_bits_used: int = 0
    lambda_threshold: float = 0.90
    moral_floor: float = 0.95
    measurable_floor: float = 0.95
    max_bits_per_call: int = 2_000_000
    max_bits_per_turn: int = 8_000_000
    dry_run: bool = True


def process_tool_call(
    call: ToolCall,
    session: A11oyCodeSession,
) -> ToolResult:
    """
    Process a single tool call through the full a11oy-code governance pipeline.

    Pipeline:
      1. DPI capacity check
      2. Lambda-gate evaluation
      3. HUKLLA halt check
      4. Tool execution (stubbed)
      5. Dual-witness receipt (if edit-class tool)
      6. OTEL emission

    Source: a11oy-code spec S3. DOI: 10.5281/zenodo.19944926.

    >>> sess = A11oyCodeSession(dry_run=False)
    >>> call_ok = ToolCall("c1", "Read", {"path": "/src/main.py"}, (1.0,)*9, 1000)
    >>> result = process_tool_call(call_ok, sess)
    >>> result.error is None
    True
    >>> result.lambda_receipt.gate_decision
    'admit'
    >>> call_bad = ToolCall("c2", "Edit", {"path": "/p"}, (0.8,)+(1.0,)*8, 500)
    >>> result2 = process_tool_call(call_bad, sess)
    >>> result2.error is not None
    True
    >>> call_dpi = ToolCall("c3", "Read", {"path": "/big"}, (1.0,)*9, 5_000_000)
    >>> result3 = process_tool_call(call_dpi, sess)
    >>> result3.error is not None
    True
    """
    # DPI check
    dpi_ok, dpi_msg = dpi_check(call.estimated_info_bits, session.max_bits_per_call)
    OTELSpan("a11oy.gate.dpi", {
        "info_bits": call.estimated_info_bits,
        "admitted": dpi_ok,
    }).emit(dry_run=session.dry_run)

    if not dpi_ok:
        scores = list(call.axis_scores)
        scores[8] = 0.0  # axis 9: informationBoundedness -> 0
        lam_score, _, _ = lambda_gate(
            scores, threshold=session.lambda_threshold,
            moral_floor=session.moral_floor,
            measurable_floor=session.measurable_floor,
        )
        receipt = LambdaReceipt.build(
            session.session_id, session.turn, call.tool_name,
            tuple(scores), lam_score, admitted=False,
            failing_axis="informationBoundedness"
        )
        session.receipts.append(receipt)
        session.huklla.record_halt(call.tool_name)
        OTELSpan("a11oy.gate.huklla", {
            "tool_name": call.tool_name, "reason": dpi_msg,
        }).emit(dry_run=session.dry_run)
        return ToolResult(call.call_id, call.tool_name, None, dpi_msg, receipt, None)

    # Lambda-gate
    lam_score, admitted, failing = lambda_gate(
        call.axis_scores,
        threshold=session.lambda_threshold,
        moral_floor=session.moral_floor,
        measurable_floor=session.measurable_floor,
    )
    receipt = LambdaReceipt.build(
        session.session_id, session.turn, call.tool_name,
        call.axis_scores, lam_score, admitted, failing
    )
    session.receipts.append(receipt)
    OTELSpan("a11oy.gate.lambda", {
        "lambda_score": lam_score,
        "gate_decision": receipt.gate_decision,
        "failing_axis": failing,
    }).emit(dry_run=session.dry_run)

    if not admitted:
        halt_reason = (
            f"Lambda={lam_score:.4f} below threshold {session.lambda_threshold}. "
            f"Failing axis: {failing}"
        )
        session_halt = session.huklla.record_halt(call.tool_name)
        if session_halt:
            halt_reason += " | HUKLLA session-halt requested."
        OTELSpan("a11oy.gate.huklla", {
            "tool_name": call.tool_name,
            "lambda_score": lam_score,
            "session_halt": session_halt,
        }).emit(dry_run=session.dry_run)
        return ToolResult(call.call_id, call.tool_name, None, halt_reason, receipt, None)

    session.huklla.record_admit(call.tool_name)

    # Tool execution (stub)
    output = {"stub": True, "tool": call.tool_name, "inputs": call.inputs}
    session.turn_bits_used += call.estimated_info_bits

    # Dual-witness receipt (edit-class tools)
    EDIT_TOOLS = {"Edit", "Write", "NotebookEdit"}
    witness: DualWitnessReceipt | None = None
    if call.tool_name in EDIT_TOOLS:
        stub_bytes = str(output).encode()
        witness = DualWitnessReceipt.build(
            session_id=session.session_id,
            path=call.inputs.get("path", "<unknown>"),
            content_bytes=stub_bytes,
        )
        OTELSpan("a11oy.witness.pair", {
            "path": call.inputs.get("path"),
            "verdict": witness.verdict,
        }).emit(dry_run=session.dry_run)

    OTELSpan(f"a11oy.tool.{call.tool_name.lower()}", {
        "tool_name": call.tool_name,
        "lambda_score": lam_score,
    }).emit(dry_run=session.dry_run)

    return ToolResult(call.call_id, call.tool_name, output, None, receipt, witness)


# ---------------------------------------------------------------------------
# S9  INTEGRATION TEST RUNNER
# ---------------------------------------------------------------------------

def run_integration_tests() -> int:
    """
    Run integration tests for the process_tool_call pipeline.

    Returns number of failures.

    Tests:
      T1 admitted read-only call
      T2 halted edit (axis 1 below floor)
      T3 halted call (DPI exceeded)
      T4 dual-witness MATCH on admitted edit
      T5 HUKLLA session-halt after 3 consecutive halts

    >>> run_integration_tests()
    0
    """
    failures = 0
    sess = A11oyCodeSession(dry_run=False)

    # T1: admitted read
    c1 = ToolCall("c1", "Read", {"path": "/src/main.py"}, (1.0,)*9, 5000)
    r1 = process_tool_call(c1, sess)
    if r1.error is not None or r1.lambda_receipt.gate_decision != "admit":
        failures += 1

    # T2: halted edit (axis 1 = 0.8 < 0.95 floor)
    c2 = ToolCall("c2", "Edit", {"path": "/src/main.py"}, (0.8,)+(1.0,)*8, 5000)
    r2 = process_tool_call(c2, sess)
    if r2.error is None:
        failures += 1

    # T3: DPI exceeded
    c3 = ToolCall("c3", "Read", {"path": "/big.py"}, (1.0,)*9, 5_000_000)
    r3 = process_tool_call(c3, sess)
    if r3.error is None:
        failures += 1

    # T4: witness MATCH on admitted edit
    sess2 = A11oyCodeSession(dry_run=False)
    c4 = ToolCall("c4", "Edit", {"path": "/ok.py"}, (1.0,)*9, 1000)
    r4 = process_tool_call(c4, sess2)
    if r4.witness_receipt is None or r4.witness_receipt.verdict != "MATCH":
        failures += 1

    # T5: HUKLLA session-halt after 3 consecutive halts
    sess3 = A11oyCodeSession(dry_run=False)
    bad = lambda i: ToolCall(f"hk{i}", "Edit", {}, (0.8,)+(1.0,)*8, 100)
    for i in range(3):
        process_tool_call(bad(i), sess3)
    if not sess3.huklla.session_halt_requested:
        failures += 1

    return failures


