# ═══════════════════════════════════════════════════════════════════════════════
# 1. LAMBDA SCORING — shared across all components
# ═══════════════════════════════════════════════════════════════════════════════

_BANNED_WORDS = frozenset([
    "revolutionary", "unprecedented", "game-changing",
    "world-class", "cutting-edge", "synergy", "disruptive",
])


def lambda_score(text: str) -> float:
    """
    Compute a doctrine-v6 Λ-score for *text*. Returns a float in [0.0, 1.0].

    Penalises banned marketing superlatives (-0.15 each).
    Rewards structured citations (+0.05 each, max +0.20).
    Integrated with a11oy/packages/measurement: callers should write the
    resulting score as a measurement event via the measurement package.

    >>> lambda_score("") == 1.0
    True
    >>> lambda_score("This is revolutionary and unprecedented.") < 0.75
    True
    >>> lambda_score("See doi:10.1234/x and arXiv:2501.00001") > 1.0 - 1e-9
    True
    >>> 0.0 <= lambda_score("any text at all") <= 1.0
    True
    """
    text_lower = text.lower()
    penalty = sum(0.15 for w in _BANNED_WORDS if w in text_lower)
    citation_count = (
        text.count("doi:") + text.count("arXiv:") + text.count("github.com/")
    )
    bonus = min(0.20, citation_count * 0.05)
    return max(0.0, min(1.0, 1.0 - penalty + bonus))


# ═══════════════════════════════════════════════════════════════════════════════
# 2. CenterfugeCLI — Λ-gated CLI dispatcher with receipt-cord
# Inspiration: standardgalactic/Centerfuge da0ac149aa4d (NO LICENSE → reformulation)
# Platform target: szl-holdings/platform/packages/szl-centerfuge/
# a11oy integration:
#   - reads policy from a11oy/packages/policy (lambda_floor per command slug)
#   - writes receipts as measurement events to a11oy/packages/measurement
#   - validates command text against a11oy/packages/a11oy-knowledge corpus
# ═══════════════════════════════════════════════════════════════════════════════

def _sha256(text: str) -> str:
    return hashlib.sha256(text.encode()).hexdigest()


@dataclass
class ReceiptCord:
    """
    Audit receipt for a single CenterfugeCLI dispatch.

    Chain hash links receipts into an immutable audit-graph:
      chain_hash_n = SHA-256(chain_hash_{n-1} || SHA-256(receipt_body_n))

    Compatible with szl-holdings/platform/packages/qec-integrity receipt format.
    """
    version: str
    command: str
    args: list[str]
    timestamp: str
    lambda_in: float
    lambda_out: float
    lambda_floor: float
    output_preview: str          # first 128 chars of stdout
    output_hash: str             # SHA-256 of full stdout
    chain_hash: str              # SHA-256 of (prev_chain_hash || receipt_sha)
    blocked: bool
    session_id: str


class CenterfugeCLI:
    """
    Minimal Λ-gated CLI dispatcher with receipt-cord audit output.

    Inspiration: standardgalactic/Centerfuge da0ac149aa4d (NO LICENSE → reformulation).
    Platform target: szl-holdings/platform/packages/szl-centerfuge/
    TypeScript production skeleton: szl_eng_graft_design.md §Graft 1.

    a11oy integration notes:
      - lambda_floor sourced from a11oy/packages/policy (policy YAML, per command slug)
      - receipt written as measurement event to a11oy/packages/measurement
      - command text validated against a11oy/packages/a11oy-knowledge corpus entries
      - chain_hash fed into a11oy/packages/qec-integrity for chain verification

    >>> cli = CenterfugeCLI(lambda_floor=0.6)
    >>> result = cli.dispatch("echo", ["hello world"], handler=lambda c, a: "hello world")
    >>> result["receipt"].blocked
    False
    >>> result["receipt"].lambda_in >= 0.6
    True
    >>> result["stdout"] == "hello world"
    True
    """

    GENESIS_HASH = "0" * 64
    VERSION = "szl-centerfuge/1"

    def __init__(
        self,
        lambda_floor: float = 0.6,
        session_id: Optional[str] = None,
    ) -> None:
        """
        Initialise dispatcher.

        >>> cli = CenterfugeCLI(lambda_floor=0.5)
        >>> cli.lambda_floor
        0.5
        >>> len(cli.session_id) > 0
        True
        >>> cli._chain_hash == CenterfugeCLI.GENESIS_HASH
        True
        """
        self.lambda_floor = lambda_floor
        self.session_id = session_id or _sha256(str(time.time()))[:16]
        self._chain_hash = self.GENESIS_HASH
        self._receipts: list[ReceiptCord] = []

    def dispatch(
        self,
        command: str,
        args: list[str],
        handler: Callable[[str, list[str]], str],
    ) -> dict[str, Any]:
        """
        Route *command* through the Λ-gate.

        If lambda_in < lambda_floor: command is blocked; stdout is an error message.
        Otherwise: handler(command, args) is called; output is Λ-scored.

        Returns dict with keys 'stdout' (str), 'exit_code' (int), 'receipt' (ReceiptCord).

        >>> cli = CenterfugeCLI(lambda_floor=0.6)
        >>> r = cli.dispatch("list", [], handler=lambda c, a: "files: a.py b.py")
        >>> r["exit_code"] == 0
        True
        >>> r["receipt"].version == "szl-centerfuge/1"
        True
        >>> r["receipt"].chain_hash != CenterfugeCLI.GENESIS_HASH
        True
        """
        input_text = f"{command} {' '.join(args)}"
        lambda_in = lambda_score(input_text)
        blocked = lambda_in < self.lambda_floor
        timestamp = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())

        if blocked:
            stdout = (
                f"[BLOCKED] command={command!r} "
                f"Λ_in={lambda_in:.3f} < floor={self.lambda_floor}"
            )
            exit_code = 1
        else:
            stdout = handler(command, args)
            exit_code = 0

        lambda_out = lambda_score(stdout)
        output_hash = _sha256(stdout)
        receipt_body = json.dumps(
            {"command": command, "args": args, "timestamp": timestamp,
             "lambda_in": lambda_in, "lambda_out": lambda_out, "blocked": blocked},
            sort_keys=True,
        )
        chain_hash = _sha256(self._chain_hash + _sha256(receipt_body))
        self._chain_hash = chain_hash

        receipt = ReceiptCord(
            version=self.VERSION,
            command=command,
            args=args,
            timestamp=timestamp,
            lambda_in=lambda_in,
            lambda_out=lambda_out,
            lambda_floor=self.lambda_floor,
            output_preview=stdout[:128],
            output_hash=output_hash,
            chain_hash=chain_hash,
            blocked=blocked,
            session_id=self.session_id,
        )
        self._receipts.append(receipt)
        return {"stdout": stdout, "exit_code": exit_code, "receipt": receipt}

    def audit_graph(self) -> list[dict[str, Any]]:
        """
        Return the full receipt chain as a list of dicts (audit-graph).

        Each node's chain_hash incorporates all prior hashes, forming
        a tamper-evident linked structure.

        >>> cli = CenterfugeCLI()
        >>> _ = cli.dispatch("a", [], handler=lambda c, a: "out_a")
        >>> _ = cli.dispatch("b", [], handler=lambda c, a: "out_b")
        >>> graph = cli.audit_graph()
        >>> len(graph) == 2
        True
        >>> graph[0]["chain_hash"] != graph[1]["chain_hash"]
        True
        """
        return [asdict(r) for r in self._receipts]


