# 5. GPX constraint-distance primitive
# Inspiration: standardgalactic/pk350 81331bafd4b6 (NO LICENSE → reformulation)
# szl-cookbook target: szl-holdings/szl-cookbook/gpx-constraint-distance.ts
# a11oy integration: GPS telemetry streams validated by a11oy/packages/measurement
# ═══════════════════════════════════════════════════════════════════════════════

def constraint_step_distance(
    lat1: float, lon1: float,
    lat2: float, lon2: float,
) -> float:
    """
    L1 constraint distance between two GPS points.

    Returns |Δlat| + |Δlon| for admissible point pairs.
    Returns 0.0 if either point is out-of-bounds.

    Reformulated from standardgalactic/pk350 81331bafd4b6 (NO LICENSE).
    The admissibility-first design: invalid data contributes zero, not error.
    Drone telemetry application: accumulate only over geo-fence-admissible steps.

    >>> constraint_step_distance(0.0, 0.0, 10.0, 10.0)
    20.0
    >>> constraint_step_distance(0.0, 0.0, 91.0, 0.0)  # out-of-bounds lat
    0.0
    >>> constraint_step_distance(0.0, 0.0, 0.0, 181.0)  # out-of-bounds lon
    0.0
    >>> constraint_step_distance(-90.0, -180.0, 90.0, 180.0)
    540.0
    """
    def valid(lat: float, lon: float) -> bool:
        return -90.0 <= lat <= 90.0 and -180.0 <= lon <= 180.0

    if not valid(lat1, lon1) or not valid(lat2, lon2):
        return 0.0
    return abs(lat2 - lat1) + abs(lon2 - lon1)


