@dataclass
class DPEpochLedger:
    """Tracks cumulative DP privacy cost (ε) across federated rounds.

    Each federated training round contributes a per-round epsilon. Once the
    cumulative epsilon exceeds dpi_cap, the ledger enters halt state.
    This directly enforces SZL's Lean theorem DPIFeasibility: ε_total ≤ ε_cap.

    Upstream: pytorch/opacus PRV accountant (Apache-2.0, commit 88919b6677bb).
    SZL fashion: halt state signals HUKLLA-halt to the Flower strategy.

    >>> ledger = DPEpochLedger(dpi_cap=1.0)
    >>> ledger.add_round_epsilon(0.3)
    >>> abs(ledger.cumulative_epsilon - 0.3) < 1e-9
    True
    >>> ledger.is_halted()
    False

    >>> ledger.add_round_epsilon(0.8)
    >>> ledger.is_halted()
    True

    >>> ledger.cumulative_epsilon > 1.0
    True
    """

    dpi_cap: float
    cumulative_epsilon: float = 0.0
    round_log: List[Dict] = field(default_factory=list)
    halt_triggered: bool = False

    def add_round_epsilon(self, epsilon: float) -> None:
        """Record one round's DP cost and check halt condition.

        >>> l = DPEpochLedger(dpi_cap=0.5)
        >>> l.add_round_epsilon(0.2)
        >>> l.is_halted()
        False
        >>> l.add_round_epsilon(0.4)
        >>> l.is_halted()
        True
        """
        self.cumulative_epsilon += epsilon
        entry = {
            "round": len(self.round_log) + 1,
            "round_epsilon": epsilon,
            "cumulative_epsilon": self.cumulative_epsilon,
            "halt": self.cumulative_epsilon > self.dpi_cap,
            "timestamp": time.time(),
        }
        self.round_log.append(entry)
        if self.cumulative_epsilon > self.dpi_cap:
            self.halt_triggered = True

    def is_halted(self) -> bool:
        """Return True if cumulative epsilon has exceeded dpi_cap.

        >>> DPEpochLedger(dpi_cap=1.0).is_halted()
        False
        """
        return self.halt_triggered


@dataclass
class HaltReceipt:
    """Cryptographic audit receipt generated when HUKLLA-halt triggers.

    The SHA-256 hash covers all fields deterministically, providing a
    tamper-evident record of the halt event for the SZL audit fiber.

    >>> r = HaltReceipt(epoch_id=7, cumulative_epsilon=1.05, dpi_cap=1.0, round_log=[])
    >>> r.verdict
    'HALT'
    >>> len(r.sha256) == 64
    True
    >>> r.cumulative_epsilon > r.dpi_cap
    True
    """

    epoch_id: int
    cumulative_epsilon: float
    dpi_cap: float
    round_log: List[Dict]
    verdict: str = "HALT"
    sha256: str = field(init=False)

    def __post_init__(self) -> None:
        payload = json.dumps(
            {
                "epoch_id": self.epoch_id,
                "cumulative_epsilon": self.cumulative_epsilon,
                "dpi_cap": self.dpi_cap,
                "verdict": self.verdict,
            },
            sort_keys=True,
        ).encode()
        self.sha256 = hashlib.sha256(payload).hexdigest()

    def to_dict(self) -> Dict:
        """Serialize to dict for audit fiber logging.

        >>> r = HaltReceipt(epoch_id=1, cumulative_epsilon=1.1, dpi_cap=1.0, round_log=[])
        >>> d = r.to_dict()
        >>> d["verdict"]
        'HALT'
        >>> "sha256" in d
        True
        """
        return {
            "epoch_id": self.epoch_id,
            "cumulative_epsilon": self.cumulative_epsilon,
            "dpi_cap": self.dpi_cap,
            "verdict": self.verdict,
            "sha256": self.sha256,
            "round_count": len(self.round_log),
        }


class SzlFlowerGovernor:
    """Federated learning governor with HUKLLA-halt on DP budget exhaustion.

    Wraps Flower's FedAvg aggregation concept with a per-round DP accounting
    step. If cumulative epsilon exceeds dpi_cap, all further aggregation is
    halted and a signed HaltReceipt is emitted to the audit fiber.

    Upstream: adap/flower (Apache-2.0) commit fd50dd0eed8f.
    SZL fashion adds: halt state, HaltReceipt, audit fiber emission.

    >>> gov = SzlFlowerGovernor(dpi_cap=1.0, epoch_id=42)
    >>> gov.record_round_epsilon(0.5)
    False
    >>> gov.record_round_epsilon(0.6)
    True
    >>> gov.halt_receipt is not None
    True
    >>> gov.halt_receipt.verdict
    'HALT'
    """

    def __init__(self, dpi_cap: float = 1.0, epoch_id: int = 0) -> None:
        self.dpi_cap = dpi_cap
        self.epoch_id = epoch_id
        self.ledger = DPEpochLedger(dpi_cap=dpi_cap)
        self.halt_receipt: Optional[HaltReceipt] = None

    def record_round_epsilon(self, round_epsilon: float) -> bool:
        """Record this round's DP cost. Returns True if HUKLLA-halt triggered.

        >>> gov = SzlFlowerGovernor(dpi_cap=0.5)
        >>> gov.record_round_epsilon(0.3)
        False
        >>> gov.record_round_epsilon(0.3)
        True
        """
        self.ledger.add_round_epsilon(round_epsilon)
        if self.ledger.is_halted() and self.halt_receipt is None:
            self.halt_receipt = HaltReceipt(
                epoch_id=self.epoch_id,
                cumulative_epsilon=self.ledger.cumulative_epsilon,
                dpi_cap=self.dpi_cap,
                round_log=list(self.ledger.round_log),
            )
            return True
        return False

    def aggregate_fit(
        self,
        server_round: int,
        results: List,
        round_epsilon: float,
    ) -> Optional[Dict]:
        """Aggregate round; return None (halt signal) if DP budget exceeded.

        Once halted, all subsequent calls return None regardless of epsilon.

        >>> gov = SzlFlowerGovernor(dpi_cap=0.5)
        >>> gov.aggregate_fit(1, [], 0.3) is not None
        True
        >>> gov.aggregate_fit(2, [], 0.3) is None
        True
        >>> gov.aggregate_fit(3, [], 0.1) is None
        True
        """
        # If already halted, do not accumulate further — return None immediately
        if self.ledger.is_halted():
            return None
        self.record_round_epsilon(round_epsilon)
        if self.ledger.is_halted():
            return None
        return {"round": server_round, "status": "ok"}


