@dataclass
class SaeFeature:
    """A single sparse autoencoder feature activation.

    Implements one component of the Bricken et al. (Anthropic, 2023)
    monosemanticity decomposition. In production, feature_id maps to a human-
    interpretable concept in the SAE feature atlas.

    >>> f = SaeFeature(feature_id=847, activation=0.92, label="dpi_overflow")
    >>> f.feature_id
    847
    >>> f.activation > 0
    True
    >>> f.label
    'dpi_overflow'
    """

    feature_id: int
    activation: float
    label: Optional[str] = None


@dataclass
class MechanisticReceipt:
    """Audit receipt with top SAE features explaining a governance decision.

    For every HUKLLA-halt, the top-k active SAE features are logged here,
    transforming a black-box halt into an explainable governance event.
    SHA-256 makes the receipt tamper-evident.

    >>> feats = [SaeFeature(1, 0.9, "halt_trigger"), SaeFeature(2, 0.5, "dpi_signal")]
    >>> r = MechanisticReceipt("d1", "HUKLLA_HALT", 12, feats)
    >>> r.verdict
    'HUKLLA_HALT'
    >>> len(r.top_features)
    2
    >>> len(r.sha256) == 64
    True
    """

    decision_id: str
    verdict: str
    layer: int
    top_features: List[SaeFeature]
    timestamp: float = field(default_factory=time.time)
    sha256: str = field(init=False)

    def __post_init__(self) -> None:
        payload = json.dumps(
            {
                "decision_id": self.decision_id,
                "verdict": self.verdict,
                "layer": self.layer,
                "features": [
                    (f.feature_id, round(f.activation, 8)) for f in self.top_features
                ],
            },
            sort_keys=True,
        ).encode()
        self.sha256 = hashlib.sha256(payload).hexdigest()

    def to_dict(self) -> Dict:
        """Serialize to dict for audit fiber.

        >>> feats = [SaeFeature(1, 0.8)]
        >>> r = MechanisticReceipt("d2", "PASS", 6, feats)
        >>> d = r.to_dict()
        >>> d["verdict"]
        'PASS'
        >>> len(d["top_features"])
        1
        """
        return {
            "decision_id": self.decision_id,
            "verdict": self.verdict,
            "layer": self.layer,
            "top_features": [
                {
                    "id": f.feature_id,
                    "activation": f.activation,
                    "label": f.label,
                }
                for f in self.top_features
            ],
            "sha256": self.sha256,
            "timestamp": self.timestamp,
        }


def explain_decision(
    decision_id: str,
    verdict: str,
    activations: "np.ndarray",
    sae_encoder: "np.ndarray",
    layer: int,
    top_k: int = 5,
    feature_labels: Optional[Dict[int, str]] = None,
) -> MechanisticReceipt:
    """Compute SAE feature attribution for a governance decision.

    Projects activations onto SAE encoder weights, applies ReLU, selects top-k
    features by activation magnitude. Implements the core of Bricken et al.
    (2023) dictionary learning approach, adapted for SZL governance model.

    >>> rng = np.random.default_rng(0)
    >>> acts = rng.standard_normal(64)
    >>> enc = rng.standard_normal((128, 64))
    >>> receipt = explain_decision("d1", "HUKLLA_HALT", acts, enc, layer=12, top_k=3)
    >>> len(receipt.top_features) == 3
    True
    >>> receipt.verdict
    'HUKLLA_HALT'
    >>> all(f.activation >= 0 for f in receipt.top_features)
    True
    """
    # Project onto SAE encoder: shape (n_features,)
    feature_acts: np.ndarray = sae_encoder @ activations
    # ReLU activation (SAE decoder uses ReLU in TopK variant)
    feature_acts = np.maximum(feature_acts, 0.0)

    top_indices = np.argsort(feature_acts)[::-1][:top_k]
    features = [
        SaeFeature(
            feature_id=int(idx),
            activation=float(feature_acts[idx]),
            label=(feature_labels or {}).get(int(idx)),
        )
        for idx in top_indices
    ]
    return MechanisticReceipt(
        decision_id=decision_id,
        verdict=verdict,
        layer=layer,
        top_features=features,
    )


