@dataclass
class CounterfactualReceipt:
    """Dual-witness audit receipt with counterfactual verdict.

    Answers the regulator's question: "Would HUKLLA-halt have triggered if
    the DPI-cap had been set to a different value?" Implements the minimal
    structural causal model for SZL's threshold-based governance: the
    causal DAG has DPI_CAP → HALT ← DPI_ACTUAL. The counterfactual
    intervenes on DPI_CAP (the treatment) holding DPI_ACTUAL fixed.

    Upstream: py-why/dowhy (MIT) commit 38cf4c545ddb — do-calculus.
    SZL fashion: causal_necessity field = True iff the halt was causally
    necessary (i.e., would not have occurred at relaxed cap).

    >>> r = CounterfactualReceipt(
    ...     decision_id="d1",
    ...     factual_verdict="HALT",
    ...     factual_dpi=1.05,
    ...     counterfactual_cap=1.15,
    ...     counterfactual_verdict="PASS",
    ...     causal_necessity=True,
    ... )
    >>> r.factual_verdict
    'HALT'
    >>> r.counterfactual_verdict
    'PASS'
    >>> r.causal_necessity
    True
    >>> len(r.sha256) == 64
    True
    """

    decision_id: str
    factual_verdict: str
    factual_dpi: float
    counterfactual_cap: float
    counterfactual_verdict: str
    causal_necessity: bool
    timestamp: float = field(default_factory=time.time)
    sha256: str = field(init=False)

    def __post_init__(self) -> None:
        payload = json.dumps(
            {
                "decision_id": self.decision_id,
                "factual_verdict": self.factual_verdict,
                "factual_dpi": self.factual_dpi,
                "counterfactual_cap": self.counterfactual_cap,
                "counterfactual_verdict": self.counterfactual_verdict,
                "causal_necessity": self.causal_necessity,
            },
            sort_keys=True,
        ).encode()
        self.sha256 = hashlib.sha256(payload).hexdigest()

    def to_dict(self) -> Dict:
        """Serialize to dict for audit fiber.

        >>> r = CounterfactualReceipt("d1","HALT",1.05,1.15,"PASS",True)
        >>> d = r.to_dict()
        >>> d["causal_necessity"]
        True
        >>> "sha256" in d
        True
        """
        return {
            "decision_id": self.decision_id,
            "factual_verdict": self.factual_verdict,
            "factual_dpi": self.factual_dpi,
            "counterfactual_cap": self.counterfactual_cap,
            "counterfactual_verdict": self.counterfactual_verdict,
            "causal_necessity": self.causal_necessity,
            "sha256": self.sha256,
            "timestamp": self.timestamp,
        }


def compute_counterfactual(
    decision_id: str,
    factual_dpi: float,
    factual_cap: float,
    counterfactual_cap: float,
) -> CounterfactualReceipt:
    """Compute structural counterfactual verdict under modified DPI cap.

    Causal model: HALT ⟺ factual_dpi > cap.
    Counterfactual: intervene on cap → cap_cf, hold factual_dpi fixed.
    causal_necessity = True iff factual halt would NOT have occurred at cap_cf.

    This implements the *potential outcomes* framework (Rubin/Pearl) for a
    simple threshold SCM. In production, integrate with DoWhy's
    CausalModel + LinearRegression identification.

    >>> r = compute_counterfactual("d1", factual_dpi=1.05, factual_cap=1.0,
    ...                            counterfactual_cap=1.10)
    >>> r.factual_verdict
    'HALT'
    >>> r.counterfactual_verdict
    'PASS'
    >>> r.causal_necessity
    True

    >>> r2 = compute_counterfactual("d2", factual_dpi=1.05, factual_cap=1.0,
    ...                             counterfactual_cap=1.02)
    >>> r2.counterfactual_verdict
    'HALT'
    >>> r2.causal_necessity
    False

    >>> r3 = compute_counterfactual("d3", factual_dpi=0.9, factual_cap=1.0,
    ...                             counterfactual_cap=0.8)
    >>> r3.factual_verdict
    'PASS'
    >>> r3.counterfactual_verdict
    'HALT'
    """
    factual_verdict = "HALT" if factual_dpi > factual_cap else "PASS"
    cf_verdict = "HALT" if factual_dpi > counterfactual_cap else "PASS"
    # causal_necessity: the halt was causally necessary iff it occurred factually
    # AND would not have occurred under a relaxed (higher) cap
    causal_necessity = (factual_verdict == "HALT") and (cf_verdict == "PASS")

    return CounterfactualReceipt(
        decision_id=decision_id,
        factual_verdict=factual_verdict,
        factual_dpi=factual_dpi,
        counterfactual_cap=counterfactual_cap,
        counterfactual_verdict=cf_verdict,
        causal_necessity=causal_necessity,
    )


