def run_integration_tests() -> int:
    """Run all integration assertions. Returns number of failures."""
    failures = 0

    # ---- Part 1: SzlFlowerGovernor ----
    # T1: no halt below cap
    gov = SzlFlowerGovernor(dpi_cap=1.0, epoch_id=1)
    if gov.record_round_epsilon(0.4):
        failures += 1
    if gov.record_round_epsilon(0.3):
        failures += 1
    if gov.halt_receipt is not None:
        failures += 1

    # T2: halt at cap breach
    if not gov.record_round_epsilon(0.4):  # 1.1 > 1.0
        failures += 1
    if gov.halt_receipt is None:
        failures += 1
    if gov.halt_receipt and gov.halt_receipt.verdict != "HALT":
        failures += 1
    if gov.halt_receipt and len(gov.halt_receipt.sha256) != 64:
        failures += 1

    # T3: aggregate_fit returns None after halt
    result = gov.aggregate_fit(4, [], 0.1)
    if result is not None:
        failures += 1

    # T4: HaltReceipt to_dict has required keys
    d = gov.halt_receipt.to_dict() if gov.halt_receipt else {}
    for key in ("epoch_id", "cumulative_epsilon", "dpi_cap", "verdict", "sha256"):
        if key not in d:
            failures += 1

    # ---- Part 2: SzlSaeExplainer ----
    rng = np.random.default_rng(42)
    acts = rng.standard_normal(128)
    enc = rng.standard_normal((256, 128))

    # T5: correct number of features returned
    receipt = explain_decision("test-001", "HUKLLA_HALT", acts, enc, layer=8, top_k=5)
    if len(receipt.top_features) != 5:
        failures += 1

    # T6: all activations non-negative (ReLU applied)
    if not all(f.activation >= 0 for f in receipt.top_features):
        failures += 1

    # T7: SHA-256 has correct length
    if len(receipt.sha256) != 64:
        failures += 1

    # T8: to_dict has required keys
    d2 = receipt.to_dict()
    for key in ("decision_id", "verdict", "layer", "top_features", "sha256"):
        if key not in d2:
            failures += 1

    # T9: SAE receipt with labels
    labels = {int(i): f"feature_{i}" for i in range(256)}
    receipt2 = explain_decision("test-002", "PASS", acts, enc, layer=4, top_k=3,
                                feature_labels=labels)
    if any(f.label is None for f in receipt2.top_features):
        failures += 1

    # ---- Part 3: SzlCausalAuditor ----
    # T10: causal necessity True when cf_cap relaxes halt
    r1 = compute_counterfactual("c1", factual_dpi=1.05, factual_cap=1.0,
                                 counterfactual_cap=1.10)
    if r1.factual_verdict != "HALT":
        failures += 1
    if r1.counterfactual_verdict != "PASS":
        failures += 1
    if not r1.causal_necessity:
        failures += 1

    # T11: causal necessity False when cf_cap still halts
    r2 = compute_counterfactual("c2", factual_dpi=1.05, factual_cap=1.0,
                                 counterfactual_cap=1.02)
    if r2.counterfactual_verdict != "HALT":
        failures += 1
    if r2.causal_necessity:
        failures += 1

