from __future__ import annotations

import math
import hashlib
import time
from dataclasses import dataclass, field


# ─────────────────────────────────────────────────────────────────────────────
# §1  FEATURE IMPORTANCE RECEIPT — Lambda-scored SHAP analogue
# ─────────────────────────────────────────────────────────────────────────────

def feature_importance_receipt(
    feature_scores: dict[str, float],
) -> dict:
    """
    Compute a Lambda-scored feature-importance receipt.

    Each feature contributes to the governance score in proportion to its
    absolute importance weight. The Lambda score represents how concentrated
    the prediction is in interpretable features (higher = more interpretable).

    SZL innovation over seehiong/hdb-price-predictor (MIT): the upstream
    prediction pipeline has no auditability. SZL adds a SHAP-analogue that
    maps feature importances to a Lambda axis score (interpretability axis).

    Source: SZL Production Graft Design, §1. DOI: 10.5281/zenodo.20431181.

    >>> receipt = feature_importance_receipt({"floor_area": 0.4, "location": 0.35, "age": 0.25})
    >>> abs(sum(receipt['normalized'].values()) - 1.0) < 1e-9
    True
    >>> 0.0 <= receipt['lambda_interpretability'] <= 1.0
    True
    >>> receipt['top_feature']
    'floor_area'
    """
    if not feature_scores:
        return {
            "normalized": {},
            "lambda_interpretability": 1.0,
            "top_feature": None,
            "entropy_bits": 0.0,
        }

    total = sum(abs(v) for v in feature_scores.values())
    if total == 0:
        n = len(feature_scores)
        normalized = {k: 1.0 / n for k in feature_scores}
    else:
        normalized = {k: abs(v) / total for k, v in feature_scores.items()}

    # Shannon entropy of normalized importances (lower entropy = more concentrated)
    entropy = -sum(
        p * math.log2(p) for p in normalized.values() if p > 0
    )
    max_entropy = math.log2(len(normalized)) if len(normalized) > 1 else 0.0

    # Lambda_interpretability: 1.0 when prediction concentrates in one feature,
    # 0.5 when uniformly distributed (max entropy).
    lambda_interp = 1.0 - (entropy / max_entropy * 0.5) if max_entropy > 0 else 1.0

    top_feature = max(normalized, key=normalized.__getitem__)

    return {
        "normalized": normalized,
        "lambda_interpretability": round(lambda_interp, 6),
        "top_feature": top_feature,
        "entropy_bits": round(entropy, 6),
    }


# ─────────────────────────────────────────────────────────────────────────────
# §2  LAMBDA-GATED MULTI-MODEL ROUTER
# ─────────────────────────────────────────────────────────────────────────────

@dataclass
class ModelResponse:
    """
    A response from a single LLM model in a multi-model router.

    SZL innovation over seehiong/multi-model-chat (MIT): the upstream
    displays responses side-by-side for manual selection. SZL routes
    automatically: highest Lambda wins; ties go to dual-witness consensus.

    Source: SZL Production Graft Design, §2. DOI: 10.5281/zenodo.20431181.

    >>> r = ModelResponse("gpt-4o", "The answer is 42.", 0.92, 0.85)
    >>> r.model_id
    'gpt-4o'
    >>> 0.0 <= r.lambda_score <= 1.0
    True
    """
    model_id: str
    text: str
    lambda_score: float     # governance score of the response
    quality_score: float    # task-quality score (separate from governance)

    def __post_init__(self) -> None:
        if not (0.0 <= self.lambda_score <= 1.0):
            raise ValueError(f"lambda_score must be in [0,1], got {self.lambda_score}")
        if not (0.0 <= self.quality_score <= 1.0):
            raise ValueError(f"quality_score must be in [0,1], got {self.quality_score}")


def route_model_responses(
    responses: list[ModelResponse],
    governance_weight: float = 0.6,
    quality_weight: float = 0.4,
) -> dict:
    """
    Route to the best model response using Lambda-gated dispatch.

    Combined score = governance_weight * lambda_score + quality_weight * quality_score.
    Highest combined score wins. In case of tie (< 1e-6 difference),
    dual-witness consensus is applied between the top two.

    Source: SZL Production Graft Design, §2. DOI: 10.5281/zenodo.20431181.

    >>> r1 = ModelResponse("gpt-4o", "A", 0.9, 0.8)
    >>> r2 = ModelResponse("claude-3.5", "B", 0.7, 0.95)
    >>> result = route_model_responses([r1, r2])
    >>> result['winner'] in ("gpt-4o", "claude-3.5")
    True
    >>> 0.0 <= result['winning_score'] <= 1.0
    True
    >>> route_model_responses([])['winner'] is None
    True
    """
    if not responses:
        return {"winner": None, "winning_score": 0.0, "reason": "No responses"}

    if abs(governance_weight + quality_weight - 1.0) > 1e-9:
        raise ValueError("governance_weight + quality_weight must sum to 1.0")

    scored = [
        (r, governance_weight * r.lambda_score + quality_weight * r.quality_score)
        for r in responses
    ]
    scored.sort(key=lambda x: x[1], reverse=True)

    best_r, best_score = scored[0]

    # Tie-breaking: dual-witness consensus between top-2
    reason = "Highest combined Lambda-quality score"
    if len(scored) >= 2:
        second_r, second_score = scored[1]
        if abs(best_score - second_score) < 1e-6:
            # Dual-witness: take alphabetically first model_id as tiebreak
            if best_r.model_id > second_r.model_id:
                best_r, best_score = second_r, second_score
            reason = f"Tie-broken by dual-witness consensus (delta < 1e-6)"

    return {
        "winner": best_r.model_id,
        "winning_score": round(best_score, 6),
        "winning_text": best_r.text,
        "reason": reason,
        "all_scores": [(r.model_id, round(s, 6)) for r, s in scored],
    }


