@dataclass
class AgentNode:
    """
    A node in a multi-agent graph with Lambda governance scoring.

    SZL innovation over seehiong/ai-knowledge-assistant (MIT): the upstream
    LangGraph pipeline selects agents by static role assignment. SZL adds
    dynamic Lambda-gated selection: only agents with Lambda >= threshold
    are eligible for the next step.

    Source: SZL Production Graft Design, §3. DOI: 10.5281/zenodo.20431181.

    >>> n = AgentNode("retriever", 0.88)
    >>> n.agent_id
    'retriever'
    >>> n.lambda_score >= 0.0
    True
    """
    agent_id: str
    lambda_score: float   # Current governance score of this agent
    invocation_count: int = 0
    last_output: str = ""

    def __post_init__(self) -> None:
        if not (0.0 <= self.lambda_score <= 1.0):
            raise ValueError(f"lambda_score must be in [0,1]")


def select_next_agent(
    agents: list[AgentNode],
    lambda_threshold: float = 0.7,
    task_context: str = "",
) -> dict:
    """
    Select the next agent using Lambda-gated dispatch.

    Only agents with lambda_score >= lambda_threshold are eligible.
    Among eligible agents, select the one with highest Lambda score.
    If no agent qualifies, return HUKLLA halt signal.

    Source: SZL Production Graft Design, §3. DOI: 10.5281/zenodo.20431181.

    >>> agents = [AgentNode("retriever", 0.9), AgentNode("writer", 0.6), AgentNode("critic", 0.85)]
    >>> result = select_next_agent(agents, lambda_threshold=0.7)
    >>> result['selected'] == "retriever"
    True
    >>> result2 = select_next_agent(agents, lambda_threshold=0.95)
    >>> result2['halt']
    True
    >>> select_next_agent([], lambda_threshold=0.5)['halt']
    True
    """
    eligible = [a for a in agents if a.lambda_score >= lambda_threshold]

    if not eligible:
        return {
            "selected": None,
            "halt": True,
            "reason": (
                f"HUKLLA halt: no agent meets Lambda threshold {lambda_threshold}. "
                f"Available scores: {[(a.agent_id, a.lambda_score) for a in agents]}"
            ),
        }

    best = max(eligible, key=lambda a: a.lambda_score)
    return {
        "selected": best.agent_id,
        "halt": False,
        "lambda_score": best.lambda_score,
        "reason": f"Selected highest-Lambda eligible agent ({best.lambda_score:.4f})",
        "eligible_count": len(eligible),
    }


# ─────────────────────────────────────────────────────────────────────────────
# §4  BEKENSTEIN-BOUNDED PREDICTION THROUGHPUT
# ─────────────────────────────────────────────────────────────────────────────

def bekenstein_prediction_throughput(
    requests_per_second: float,
    features_per_request: int,
    bits_per_feature: int = 32,
    session_radius_m: float = 0.01,
    energy_J: float = 1e-4,
) -> dict:
    """
    Compute Bekenstein-bounded throughput cap for ML prediction service.

    Bekenstein cap: I_max = (2*pi*r*E) / (hbar*c*ln(2)) bits.
    Actual throughput = requests_per_second * features_per_request * bits_per_feature.
    If actual > cap, the prediction rate exceeds the governance-bounded limit.

    Source: SZL Production Graft Design, §4. DOI: 10.5281/zenodo.20431181.

    >>> r = bekenstein_prediction_throughput(10, 5, 32, 0.01, 1e-4)
    >>> r['actual_bits_per_second'] == 10 * 5 * 32
    True
    >>> r['cap_bits'] > 0
    True
    >>> r2 = bekenstein_prediction_throughput(1e20, 1000, 64, 1e-10, 1e-40)
    >>> r2['cap_exceeded']
    True
    """
    hbar = 1.054571817e-34
    c = 2.99792458e8
    cap_bits = (2 * math.pi * session_radius_m * energy_J) / (hbar * c * math.log(2))

    actual_bps = requests_per_second * features_per_request * bits_per_feature
    cap_exceeded = actual_bps > cap_bits

    return {
        "cap_bits": cap_bits,
        "actual_bits_per_second": actual_bps,
        "cap_exceeded": cap_exceeded,
        "utilization": round(actual_bps / cap_bits, 6) if cap_bits > 0 else float("inf"),
        "max_requests_per_second": cap_bits / (features_per_request * bits_per_feature),
    }


# ─────────────────────────────────────────────────────────────────────────────
# §5  PRODUCTION DEPLOYMENT RECEIPT
# ─────────────────────────────────────────────────────────────────────────────

@dataclass
class ProductionDeploymentReceipt:
    """
    Governance stamp for a production deployment.

    Captures: service name, version, Lambda score at deploy time, deployment
    hash (SHA-256 of config), timestamp. Immutable after creation.

    Doctrine v6: every production deployment must carry a governance receipt.
    Receipts are stored in the CRDT audit chain for post-incident analysis.

    Source: SZL Production Graft Design, §5. DOI: 10.5281/zenodo.20431181.

    >>> r = ProductionDeploymentReceipt.stamp("hdb-predictor", "v1.2.3", 0.91, {"env": "prod"})
    >>> r.service_name
    'hdb-predictor'
    >>> 0.0 <= r.lambda_at_deploy <= 1.0
    True
    >>> len(r.config_hash) == 64
    True
    """
    service_name: str
    version: str
    lambda_at_deploy: float
    config_hash: str   # SHA-256 of deployment config
    deploy_timestamp: float
    receipt_id: str

    @classmethod
    def stamp(
        cls,
        service_name: str,
        version: str,
        lambda_at_deploy: float,
        config: dict,
    ) -> "ProductionDeploymentReceipt":
        """
        Create a deployment receipt from service metadata.

        >>> r = ProductionDeploymentReceipt.stamp("svc", "v1.0", 0.88, {"k": "v"})
        >>> r.version
        'v1.0'
        >>> r.lambda_at_deploy
        0.88
        >>> r.deploy_timestamp > 0
        True
        """
        import json
        config_str = json.dumps(config, sort_keys=True)
        config_hash = hashlib.sha256(config_str.encode()).hexdigest()
        ts = time.time()
        receipt_id = hashlib.sha256(
            f"{service_name}:{version}:{ts}".encode()
        ).hexdigest()[:16]
        return cls(
            service_name=service_name,
            version=version,
            lambda_at_deploy=lambda_at_deploy,
            config_hash=config_hash,
            deploy_timestamp=ts,
            receipt_id=receipt_id,
        )


