# ─────────────────────────────────────────────────────────────────────────────
# §1  GAP-SENTENCE LAMBDA PROXY — PEGASUS GSG score as governance signal
# ─────────────────────────────────────────────────────────────────────────────

def gap_sentence_lambda_proxy(
    source_sentences: list[str],
    gap_indices: list[int],
    n_top: int = 3,
) -> dict:
    """
    Compute a Lambda proxy score from gap-sentence selection.

    Inspired by PEGASUS (Liu, Lapata, arXiv:1912.08777): the gap-sentence
    generation proxy selects sentences most important to the document summary.
    SZL adapts this: sentences with high GSG proxy scores signal high
    information density, which maps to a Lambda-governance axis (informationBoundedness).

    If gap_indices selects the top-n_top sentences by proxy score, the
    Lambda proxy = fraction of total document importance covered by selected sentences.
    Ideal: top-3 sentences cover >= 60% of importance (governance: bounded summarization).

    Upstream: PEGASUS arXiv:1912.08777. SZL innovation: governance proxy.
    Source: SZL Agent Tooling Graft Design, §1. DOI: 10.5281/zenodo.20431181.

    >>> sents = ["The Bekenstein bound limits information.", "Lambda gates every event.", "DPI caps flow."]
    >>> result = gap_sentence_lambda_proxy(sents, [0, 1], n_top=2)
    >>> 0.0 <= result['lambda_proxy'] <= 1.0
    True
    >>> result['gap_count']
    2
    >>> gap_sentence_lambda_proxy([], [])['lambda_proxy']
    1.0
    """
    if not source_sentences:
        return {"lambda_proxy": 1.0, "gap_count": 0, "coverage": 1.0}

    # Proxy score per sentence: length-normalized (longer = more info-dense)
    scores = [len(s.split()) for s in source_sentences]
    total_score = sum(scores)
    if total_score == 0:
        return {"lambda_proxy": 1.0, "gap_count": 0, "coverage": 1.0}

    # Normalized importances
    importance = [s / total_score for s in scores]

    # Coverage by gap-selected sentences
    valid_gaps = [i for i in gap_indices if 0 <= i < len(source_sentences)]
    gap_coverage = sum(importance[i] for i in valid_gaps)

    # Lambda proxy: coverage of information by selected gap sentences
    # High coverage = high information density in gaps = bounded summarization
    lambda_proxy = min(1.0, gap_coverage)

    return {
        "lambda_proxy": round(lambda_proxy, 6),
        "gap_count": len(valid_gaps),
        "coverage": round(gap_coverage, 6),
        "sentence_importances": [round(x, 6) for x in importance],
    }


# ─────────────────────────────────────────────────────────────────────────────
# §2  TOOL MANIFEST VERIFIER — JSON tool schemas checked for doctrine compliance
# ─────────────────────────────────────────────────────────────────────────────

BANNED_TOOL_PATTERNS = [
    "autonomous_kill",
    "lethal_force",
    "delete_without_confirm",
    "override_safety",
    "bypass_auth",
]

REQUIRED_TOOL_FIELDS = {"name", "description", "parameters"}


def verify_tool_manifest(tool: dict) -> dict:
    """
    Verify a tool manifest (JSON schema) for doctrine v6 compliance.

    Checks:
      1. Required fields present: {name, description, parameters}
      2. No banned patterns in tool name or description
      3. Lambda score for the manifest (proxy for governance quality)

    Doctrine: SZL does not redistribute commercial prompt text.
    This verifies tool STRUCTURE only — not any proprietary content.

    Source: SZL Agent Tooling Graft Design, §2.
    Upstream: peterjliu/system-prompts-and-models-of-ai-tools (structural pattern).
    DOI: 10.5281/zenodo.20431181.

    >>> t = {"name": "read_file", "description": "Read a file safely", "parameters": {"path": "str"}}
    >>> result = verify_tool_manifest(t)
    >>> result['compliant']
    True
    >>> t_bad = {"name": "autonomous_kill", "description": "x", "parameters": {}}
    >>> verify_tool_manifest(t_bad)['compliant']
    False
    >>> t_incomplete = {"name": "x", "description": "x"}
    >>> verify_tool_manifest(t_incomplete)['compliant']
    False
    """
    violations = []

    # Check required fields
    missing = REQUIRED_TOOL_FIELDS - set(tool.keys())
    if missing:
        violations.append(f"Missing required fields: {sorted(missing)}")

    # Check banned patterns
    tool_text = f"{tool.get('name', '')} {tool.get('description', '')}".lower()
    for pattern in BANNED_TOOL_PATTERNS:
        if pattern in tool_text:
            violations.append(f"Banned pattern: {pattern!r}")

    # Lambda score: 1.0 if compliant, decreases with violations
    lambda_score = max(0.0, 1.0 - len(violations) * 0.3)

    return {
        "compliant": len(violations) == 0,
        "violations": violations,
        "lambda_score": round(lambda_score, 6),
        "tool_name": tool.get("name", "<unnamed>"),
    }


def verify_tool_manifest_batch(tools: list[dict]) -> dict:
    """
    Verify a batch of tool manifests and return aggregate compliance.

    Returns overall compliance flag and per-tool results.

    >>> tools = [
    ...     {"name": "read", "description": "Read a file", "parameters": {}},
    ...     {"name": "write", "description": "Write safely", "parameters": {}},
    ... ]
    >>> result = verify_tool_manifest_batch(tools)
    >>> result['all_compliant']
    True
    >>> result['tool_count']
    2
    >>> bad_tools = [{"name": "bypass_auth", "description": "x", "parameters": {}}]
    >>> verify_tool_manifest_batch(bad_tools)['all_compliant']
    False
    """
    results = [verify_tool_manifest(t) for t in tools]
    all_compliant = all(r["compliant"] for r in results)
    avg_lambda = sum(r["lambda_score"] for r in results) / len(results) if results else 1.0
    return {
        "all_compliant": all_compliant,
        "tool_count": len(tools),
        "avg_lambda_score": round(avg_lambda, 6),
        "per_tool": results,
    }


# ─────────────────────────────────────────────────────────────────────────────
# §3  AGENT LOOP RECEIPT — per-turn Lambda receipt for agent control loops
# ─────────────────────────────────────────────────────────────────────────────

@dataclass
class AgentTurnReceipt:
    """
    Lambda receipt for a single turn in an agent control loop.

    Captures: turn_id, tool_calls, per-call Lambda scores, aggregate Lambda,
    gate decision, and a tamper-evident hash.

    Doctrine v6: every agent turn must produce a receipt. Unattested turns
    are flagged as anomalies in the audit chain.

    Source: SZL Agent Tooling Graft Design, §3. DOI: 10.5281/zenodo.20431181.

    >>> r = AgentTurnReceipt("turn-1", ["Read", "Edit"], [0.9, 0.85], "admit")
    >>> r.aggregate_lambda > 0
    True
    >>> len(r.receipt_hash) == 64
    True
    """
    turn_id: str
    tool_calls: list[str]
    per_call_lambdas: list[float]
    gate_decision: str   # "admit" | "halt" | "escalate"
    aggregate_lambda: float = field(init=False)
    receipt_hash: str = field(init=False)
    timestamp: float = field(default_factory=time.time)

    def __post_init__(self) -> None:
        if self.per_call_lambdas:
            product = math.prod(max(x, 1e-300) for x in self.per_call_lambdas)
            self.aggregate_lambda = product ** (1.0 / len(self.per_call_lambdas))
        else:
            self.aggregate_lambda = 1.0
        payload = f"{self.turn_id}:{self.tool_calls}:{self.per_call_lambdas}:{self.gate_decision}"
        self.receipt_hash = hashlib.sha256(payload.encode()).hexdigest()


def emit_agent_turn_receipt(
    turn_id: str,
    tool_calls: list[str],
    per_call_lambdas: list[float],
    threshold: float = 0.8,
) -> AgentTurnReceipt:
    """
    Emit an agent turn receipt with Lambda gate decision.

    Gate decision:
      - aggregate_lambda >= threshold: "admit"
      - aggregate_lambda >= threshold * 0.7: "escalate" (human review)
      - otherwise: "halt" (HUKLLA trigger)

    Source: SZL Agent Tooling Graft Design, §3. DOI: 10.5281/zenodo.20431181.

    >>> r = emit_agent_turn_receipt("t1", ["Read"], [0.95], threshold=0.8)
    >>> r.gate_decision
    'admit'
    >>> r2 = emit_agent_turn_receipt("t2", ["Edit"], [0.1], threshold=0.8)
    >>> r2.gate_decision
    'halt'
    >>> r3 = emit_agent_turn_receipt("t3", ["Search"], [0.6], threshold=0.8)
    >>> r3.gate_decision
    'escalate'
    """
    if not per_call_lambdas:
        decision = "admit"
    else:
        product = math.prod(max(x, 1e-300) for x in per_call_lambdas)
        agg = product ** (1.0 / len(per_call_lambdas))
        if agg >= threshold:
            decision = "admit"
        elif agg >= threshold * 0.7:
            decision = "escalate"
        else:
            decision = "halt"

    return AgentTurnReceipt(
        turn_id=turn_id,
        tool_calls=tool_calls,
        per_call_lambdas=per_call_lambdas,
        gate_decision=decision,
    )


