@dataclass
class FinancialSignal:
    """
    A quantitative financial signal subject to Lambda governance.

    Source: SZL Agent Tooling Graft Design, §4. DOI: 10.5281/zenodo.20431181.

    >>> s = FinancialSignal("momentum", 0.72, 0.05, "SGX")
    >>> 0.0 <= s.lambda_score <= 1.0
    True
    >>> s.signal_type
    'momentum'
    """
    signal_type: str          # e.g., "momentum", "mean_reversion", "arbitrage"
    lambda_score: float       # governance score of this signal
    confidence: float         # statistical confidence in [0,1]
    exchange: str             # originating exchange

    def __post_init__(self) -> None:
        if not (0.0 <= self.lambda_score <= 1.0):
            raise ValueError(f"lambda_score must be in [0,1]")
        if not (0.0 <= self.confidence <= 1.0):
            raise ValueError(f"confidence must be in [0,1]")


def gate_financial_signals(
    signals: list[FinancialSignal],
    lambda_threshold: float = 0.75,
    confidence_floor: float = 0.6,
) -> dict:
    """
    Apply Lambda gate to a batch of financial signals.

    Only signals meeting BOTH Lambda threshold AND confidence floor are admitted.
    Admitted signals are sorted by combined governance-confidence score.

    Source: SZL Agent Tooling Graft Design, §4. DOI: 10.5281/zenodo.20431181.

    >>> s1 = FinancialSignal("momentum", 0.9, 0.8, "SGX")
    >>> s2 = FinancialSignal("arbitrage", 0.5, 0.9, "NYSE")
    >>> s3 = FinancialSignal("mean_reversion", 0.8, 0.4, "LSE")
    >>> result = gate_financial_signals([s1, s2, s3], lambda_threshold=0.75, confidence_floor=0.6)
    >>> result['admitted_count']
    1
    >>> result['admitted'][0].signal_type
    'momentum'
    """
    admitted = []
    rejected = []
    for s in signals:
        if s.lambda_score >= lambda_threshold and s.confidence >= confidence_floor:
            admitted.append(s)
        else:
            rejected.append(s)

    admitted.sort(
        key=lambda s: 0.6 * s.lambda_score + 0.4 * s.confidence,
        reverse=True,
    )

    return {
        "admitted": admitted,
        "admitted_count": len(admitted),
        "rejected_count": len(rejected),
        "rejected_reasons": [
            f"{s.signal_type}: Lambda={s.lambda_score:.3f} (need>={lambda_threshold}), "
            f"conf={s.confidence:.3f} (need>={confidence_floor})"
            for s in rejected
        ],
    }


# ─────────────────────────────────────────────────────────────────────────────
# §5  DUAL-WITNESS TOOL CALL
# ─────────────────────────────────────────────────────────────────────────────

@dataclass
class DualWitnessToolCall:
    """
    Two-key attestation for destructive tool calls (Write, Delete, Execute).

    Ensures that no destructive operation proceeds without both an internal
    (agent) witness and an external (operator/GCS) witness agreeing on the
    exact payload. Mismatched witnesses trigger an anomaly flag.

    Invariant (DualWitness.sound):
      verdict = "MATCH" implies internal_hash == external_hash.

    Source: SZL Agent Tooling Graft Design, §5. DOI: 10.5281/zenodo.20431181.

    >>> dw = DualWitnessToolCall.build("Write", b"import math", b"import math")
    >>> dw.verdict
    'MATCH'
    >>> dw2 = DualWitnessToolCall.build("Write", b"content A", b"content B")
    >>> dw2.verdict
    'DIVERGE'
    """
    tool_name: str
    internal_hash: str   # SHA-256 of content as seen by agent
    external_hash: str   # SHA-256 of content as seen by operator witness
    verdict: str         # "MATCH" | "DIVERGE" | "PENDING"
    timestamp: float = field(default_factory=time.time)

    @classmethod
    def build(
        cls,
        tool_name: str,
        internal_bytes: bytes,
        external_bytes: bytes | None = None,
    ) -> "DualWitnessToolCall":
        """
        Build a dual-witness record from internal and optional external content.

        If external_bytes is None: verdict = "PENDING".
        If hashes match: verdict = "MATCH".
        If hashes diverge: verdict = "DIVERGE" (anomaly flagged).

        >>> dw = DualWitnessToolCall.build("Edit", b"print(1)", b"print(1)")
        >>> dw.verdict
        'MATCH'
        >>> dw2 = DualWitnessToolCall.build("Edit", b"A", b"B")
        >>> dw2.verdict
        'DIVERGE'
        >>> dw3 = DualWitnessToolCall.build("Edit", b"A")
        >>> dw3.verdict
        'PENDING'
        """
        internal_hash = hashlib.sha256(internal_bytes).hexdigest()
        if external_bytes is None:
            return cls(tool_name, internal_hash, "", "PENDING")
        external_hash = hashlib.sha256(external_bytes).hexdigest()
        verdict = "MATCH" if internal_hash == external_hash else "DIVERGE"
        return cls(tool_name, internal_hash, external_hash, verdict)


