@dataclass
class AxisScores:
    """
    Four-dimensional Λ-axis score vector.

    Each axis ∈ [0.0, 1.0]. Axes:
      catoni_lambda  — PAC-Bayes Catoni bound (Catoni 2007, arXiv:0712.0248)
      feynman_path   — Feynman path-integral weight (Feynman 1948, doi:10.1103/RevModPhys.20.367)
      liu_hui_pi     — Liu Hui recursive refinement score (Liu Hui 263 CE)
      pacbayes_bound — Generalised PAC-Bayes bound tightness

    >>> ax = AxisScores(catoni_lambda=0.8, feynman_path=0.7, liu_hui_pi=0.9, pacbayes_bound=0.6)
    >>> all(0.0 <= v <= 1.0 for v in ax.to_dict().values())
    True
    >>> ax.to_dict()["catoni_lambda"]
    0.8
    """

    catoni_lambda: float
    feynman_path: float
    liu_hui_pi: float
    pacbayes_bound: float

    def __post_init__(self) -> None:
        for name in AXIS_IDS:
            val = getattr(self, name)
            if not (0.0 <= val <= 1.0):
                raise ValueError(f"Axis {name}={val!r} must be in [0.0, 1.0]")

    def to_dict(self) -> dict[str, float]:
        return {
            "catoni_lambda": self.catoni_lambda,
            "feynman_path": self.feynman_path,
            "liu_hui_pi": self.liu_hui_pi,
            "pacbayes_bound": self.pacbayes_bound,
        }

    def weighted_composite(self, weights: list[float]) -> float:
        """
        Weighted composite of the four axes.

        >>> ax = AxisScores(0.8, 0.7, 0.9, 0.6)
        >>> round(ax.weighted_composite([0.25, 0.25, 0.25, 0.25]), 4)
        0.75
        >>> round(ax.weighted_composite([1.0, 0.0, 0.0, 0.0]), 4)
        0.8
        """
        if len(weights) != 4:
            raise ValueError(f"weights must have 4 elements, got {len(weights)}")
        if abs(sum(weights) - 1.0) > 1e-6:
            raise ValueError(f"weights must sum to 1.0, got {sum(weights)}")
        vals = [self.catoni_lambda, self.feynman_path, self.liu_hui_pi, self.pacbayes_bound]
        return sum(v * w for v, w in zip(vals, weights))


@dataclass
class LambdaScore:
    """
    Λ-score for a single agent at a point in time.

    >>> ls = LambdaScore("agent-001", AxisScores(0.8, 0.7, 0.9, 0.6), [0.25]*4)
    >>> ls.composite
    0.75
    >>> ls.huklla_eligible
    False
    >>> ls2 = LambdaScore("agent-002", AxisScores(0.2, 0.15, 0.25, 0.18), [0.25]*4)
    >>> ls2.huklla_eligible
    True
    """

    agent_id: str
    axes: AxisScores
    weights: list[float]
    timestamp: str = field(
        default_factory=lambda: datetime.now(timezone.utc).isoformat()
    )

    def __post_init__(self) -> None:
        self._composite = self.axes.weighted_composite(self.weights)

    @property
    def composite(self) -> float:
        return self._composite

    @property
    def huklla_eligible(self) -> bool:
        """True iff composite < HALT_THRESHOLD (0.30)."""
        return self._composite < HALT_THRESHOLD

    def to_dict(self) -> dict[str, Any]:
        return {
            "agent_id": self.agent_id,
            "timestamp": self.timestamp,
            "axes": self.axes.to_dict(),
            "composite": round(self._composite, 6),
            "huklla_eligible": self.huklla_eligible,
            "halt_threshold": HALT_THRESHOLD,
        }


@dataclass
class AuditFiber:
    """
    Single node in the audit-fiber tree.

    The audit-fiber tree is the proof-artifact tree produced by Lean 4
    kernel verification of Λ-axis claims. Each fiber references a
    theorem and a receipt hash.

    >>> f = AuditFiber("f-001", None, "agent-001", "V18.0-Q1", "PASS", 0.8, "abc123")
    >>> f.status
    'PASS'
    >>> f2 = AuditFiber("f-002", "f-001", "agent-001", "V18.0-Q2", "FAIL", 0.2, "def456")
    >>> f2.parent_id
    'f-001'
    """

    fiber_id: str
    parent_id: str | None
    agent_id: str
    theorem: str
    status: str   # "PASS" | "FAIL" | "PENDING"
    lambda_val: float
    receipt_hash: str
    children: list["AuditFiber"] = field(default_factory=list)

    def __post_init__(self) -> None:
        if self.status not in ("PASS", "FAIL", "PENDING"):
            raise ValueError(f"status must be PASS/FAIL/PENDING, got {self.status!r}")

    def to_dict(self, include_children: bool = True) -> dict[str, Any]:
        d: dict[str, Any] = {
            "fiber_id": self.fiber_id,
            "parent_id": self.parent_id,
            "agent_id": self.agent_id,
            "theorem": self.theorem,
            "status": self.status,
            "lambda": round(self.lambda_val, 6),
            "receipt_hash": self.receipt_hash,
        }
        if include_children:
            d["children"] = [c.to_dict() for c in self.children]
        return d


@dataclass
class OperatorDashboardData:
    """
    Python pendant of the szl-operator-dashboard TypeScript data model.

    Aggregates Λ-scores, audit fibers, and receipts for dashboard rendering.
    Upstream structural reference: JohnMwendwa/vet-management-system (NONE license).
    SZL innovation: Λ-axis semantics, audit-fiber tree, HUKLLA halt-eligibility.

    >>> axes = AxisScores(0.8, 0.7, 0.9, 0.6)
    >>> ls = LambdaScore("agent-001", axes, [0.25]*4)
    >>> fiber = AuditFiber("f-001", None, "agent-001", "V18.0-Q1", "PASS", 0.8, "abc")
    >>> data = OperatorDashboardData(lambda_scores=[ls], audit_fibers=[fiber], receipts=[])
    >>> len(data.lambda_scores)
    1
    >>> data.huklla_alerts()
    []
    """

    lambda_scores: list[LambdaScore]
    audit_fibers: list[AuditFiber]
    receipts: list[dict[str, Any]]

    def huklla_alerts(self) -> list[dict[str, Any]]:
        """
        Return list of halt-eligible agents with escalation metadata.

        >>> axes_bad = AxisScores(0.1, 0.2, 0.15, 0.18)
        >>> ls_bad = LambdaScore("agent-halt", axes_bad, [0.25]*4)
        >>> data = OperatorDashboardData([ls_bad], [], [])
        >>> alerts = data.huklla_alerts()
        >>> len(alerts)
        1
        >>> alerts[0]["agent_id"]
        'agent-halt'
        >>> alerts[0]["escalation_level"] in (1, 2, 3)
        True
        """
        alerts = []
        for ls in self.lambda_scores:
            if ls.huklla_eligible:
                below = [
                    axis
                    for axis, val in ls.axes.to_dict().items()
                    if val < HALT_THRESHOLD
                ]
                # Escalation: 1 = composite barely below, 2 = < 0.20, 3 = < 0.10
                level = 1
                if ls.composite < 0.20:
                    level = 2
                if ls.composite < 0.10:
                    level = 3
                alerts.append(
                    {
                        "agent_id": ls.agent_id,
                        "composite": round(ls.composite, 6),
                        "halt_threshold": HALT_THRESHOLD,
                        "axes_below_threshold": below,
                        "escalation_level": level,
                    }
                )
        return alerts

