# ──────────────────────────────────────────────────────────────────────────────
# lambda_axis_summary
# Generates dashboard-ready summary statistics for the Λ-axis scores panel.
# ──────────────────────────────────────────────────────────────────────────────


def lambda_axis_summary(
    executions: list[dict[str, Any]],
    axes_weights: list[float],
) -> dict[str, Any]:
    """
    Generate dashboard-ready summary statistics for a list of agent executions.

    Each execution dict must have:
      - "agent_id": str
      - "axes": dict with keys matching AXIS_IDS and float values ∈ [0, 1]

    Returns a dict with:
      - "agent_count": int
      - "mean_composite": float — mean weighted composite across all agents
      - "min_composite": float
      - "max_composite": float
      - "huklla_count": int — agents below HALT_THRESHOLD
      - "per_axis_mean": dict[str, float] — mean per axis
      - "axes_weights": list[float]
      - "doctrine_version": str

    Args:
        executions: List of execution dicts.
        axes_weights: Weight vector for the four axes, must sum to 1.0.

    >>> execs = [
    ...     {"agent_id": "a1", "axes": {"catoni_lambda": 0.8, "feynman_path": 0.7,
    ...                                  "liu_hui_pi": 0.9, "pacbayes_bound": 0.6}},
    ...     {"agent_id": "a2", "axes": {"catoni_lambda": 0.2, "feynman_path": 0.1,
    ...                                  "liu_hui_pi": 0.15, "pacbayes_bound": 0.18}},
    ... ]
    >>> summary = lambda_axis_summary(execs, [0.25, 0.25, 0.25, 0.25])
    >>> summary["agent_count"]
    2
    >>> summary["huklla_count"]
    1
    >>> 0.0 <= summary["mean_composite"] <= 1.0
    True
    >>> summary["min_composite"] < summary["max_composite"]
    True
    >>> summary["doctrine_version"]
    'v6'
    >>> all(k in summary["per_axis_mean"] for k in ("catoni_lambda", "feynman_path", "liu_hui_pi", "pacbayes_bound"))
    True

    Raises:
        ValueError: if axes_weights does not sum to 1.0 or has wrong length.
        ValueError: if any axis value is outside [0, 1].

    >>> lambda_axis_summary([], [0.25, 0.25, 0.25, 0.25])["agent_count"]
    0
    >>> lambda_axis_summary([], [0.25, 0.25, 0.25, 0.25])["mean_composite"]
    0.0
    """
    if len(axes_weights) != 4:
        raise ValueError(f"axes_weights must have 4 elements, got {len(axes_weights)}")
    if abs(sum(axes_weights) - 1.0) > 1e-6:
        raise ValueError(f"axes_weights must sum to 1.0, got {sum(axes_weights)}")

    if not executions:
        return {
            "agent_count": 0,
            "mean_composite": 0.0,
            "min_composite": 0.0,
            "max_composite": 0.0,
            "huklla_count": 0,
            "per_axis_mean": {k: 0.0 for k in AXIS_IDS},
            "axes_weights": axes_weights,
            "doctrine_version": DOCTRINE_VERSION,
        }

    composites: list[float] = []
    axis_sums: dict[str, float] = {k: 0.0 for k in AXIS_IDS}
    huklla_count = 0

    for ex in executions:
        axes_dict: dict[str, float] = ex["axes"]
        for axis in AXIS_IDS:
            val = axes_dict[axis]
            if not (0.0 <= val <= 1.0):
                raise ValueError(f"axis {axis}={val!r} outside [0, 1]")
            axis_sums[axis] += val

        vals = [axes_dict[k] for k in AXIS_IDS]
        composite = sum(v * w for v, w in zip(vals, axes_weights))
        composites.append(composite)
        if composite < HALT_THRESHOLD:
            huklla_count += 1

    n = len(executions)
    return {
        "agent_count": n,
        "mean_composite": round(sum(composites) / n, 6),
        "min_composite": round(min(composites), 6),
        "max_composite": round(max(composites), 6),
        "huklla_count": huklla_count,
        "per_axis_mean": {k: round(axis_sums[k] / n, 6) for k in AXIS_IDS},
        "axes_weights": axes_weights,
        "doctrine_version": DOCTRINE_VERSION,
    }


