# receipt_chain_timeline
# Sorts and annotates receipts for timeline display in the operator dashboard.
# Upstream pattern: JohnMwendwa/recipe-book-app CRUD pattern (NONE license).
# SZL innovation: receipt-chain hash verification, doctrine-v6 annotation.
# ──────────────────────────────────────────────────────────────────────────────


def receipt_chain_timeline(receipts: list[dict[str, Any]]) -> list[dict[str, Any]]:
    """
    Sort and annotate receipts for timeline display.

    Each receipt dict must have:
      - "receipt_id": str
      - "execution_id": str
      - "agent_id": str
      - "lambda": float ∈ [0, 1]
      - "timestamp": str — ISO 8601
      - "witness_type": str — "classical" | "quantum" | "dual"
      - "classical_witness_hash": str
      - "doctrine_version": str

    Annotations added by this function:
      - "sha256": SHA-256 of canonical JSON representation
      - "huklla_eligible": bool
      - "chain_index": int — position in sorted chain (0-based)
      - "prev_receipt_sha": str | None — SHA-256 of previous receipt in chain

    Sorted by timestamp ascending.

    >>> receipts = [
    ...     {"receipt_id": "r2", "execution_id": "e2", "agent_id": "a1",
    ...      "lambda": 0.7, "timestamp": "2026-05-28T10:01:00Z",
    ...      "witness_type": "classical", "classical_witness_hash": "hash2",
    ...      "doctrine_version": "v6"},
    ...     {"receipt_id": "r1", "execution_id": "e1", "agent_id": "a1",
    ...      "lambda": 0.8, "timestamp": "2026-05-28T10:00:00Z",
    ...      "witness_type": "classical", "classical_witness_hash": "hash1",
    ...      "doctrine_version": "v6"},
    ... ]
    >>> timeline = receipt_chain_timeline(receipts)
    >>> len(timeline)
    2
    >>> timeline[0]["receipt_id"]
    'r1'
    >>> timeline[1]["chain_index"]
    1
    >>> timeline[0]["prev_receipt_sha"] is None
    True
    >>> timeline[1]["prev_receipt_sha"] == timeline[0]["sha256"]
    True
    >>> all("sha256" in r for r in timeline)
    True
    >>> all("huklla_eligible" in r for r in timeline)
    True

    Empty input:

    >>> receipt_chain_timeline([])
    []
    """
    if not receipts:
        return []

    def _canonical_sha256(obj: dict[str, Any]) -> str:
        canonical = json.dumps(
            {k: obj[k] for k in sorted(obj.keys()) if k not in ("sha256", "prev_receipt_sha", "chain_index")},
            sort_keys=True,
            ensure_ascii=True,
        )
        return hashlib.sha256(canonical.encode()).hexdigest()

    # Sort ascending by timestamp
    sorted_receipts = sorted(receipts, key=lambda r: r["timestamp"])

    result: list[dict[str, Any]] = []
    prev_sha: str | None = None

    for idx, receipt in enumerate(sorted_receipts):
        annotated = dict(receipt)
        annotated["chain_index"] = idx
        annotated["huklla_eligible"] = float(receipt["lambda"]) < HALT_THRESHOLD
        annotated["sha256"] = _canonical_sha256(annotated)
        annotated["prev_receipt_sha"] = prev_sha
        prev_sha = annotated["sha256"]
        result.append(annotated)

    return result


