@dataclass
class LearningPathManifest:
    """
    Generates the doctrine-v6 learning path JSON.

    Upstream pattern: JohnMwendwa/free-ai-resources (MIT).
    Citation: https://github.com/JohnMwendwa/free-ai-resources
      commit b6ae6a626485025dfaebd0fd59b35ab09e87e429 — MIT License
    SZL innovation: kernel-checked-proof literacy; no consumer AI courses.

    >>> m = LearningPathManifest()
    >>> j = m.to_json()
    >>> import json as _json
    >>> data = _json.loads(j)
    >>> data["doctrine_version"]
    'v6'
    >>> len(data["required_readings"]) >= 4
    True
    >>> all(r["doctrine_v6_prerequisite"] for r in data["required_readings"])
    True
    >>> len(data["hands_on_exercises"]) >= 3
    True
    >>> data["upstream_citation"]["license"]
    'MIT'
    """

    doctrine_version: str = DOCTRINE_VERSION
    required_readings: list[dict[str, Any]] = field(
        default_factory=lambda: list(REQUIRED_READINGS)
    )
    optional_by_version: dict[str, list[str]] = field(
        default_factory=lambda: dict(OPTIONAL_BY_VERSION)
    )
    hands_on_exercises: list[dict[str, Any]] = field(
        default_factory=lambda: list(HANDS_ON_EXERCISES)
    )

    def to_dict(self) -> dict[str, Any]:
        """Return the manifest as a Python dict.

        >>> m = LearningPathManifest()
        >>> d = m.to_dict()
        >>> "required_readings" in d
        True
        >>> "optional_by_version" in d
        True
        >>> "community_channels" in d
        True
        """
        return {
            "doctrine_version": self.doctrine_version,
            "payload_version": PAYLOAD_VERSION,
            "upstream_citation": {
                "repo": "JohnMwendwa/free-ai-resources",
                "url": "https://github.com/JohnMwendwa/free-ai-resources",
                "commit": "b6ae6a626485025dfaebd0fd59b35ab09e87e429",
                "license": "MIT",
            },
            "szl_innovation": (
                "First AI-governance curriculum requiring kernel-checked-proof literacy. "
                "Required readings begin at PAC-Bayes proofs, not consumer AI courses."
            ),
            "required_readings": self.required_readings,
            "optional_by_version": self.optional_by_version,
            "hands_on_exercises": self.hands_on_exercises,
            "community_channels": {
                "github_discussions": "https://github.com/szl-holdings/ouroboros-thesis/discussions",
                "doctrine_v6_qa": "https://github.com/szl-holdings/community/discussions",
            },
        }

    def to_json(self, indent: int = 2) -> str:
        """Return the manifest as a JSON string.

        >>> m = LearningPathManifest()
        >>> j = m.to_json()
        >>> j.startswith('{')
        True
        """
        return json.dumps(self.to_dict(), indent=indent, ensure_ascii=False)

    def required_ids(self) -> list[str]:
        """
        Return list of required reading IDs.

        >>> m = LearningPathManifest()
        >>> "catoni-2007" in m.required_ids()
        True
        >>> "feynman-1948" in m.required_ids()
        True
        """
        return [r["id"] for r in self.required_readings]


# ──────────────────────────────────────────────────────────────────────────────
# DpiCapacityMeter
# DPI-bound capacity meter — data-processing intensity fraction.
# ──────────────────────────────────────────────────────────────────────────────


def compute_dpi_bound(
    mutual_info_xy: float,
    lambda_score: float,
) -> dict[str, float]:
    """
    Compute DPI-bound capacity fraction.

    DPI (Data Processing Inequality): I(X;Z) ≤ I(X;Y) for any Markov chain X→Y→Z.
    DPI-bound capacity fraction = lambda_score / max(mutual_info_xy, 1e-9).
    Clamped to [0, 1].

    Args:
        mutual_info_xy: Mutual information I(X;Y) ≥ 0 (nats or bits).
        lambda_score: Composite Λ-score ∈ [0, 1].

    >>> result = compute_dpi_bound(0.8, 0.6)
    >>> 0.0 <= result["dpi_fraction"] <= 1.0
    True
    >>> result["dpi_fraction"]
    0.75
    >>> compute_dpi_bound(0.0, 0.5)["dpi_fraction"]
    1.0
    >>> compute_dpi_bound(1.0, 1.0)["dpi_fraction"]
    1.0
    """
    denom = max(mutual_info_xy, 1e-9)
    fraction = min(lambda_score / denom, 1.0)
    return {
        "mutual_info_xy": mutual_info_xy,
        "lambda_score": lambda_score,
        "dpi_fraction": round(fraction, 6),
        "dpi_bound_satisfied": lambda_score <= mutual_info_xy,
    }


