def _run_tests() -> int:
    """Run assertion-based self-tests. Returns number of failures."""
    failures = 0

    def check(condition: bool, label: str) -> None:
        nonlocal failures
        if not condition:
            print(f"  FAIL: {label}")
            failures += 1
        else:
            print(f"  pass: {label}")

    print(chr(10) + "--- AxisScores ---")
    ax = AxisScores(catoni_lambda=0.8, feynman_path=0.7, liu_hui_pi=0.9, pacbayes_bound=0.6)
    check(ax.catoni_lambda == 0.8, "T01 catoni_lambda=0.8")
    check(all(0 <= v <= 1 for v in ax.to_dict().values()), "T02 all axes ∈ [0,1]")
    check(
        abs(ax.weighted_composite([0.25, 0.25, 0.25, 0.25]) - 0.75) < 1e-6,
        "T03 uniform weights composite=0.75",
    )
    check(
        abs(ax.weighted_composite([1.0, 0.0, 0.0, 0.0]) - 0.8) < 1e-6,
        "T04 single-axis weight",
    )

    try:
        AxisScores(catoni_lambda=1.5, feynman_path=0.7, liu_hui_pi=0.9, pacbayes_bound=0.6)
        check(False, "T05 invalid axis should raise")
    except ValueError:
        check(True, "T05 invalid axis raises ValueError")

    print(chr(10) + "--- LambdaScore ---")
    ls_good = LambdaScore("a1", AxisScores(0.8, 0.7, 0.9, 0.6), [0.25] * 4)
    ls_bad = LambdaScore("a2", AxisScores(0.1, 0.2, 0.15, 0.18), [0.25] * 4)
    check(not ls_good.huklla_eligible, "T06 good score not HUKLLA eligible")
    check(ls_bad.huklla_eligible, "T07 bad score HUKLLA eligible")
    check(abs(ls_good.composite - 0.75) < 1e-6, "T08 good composite=0.75")

    print(chr(10) + "--- OperatorDashboardData ---")
    fiber = AuditFiber("f-001", None, "a1", "V18.0-Q1", "PASS", 0.8, "abc123")
    data = OperatorDashboardData([ls_good, ls_bad], [fiber], [])
    alerts = data.huklla_alerts()
    check(len(alerts) == 1, "T09 one HUKLLA alert")
    check(alerts[0]["agent_id"] == "a2", "T10 alert agent_id=a2")
    check(alerts[0]["escalation_level"] in (1, 2, 3), "T11 escalation level valid")
    features = data.v18x_feature_status()
    check(any(f["feature_name"] == "sovereign-train" for f in features), "T12 sovereign-train present")
    check(any(f["feature_name"] == "operator-dashboard" for f in features), "T13 operator-dashboard present")

    print(chr(10) + "--- lambda_axis_summary ---")
    execs = [
        {"agent_id": "a1", "axes": {"catoni_lambda": 0.8, "feynman_path": 0.7,
                                     "liu_hui_pi": 0.9, "pacbayes_bound": 0.6}},
        {"agent_id": "a2", "axes": {"catoni_lambda": 0.2, "feynman_path": 0.1,
                                     "liu_hui_pi": 0.15, "pacbayes_bound": 0.18}},
    ]
    summary = lambda_axis_summary(execs, [0.25, 0.25, 0.25, 0.25])
    check(summary["agent_count"] == 2, "T14 agent_count=2")
    check(summary["huklla_count"] == 1, "T15 huklla_count=1")
    check(summary["doctrine_version"] == "v6", "T16 doctrine_version=v6")
    check(summary["min_composite"] < summary["max_composite"], "T17 min < max composite")
    check(0.0 <= summary["mean_composite"] <= 1.0, "T18 mean_composite ∈ [0,1]")

    empty_summary = lambda_axis_summary([], [0.25, 0.25, 0.25, 0.25])
    check(empty_summary["agent_count"] == 0, "T19 empty summary agent_count=0")
    check(empty_summary["mean_composite"] == 0.0, "T20 empty summary mean=0.0")

    print(chr(10) + "--- receipt_chain_timeline ---")
    receipts = [
        {"receipt_id": "r2", "execution_id": "e2", "agent_id": "a1",
         "lambda": 0.7, "timestamp": "2026-05-28T10:01:00Z",
         "witness_type": "classical", "classical_witness_hash": "hash2",
         "doctrine_version": "v6"},
        {"receipt_id": "r1", "execution_id": "e1", "agent_id": "a1",
         "lambda": 0.8, "timestamp": "2026-05-28T10:00:00Z",
         "witness_type": "classical", "classical_witness_hash": "hash1",
         "doctrine_version": "v6"},
    ]
    timeline = receipt_chain_timeline(receipts)
    check(len(timeline) == 2, "T21 timeline length=2")
    check(timeline[0]["receipt_id"] == "r1", "T22 sorted ascending by timestamp")
    check(timeline[0]["prev_receipt_sha"] is None, "T23 first receipt prev=None")
    check(timeline[1]["prev_receipt_sha"] == timeline[0]["sha256"], "T24 chain link valid")
    check(all("sha256" in r for r in timeline), "T25 all receipts have sha256")
    check(receipt_chain_timeline([]) == [], "T26 empty receipts returns []")

    print(chr(10) + "--- LearningPathManifest ---")
    manifest = LearningPathManifest()
    d = manifest.to_dict()
    check(d["doctrine_version"] == "v6", "T27 manifest doctrine_version=v6")
    check(len(d["required_readings"]) >= 4, "T28 ≥4 required readings")
    check(all(r["doctrine_v6_prerequisite"] for r in d["required_readings"]), "T29 all required are v6 prereq")
    check("catoni-2007" in manifest.required_ids(), "T30 catoni-2007 in required_ids")
    check(d["upstream_citation"]["license"] == "MIT", "T31 upstream MIT license")

    print(chr(10) + "--- compute_dpi_bound ---")
    dpi = compute_dpi_bound(0.8, 0.6)
    check(abs(dpi["dpi_fraction"] - 0.75) < 1e-6, "T32 dpi_fraction=0.75")
    check(dpi["dpi_bound_satisfied"], "T33 dpi bound satisfied for 0.6<=0.8")
    dpi2 = compute_dpi_bound(0.4, 0.6)
    check(not dpi2["dpi_bound_satisfied"], "T34 dpi bound violated for 0.6>0.4")
    dpi3 = compute_dpi_bound(0.0, 0.5)
    check(dpi3["dpi_fraction"] == 1.0, "T35 zero mutual_info → fraction clamped to 1.0")

    return failures


