def run_self_tests() -> int:
    """Standard hook for OUROBOROS_RUN_ALL.py. Returns number of failures."""
    import doctest
    dr = doctest.testmod(verbose=False)
    doctest_fails = dr.failed
    assertion_fails = _run_tests()
    return doctest_fails + assertion_fails


