def firewall_preserves_lambda(
    src_lambda: float,
    dst_lambda: float,
    threshold: float,
) -> bool:
    """
    Evaluate whether a NGFW flow (src, dst) satisfies the Λ-threshold policy.

    Graft C — Python pendant of Lutar.NetworkLambda.firewall_preserves_lambda.
    A next-generation firewall policy that allows traffic only if
    (src.Λ + dst.Λ) / 2 ≥ threshold preserves system-wide Λ.

    Cite: Nir Zuk Zero Trust doctrine
    Cite: PAN-OS SP3 architecture (paloaltonetworks.com/cyberpedia/zero-trust-and-sase)
    Lean theorem: Lutar.NetworkLambda.firewall_preserves_lambda (1 honest axiom:
                  NGFW_lambda_prop)

    Parameters
    ----------
    src_lambda : Λ-score of the source endpoint (0.0–1.0)
    dst_lambda : Λ-score of the destination endpoint (0.0–1.0)
    threshold  : minimum (src.Λ + dst.Λ)/2 to permit the flow

    Returns
    -------
    bool — True if flow is permitted (Λ ≥ threshold), False if denied

    Doctests
    --------
    >>> firewall_preserves_lambda(0.90, 0.80, 0.75)
    True
    >>> firewall_preserves_lambda(0.50, 0.60, 0.75)
    False
    >>> firewall_preserves_lambda(0.75, 0.75, 0.75)
    True
    >>> firewall_preserves_lambda(0.74, 0.75, 0.75)
    False
    >>> firewall_preserves_lambda(1.0, 1.0, 1.0)
    True
    >>> firewall_preserves_lambda(0.0, 0.0, 0.001)
    False
    """
    if not (0.0 <= src_lambda <= 1.0):
        raise ValueError(f"src_lambda must be in [0,1]; got {src_lambda}")
    if not (0.0 <= dst_lambda <= 1.0):
        raise ValueError(f"dst_lambda must be in [0,1]; got {dst_lambda}")
    if not (0.0 < threshold <= 1.0):
        raise ValueError(f"threshold must be in (0,1]; got {threshold}")
    flow_lambda = (src_lambda + dst_lambda) / 2.0
    return flow_lambda >= threshold


def sase_session_lambda_floor(
    user_lambda: float,
    device_lambda: float,
    resource_lambda: float,
) -> float:
    """
    Compute SASE per-session Λ floor (ZTNA 2.0 model — minimum of all principals).

    Pendant of Lutar.NetworkLambda.sase_zero_trust_lambda_bound.
    SASE/ZTNA 2.0 grants access only if ALL three Λ-scores meet threshold.
    The session Λ floor is the minimum across user, device, resource.

    Cite: paloaltonetworks.com/cyberpedia/zero-trust-and-sase

    >>> round(sase_session_lambda_floor(0.90, 0.85, 0.80), 4)
    0.8
    >>> sase_session_lambda_floor(0.90, 0.40, 0.85)
    0.4
    >>> sase_session_lambda_floor(1.0, 1.0, 1.0)
    1.0
    """
    return min(user_lambda, device_lambda, resource_lambda)


