# §4. GRAFT C — gnn_pac_bayes_bound
# =============================================================================

def gnn_pac_bayes_bound(
    empirical_risk: float,
    kl: float,
    m: int,
    delta: float = 0.05,
    gov_penalty: float = 0.0,
) -> float:
    """
    PAC-Bayes generalization bound for GNNs.

    Runtime pendant for Lutar.GraphPACBayes.gnn_pac_bayes_bound (Lean skeleton
    in szl_pyg_graft_design.md, Graft C).

    For any prior P over GNN weights, with probability >= 1 - delta over m
    training graphs:
      true_risk <= empirical_risk + sqrt((KL + gov_penalty + ln(1/delta)) / (2m))

    Literature:
      Liao et al. 2021 — PAC-Bayes for GNNs — https://arxiv.org/abs/2012.13619
      Ma et al. 2021 — https://arxiv.org/abs/2012.11454
      McAllester 1999 — https://arxiv.org/abs/cs/9912023

    Cross-reference:
      v15 Lutar.DPOFeasibility + Lutar.PACBayes
      /home/user/workspace/szl/repos/lutar-lean/Lutar/PACBayes.lean

    Parameters
    ----------
    empirical_risk : float
        Empirical risk in [0, 1].
    kl : float
        KL(Q || P) >= 0.
    m : int
        Number of training samples (m >= 1).
    delta : float
        Failure probability in (0, 1). Default: 0.05.
    gov_penalty : float
        Governance penalty: ln(tau / max(lambda_graph, eps)). Default: 0.0.

    Returns
    -------
    float
        Upper bound on true risk.

    Raises
    ------
    ValueError
        If inputs are out of range.

    Examples
    --------
    >>> round(gnn_pac_bayes_bound(0.1, 0.0, 1000), 6)
    0.138702
    >>> round(gnn_pac_bayes_bound(0.0, 0.0, 1000), 6)
    0.038702
    >>> gnn_pac_bayes_bound(0.5, 1.0, 100) > 0.5
    True
    >>> gnn_pac_bayes_bound(0.1, 0.0, 1000) < gnn_pac_bayes_bound(0.1, 1.0, 1000)
    True
    >>> gnn_pac_bayes_bound(0.1, 0.0, 100) > gnn_pac_bayes_bound(0.1, 0.0, 10000)
    True
    >>> gnn_pac_bayes_bound(0.1, 0.0, 1000, gov_penalty=0.5) > gnn_pac_bayes_bound(0.1, 0.0, 1000)
    True
    """
    if empirical_risk < 0 or empirical_risk > 1:
        raise ValueError(f"empirical_risk must be in [0, 1], got {empirical_risk}")
    if kl < 0:
        raise ValueError(f"kl must be >= 0, got {kl}")
    if m < 1:
        raise ValueError(f"m must be >= 1, got {m}")
    if not (0 < delta < 1):
        raise ValueError(f"delta must be in (0, 1), got {delta}")
    if gov_penalty < 0:
        raise ValueError(f"gov_penalty must be >= 0, got {gov_penalty}")

    complexity = (kl + gov_penalty + math.log(1.0 / delta)) / (2.0 * m)
    return empirical_risk + math.sqrt(complexity)


def gov_penalty(lambda_graph: float, tau: float = 1.0, eps: float = 1e-8) -> float:
    """
    Compute governance penalty: log(tau / max(lambda_graph, eps)).

    When lambda_graph < tau, the penalty is positive (worse bound).
    When lambda_graph >= tau, penalty is 0 or negative (clamped to 0).

    Runtime pendant for Lutar.GraphPACBayes.govPenalty.

    >>> round(gov_penalty(1.0), 6)
    0.0
    >>> gov_penalty(0.5) > 0
    True
    >>> gov_penalty(0.1) > gov_penalty(0.5)
    True
    >>> gov_penalty(0.0) > 0
    True
    """
    denom = max(lambda_graph, eps)
    raw = math.log(tau / denom)
    return max(raw, 0.0)


