# =============================================================================
# §1. LayerReceipt — per-layer governance receipt
# =============================================================================

@dataclass
class LayerReceipt:
    """
    Per-layer governance receipt for DSA sparse attention.

    SHA-256 over (layer_idx, canonical top-k indices, optional attn hash).
    Mirrors v18.13 BatchReceipt schema (OUROBOROS_RUN_ALL.py line 12318).

    Upstream: rasbt/LLMs-from-scratch ch04/09_dsa/gpt_with_kv_dsa.py
    Lines: topk_indices = index_scores.topk(k_val, dim=-1).indices  (line ~106)
    SHA: 63224d6e2650de46970cdd08c9e5d05d65138604

    Attributes
    ----------
    receipt_sha : str
        64-char SHA-256 hex digest.
    layer_idx : int
        Transformer layer index.
    topk_k : int
        k value (number of tokens selected).
    seq_len : int
        Query sequence length (T_q).
    version : str
        Graft provenance tag.

    Examples
    --------
    >>> r = LayerReceipt(receipt_sha="a" * 64, layer_idx=0, topk_k=5, seq_len=10,
    ...                  version="v18.15-szl-dsa-receipt-kernel")
    >>> r.layer_idx
    0
    >>> r.topk_k
    5
    >>> r.version
    'v18.15-szl-dsa-receipt-kernel'
    >>> r.is_valid()
    True
    """
    receipt_sha: str
    layer_idx: int
    topk_k: int
    seq_len: int
    version: str = "v18.15-szl-dsa-receipt-kernel"

    def is_valid(self) -> bool:
        """
        Validate receipt structure.

        >>> r = LayerReceipt.from_topk_indices(2, [[0, 1, 2], [1, 2, 3]])
        >>> r.is_valid()
        True
        >>> bad = LayerReceipt(receipt_sha="short", layer_idx=-1, topk_k=0, seq_len=0)
        >>> bad.is_valid()
        False
        """
        return (
            len(self.receipt_sha) == 64
            and self.layer_idx >= 0
            and self.topk_k > 0
            and self.seq_len > 0
        )

    @classmethod
    def from_topk_indices(
        cls,
        layer_idx: int,
        topk_indices: list[list[int]],
        attn_sample: Optional[list[float]] = None,
    ) -> "LayerReceipt":
        """
        Build a LayerReceipt from top-k index data.

        Canonical form: sort each row before hashing (position-invariant).
        Mirrors rasbt's topk_indices selection (gpt_with_kv_dsa.py line ~106).

        Parameters
        ----------
        layer_idx : int
            Layer index.
        topk_indices : list of list of int
            Shape (T_q, k). Top-k token indices per query position.
        attn_sample : list of float, optional
            Sample attention weights for extra hash material.

        Returns
        -------
        LayerReceipt

        Examples
        --------
        >>> r = LayerReceipt.from_topk_indices(0, [[2, 0, 1], [3, 1, 2]])
        >>> len(r.receipt_sha) == 64
        True
        >>> r.topk_k
        3
        >>> r.seq_len
        2
        >>> r.layer_idx
        0
        >>> # Canonical: sorted rows → same receipt regardless of order in row
        >>> r1 = LayerReceipt.from_topk_indices(0, [[0, 1, 2]])
        >>> r2 = LayerReceipt.from_topk_indices(0, [[2, 0, 1]])
        >>> r1.receipt_sha == r2.receipt_sha
        True
        >>> # Different layer_idx → different receipt
        >>> r3 = LayerReceipt.from_topk_indices(1, [[0, 1, 2]])
        >>> r1.receipt_sha != r3.receipt_sha
        True
        """
        T_q = len(topk_indices)
        k = len(topk_indices[0]) if topk_indices else 0
        canonical = [sorted(row) for row in topk_indices]
        payload = f"layer={layer_idx}"
        for row in canonical:
            payload += "|" + ",".join(str(x) for x in row)
        if attn_sample is not None:
            ap_str = ",".join(f"{x:.6f}" for x in attn_sample)
            payload += "|attn=" + hashlib.sha256(ap_str.encode()).hexdigest()[:16]
        sha = hashlib.sha256(payload.encode()).hexdigest()
        return cls(receipt_sha=sha, layer_idx=layer_idx, topk_k=k, seq_len=T_q)


# =============================================================================
# §2. DSAReceiptChain — SHA-256 Wheeler chain over layer receipts
# =============================================================================

@dataclass
class DSAReceiptChain:
    """
    SHA-256 chain over DSA layer receipts (Wheeler chain pattern, v18.13).

    chain_sha[i] = SHA-256(chain_sha[i-1] || receipt_sha[i])
    First entry: chain_sha[0] = SHA-256("0"*64 || receipt_sha[0])

    Reuses v18.13 BatchReceipt.chain_hash pattern:
    OUROBOROS_RUN_ALL.py lines 12380–12400 (BatchReceipt.chain_hash)

    Attributes
    ----------
    entries : list of LayerReceipt
        All receipts in chain order.

    Examples
    --------
    >>> chain = DSAReceiptChain()
    >>> chain.is_empty()
    True
    >>> r0 = LayerReceipt.from_topk_indices(0, [[0, 1, 2]])
    >>> _ = chain.append(r0)
    >>> chain.is_empty()
    False
    >>> len(chain.get_chain_sha()) == 64
    True
    """
    entries: list[LayerReceipt] = field(default_factory=list)
    _chain_shas: list[str] = field(default_factory=list, repr=False)

    def is_empty(self) -> bool:
        """
        Check if chain has no entries.

        >>> chain = DSAReceiptChain()
        >>> chain.is_empty()
        True
        >>> _ = chain.append(LayerReceipt.from_topk_indices(0, [[0]]))
        >>> chain.is_empty()
        False
        """
        return len(self.entries) == 0

    def append(self, receipt: LayerReceipt) -> str:
        """
        Append a receipt to the chain and return the new chain SHA.

        chain_sha = SHA-256(prev_chain_sha || receipt.receipt_sha)

        Parameters
        ----------
        receipt : LayerReceipt

        Returns
        -------
        str : new chain SHA (64 hex chars)

        Examples
        --------
        >>> chain = DSAReceiptChain()
        >>> r0 = LayerReceipt.from_topk_indices(0, [[0, 1]])
        >>> sha0 = chain.append(r0)
        >>> len(sha0) == 64
        True
        >>> r1 = LayerReceipt.from_topk_indices(1, [[1, 2]])
        >>> sha1 = chain.append(r1)
        >>> sha1 != sha0
        True
        >>> len(sha1) == 64
        True
        """
        prev = self._chain_shas[-1] if self._chain_shas else "0" * 64
        new_sha = hashlib.sha256((prev + receipt.receipt_sha).encode()).hexdigest()
        self.entries.append(receipt)
        self._chain_shas.append(new_sha)
        return new_sha

    def get_chain_sha(self) -> str:
        """
        Return the current cumulative chain SHA.

        Returns "0"*64 for empty chain.

        Examples
        --------
        >>> chain = DSAReceiptChain()
        >>> chain.get_chain_sha() == "0" * 64
        True
        >>> _ = chain.append(LayerReceipt.from_topk_indices(0, [[0, 1]]))
        >>> len(chain.get_chain_sha()) == 64
        True
        """
        if not self._chain_shas:
            return "0" * 64
        return self._chain_shas[-1]

    @staticmethod
    def batch_chain_hash(receipts: list[LayerReceipt]) -> str:
        """
        Compute Wheeler chain hash over a list of receipts in one shot.

        Identical to v18.13 BatchReceipt.chain_hash:
        chain = SHA-256(sha_0 || sha_1 || ... || sha_n)

        Examples
        --------
        >>> r0 = LayerReceipt.from_topk_indices(0, [[0, 1]])
        >>> r1 = LayerReceipt.from_topk_indices(1, [[1, 2]])
        >>> ch = DSAReceiptChain.batch_chain_hash([r0, r1])
        >>> len(ch) == 64
        True
        >>> # Deterministic
        >>> ch2 = DSAReceiptChain.batch_chain_hash([r0, r1])
        >>> ch == ch2
        True
        >>> # Different order → different hash
        >>> ch3 = DSAReceiptChain.batch_chain_hash([r1, r0])
        >>> ch != ch3
        True
        """
        combined = "".join(r.receipt_sha for r in receipts)
        return hashlib.sha256(combined.encode()).hexdigest()

    def verify_chain(self) -> bool:
        """
        Verify the internal consistency of the chain.

        Rebuilds all chain SHAs from scratch and compares.

        Examples
        --------
        >>> chain = DSAReceiptChain()
        >>> _ = chain.append(LayerReceipt.from_topk_indices(0, [[0, 1]]))
        >>> _ = chain.append(LayerReceipt.from_topk_indices(1, [[1, 2]]))
        >>> chain.verify_chain()
        True
        """
        rebuilt = []
        prev = "0" * 64
        for r in self.entries:
            sha = hashlib.sha256((prev + r.receipt_sha).encode()).hexdigest()
            rebuilt.append(sha)
            prev = sha
        return rebuilt == self._chain_shas


# =============================================================================
# §3. TopKSparseAttention — Graft A numpy pendant
# =============================================================================

class TopKSparseAttention:
    """
    Pure-numpy top-k sparse attention with Λ-receipt per layer.

    Pendant of Lutar.SparseAttentionLambda (Graft A) and DSAReceiptAttention (Graft B).

    Emulates rasbt's LightningIndexer + MultiHeadAttentionWithDSA using numpy.
    NO torch import.

    Upstream: rasbt/LLMs-from-scratch ch04/09_dsa/gpt_with_kv_dsa.py
    SHA: 63224d6e2650de46970cdd08c9e5d05d65138604
    Classes:
      LightningIndexer.__init__:  lines ~41–61
      LightningIndexer.forward:   lines ~63–106
      MultiHeadAttentionWithDSA:  lines ~109–246

    Parameters
    ----------
    emb_dim : int
        Embedding dimension.
    n_heads : int
        Number of attention heads.
    index_n_heads : int
        Number of lightweight indexer heads (H_I in the paper).
    index_head_dim : int
        Dimension per indexer head.
    topk : int
        Number of tokens to select (k).
    layer_idx : int
        Layer index for receipt labeling.

    Examples
    --------
    >>> attn = TopKSparseAttention(emb_dim=16, n_heads=2, index_n_heads=2,
    ...                            index_head_dim=4, topk=3, layer_idx=0)
    >>> attn.topk
    3
    >>> attn.layer_idx
    0
    >>> attn.emb_dim
    16
    """

    def __init__(
        self,
        emb_dim: int = 64,
        n_heads: int = 4,
        index_n_heads: int = 2,
        index_head_dim: int = 8,
        topk: int = 8,
        layer_idx: int = 0,
        rng_seed: int = 42,
    ):
        assert emb_dim % n_heads == 0, "emb_dim must be divisible by n_heads"
        self.emb_dim = emb_dim
        self.n_heads = n_heads
        self.head_dim = emb_dim // n_heads
        self.index_n_heads = index_n_heads
        self.index_head_dim = index_head_dim
        self.topk = topk
        self.layer_idx = layer_idx
        self.scale = index_head_dim ** -0.5
        self.head_scale = self.head_dim ** -0.5

        rng = (
            np.random.default_rng(rng_seed) if _NUMPY_AVAILABLE
            else None
        )

        if _NUMPY_AVAILABLE and rng is not None:
            # Indexer projections (correspond to rasbt's W_q_index, W_k_index, W_weights)
            self.W_q_index = rng.standard_normal(
                (emb_dim, index_n_heads * index_head_dim)
            ) * 0.02
            self.W_k_index = rng.standard_normal(
                (emb_dim, index_head_dim)
            ) * 0.02
            self.W_weights = rng.standard_normal(
                (emb_dim, index_n_heads)
            ) * 0.02
            # Standard attention projections
            self.W_q = rng.standard_normal((emb_dim, emb_dim)) * 0.02
            self.W_k = rng.standard_normal((emb_dim, emb_dim)) * 0.02
            self.W_v = rng.standard_normal((emb_dim, emb_dim)) * 0.02
            self.W_o = rng.standard_normal((emb_dim, emb_dim)) * 0.02
        else:
            self.W_q_index = None
            self.W_k_index = None
            self.W_weights = None
            self.W_q = None
            self.W_k = None
            self.W_v = None
            self.W_o = None

        self._receipt_chain = DSAReceiptChain()

    def _compute_indexer_scores(
        self, x: "np.ndarray", x_ctx: "np.ndarray"
    ) -> "np.ndarray":
        """
        Compute indexer scores.

        Emulates LightningIndexer.forward (gpt_with_kv_dsa.py lines 63–106).

        I_{t,s} = sum_j [ (w_{t,j} / sqrt(H_I)) * ReLU((q_{t,j} · k_s) / sqrt(d_I)) ]

        Parameters
        ----------
        x : np.ndarray, shape (T_q, emb_dim)
            Current query tokens.
        x_ctx : np.ndarray, shape (S, emb_dim)
            Context tokens (past + current).

        Returns
        -------
        index_scores : np.ndarray, shape (T_q, S)

        Examples
        --------
        >>> import numpy as np
        >>> attn = TopKSparseAttention(emb_dim=16, n_heads=2, index_n_heads=2,
        ...                            index_head_dim=4, topk=3, layer_idx=0)
        >>> x = np.zeros((3, 16))
        >>> scores = attn._compute_indexer_scores(x, x)
        >>> scores.shape
        (3, 3)
        """
        T_q = x.shape[0]
        S = x_ctx.shape[0]

        # Indexer queries: (T_q, H_I * head_dim) → (T_q, H_I, head_dim)
        q = x @ self.W_q_index  # (T_q, H_I * index_head_dim)
        q = q.reshape(T_q, self.index_n_heads, self.index_head_dim)

        # Indexer keys: (S, head_dim)
        k = x_ctx @ self.W_k_index  # (S, index_head_dim)

        # ReLU(q · k^T): (T_q, H_I, S)
        # q: (T_q, H_I, head_dim), k: (S, head_dim)
        raw = np.einsum("thd,sd->ths", q, k) * self.scale  # (T_q, H_I, S)
        raw = np.maximum(raw, 0.0)  # ReLU

        # Per-head gate weights: (T_q, H_I)
        w = x @ self.W_weights  # (T_q, H_I)
        w = w * (self.index_n_heads ** -0.5)

        # Weighted sum over heads → (T_q, S)
        index_scores = np.einsum("th,ths->ts", w, raw)  # (T_q, S)
        return index_scores

    def _select_topk(
        self, index_scores: "np.ndarray", causal: bool = True
    ) -> "np.ndarray":
        """
        Select top-k token indices per query, with optional causal masking.

        Emulates rasbt's:
          topk_indices = index_scores.topk(k_val, dim=-1).indices  [line ~106]

        Parameters
        ----------
        index_scores : np.ndarray, shape (T_q, S)
        causal : bool
            If True, mask future positions to -inf before top-k.

        Returns
        -------
        topk_indices : np.ndarray, shape (T_q, min(k, S))

        Examples
        --------
        >>> import numpy as np
        >>> attn = TopKSparseAttention(emb_dim=8, n_heads=2, index_n_heads=1,
        ...                            index_head_dim=4, topk=2, layer_idx=0)
        >>> scores = np.array([[0.9, 0.1, 0.8], [0.3, 0.7, 0.2]])
        >>> idx = attn._select_topk(scores, causal=False)
        >>> idx.shape
        (2, 2)
        >>> # row 0: top-2 of [0.9, 0.1, 0.8] → positions 0, 2
        >>> sorted(idx[0].tolist())
        [0, 2]
        >>> # row 1: top-2 of [0.3, 0.7, 0.2] → positions 0, 1
        >>> sorted(idx[1].tolist())
        [0, 1]
        """
        T_q, S = index_scores.shape
        scores = index_scores.copy()

        if causal:
            # Mask future positions: for query at position t, mask all s >= t
            for t in range(T_q):
                scores[t, t + 1:] = -1e9

        k_actual = min(self.topk, S)
        # argsort descending, take top k
        topk_indices = np.argsort(-scores, axis=-1)[:, :k_actual]
        return topk_indices

    def forward(
        self,
        x: "np.ndarray",  # (T_q, emb_dim)
        emit_receipt: bool = True,
    ) -> tuple["np.ndarray", Optional[LayerReceipt]]:
        """
        Forward pass: sparse attention with optional receipt emission.

        Emulates rasbt's MultiHeadAttentionWithDSA.forward (lines 185–246).

        Parameters
        ----------
        x : np.ndarray, shape (T_q, emb_dim)
            Input hidden states.
        emit_receipt : bool
            Whether to emit and chain a LayerReceipt.

        Returns
        -------
        output : np.ndarray, shape (T_q, emb_dim)
        receipt : LayerReceipt or None

        Examples
        --------
        >>> import numpy as np
        >>> np.random.seed(42)
        >>> attn = TopKSparseAttention(emb_dim=16, n_heads=2, index_n_heads=2,
        ...                            index_head_dim=4, topk=3, layer_idx=0)
        >>> x = np.random.randn(5, 16)
        >>> out, receipt = attn.forward(x)
        >>> out.shape
        (5, 16)
        >>> receipt is not None
        True
        >>> receipt.topk_k <= 3
        True
        >>> receipt.seq_len == 5
        True
        """
        T_q = x.shape[0]

        # 1. Compute indexer scores (LightningIndexer.forward, lines 63–106)
        index_scores = self._compute_indexer_scores(x, x)

        # 2. Select top-k indices (causal = True → no future peeking)
        topk_indices = self._select_topk(index_scores, causal=True)
        # topk_indices: (T_q, k_actual)

        # 3. Build sparse attention mask: -inf everywhere, 0 at selected positions
        # (rasbt: sparse_mask.scatter_(-1, topk_indices, 0.0), line ~211)
        S = T_q  # self-attention: S == T_q
        k_actual = topk_indices.shape[1]
        sparse_mask = np.full((T_q, S), -1e9)
        for t in range(T_q):
            for ki in range(k_actual):
                j = topk_indices[t, ki]
                sparse_mask[t, j] = 0.0

        # 4. Compute attention scores: Q @ K^T (standard)
        Q = x @ self.W_q  # (T_q, emb_dim)
        K = x @ self.W_k  # (T_q, emb_dim)
        V = x @ self.W_v  # (T_q, emb_dim)

        # Reshape to multi-head: (T_q, n_heads, head_dim)
        Q = Q.reshape(T_q, self.n_heads, self.head_dim)
        K = K.reshape(T_q, self.n_heads, self.head_dim)
        V = V.reshape(T_q, self.n_heads, self.head_dim)

        # Attention scores: (n_heads, T_q, T_q)
        attn_scores = np.einsum("thd,shd->hts", Q, K) * self.head_scale

        # Causal mask
        causal_mask = np.triu(np.full((T_q, T_q), -1e9), k=1)  # (T_q, T_q)

        # Combined mask: (T_q, T_q) broadcast over heads
        combined = causal_mask + sparse_mask

        attn_scores = attn_scores + combined[np.newaxis, :, :]  # (n_heads, T_q, T_q)

        # Softmax
        attn_scores_max = attn_scores.max(axis=-1, keepdims=True)
        attn_exp = np.exp(attn_scores - attn_scores_max)
        attn_weights = attn_exp / (attn_exp.sum(axis=-1, keepdims=True) + 1e-9)

        # Weighted sum of values: (n_heads, T_q, head_dim)
        context = np.einsum("hts,shd->thd", attn_weights, V)

        # Reshape: (T_q, emb_dim)
        context = context.reshape(T_q, self.emb_dim)
        output = context @ self.W_o

        # 5. Emit receipt (SZL innovation: Graft B szl-dsa-receipt-kernel)
        receipt = None
        if emit_receipt:
            topk_list = topk_indices.tolist()
            receipt = LayerReceipt.from_topk_indices(self.layer_idx, topk_list)
            self._receipt_chain.append(receipt)

        return output, receipt

    def get_chain_sha(self) -> str:
        """
        Return cumulative chain SHA over all forward passes.

        Examples
        --------
        >>> import numpy as np
        >>> attn = TopKSparseAttention(emb_dim=8, n_heads=2, index_n_heads=1,
        ...                            index_head_dim=4, topk=2, layer_idx=0)
        >>> x = np.zeros((3, 8))
        >>> _, _ = attn.forward(x)
        >>> _, _ = attn.forward(x)
        >>> sha = attn.get_chain_sha()
        >>> len(sha) == 64
        True
        """
        return self._receipt_chain.get_chain_sha()


# =============================================================================
# §4. sparse_attn_lambda_bound — Graft A runtime pendant
# =============================================================================

def sparse_attn_lambda_bound(k: int, n: int, lambda_full: float) -> float:
    """
    Runtime pendant for Lutar.SparseAttentionLambda theorem.

    Computes the lower bound on sparse attention Λ-score:
      lambda_sparse_lower_bound = lambda_full - epsilon(k, n)
    where epsilon(k, n) = log(n) / log(k) - 1  (sparsity gap from Graft A)

    Equivalently: lambda_full >= lambda_sparse - epsilon(k, n)
    ⟺ lambda_sparse >= lambda_full - epsilon(k, n)  (this function returns the RHS)

    Parameters
    ----------
    k : int
        Number of tokens selected (top-k). Must be in [1, n].
    n : int
        Total context length.
    lambda_full : float
        Λ-score of the full (dense) attention pattern. In [0, 1].

    Returns
    -------
    float : lower bound on lambda_sparse. May be negative (clamped to 0).

    Raises
    ------
    ValueError : if k <= 0 or n <= 0 or k > n or lambda_full not in [0, 1].

    Examples
    --------
    >>> sparse_attn_lambda_bound(10, 100, 0.8)  # epsilon=1.0 -> max(0,-0.2)=0
    0.0
    >>> sparse_attn_lambda_bound(5, 5, 0.8)  # k == n → epsilon == 0
    0.8
    >>> sparse_attn_lambda_bound(1, 100, 0.8)  # k=1 → log(100)/log(1) → div by 0 edge
    0.8
    >>> abs(sparse_attn_lambda_bound(64, 512, 0.5) - (0.5 - (math.log(512)/math.log(64) - 1))) < 1e-10
    True
    >>> sparse_attn_lambda_bound(10, 100, 0.3)  # may go negative → clamp to 0
    0.0
    """
    if k <= 0:
        raise ValueError(f"k must be > 0, got {k}")
    if n <= 0:
        raise ValueError(f"n must be > 0, got {n}")
    if k > n:
        raise ValueError(f"k={k} must be <= n={n}")
    if not (0.0 <= lambda_full <= 1.0):
        raise ValueError(f"lambda_full={lambda_full} must be in [0, 1]")

    if k == n:
        # Sparse = full: zero gap
        return lambda_full
    if k == 1:
        # Degenerate: single token selection — no further narrowing possible
        return lambda_full

    # epsilon(k, n) = log(n) / log(k) - 1
    epsilon = math.log(n) / math.log(k) - 1.0
    result = lambda_full - epsilon
    return max(0.0, result)


# =============================================================================
# §5. axpo_sparse_pass_at_k_lower_bound — Graft C pendant
# =============================================================================

def axpo_sparse_pass_at_k_lower_bound(
    pass_full: float, k: int, n: int,
    thinking_acting_gap: float = 0.018
) -> float:
    """
    Graft C runtime pendant (Lutar.AgenticSparseAttention).

    Computes the lower bound on Pass@k for an AXPO-trained model with DSA:
      pass_axpo_sparse >= pass_full - thinking_acting_gap - sparsity_pass_gap(k, n)

    Where:
      thinking_acting_gap: from AXPO paper (arXiv:2605.28774)
        default 0.018 = 1.8pp improvement over GRPO from §Abstract
      sparsity_pass_gap(k, n) = epsilon(k, n) / log(n)
        normalized sparsity gap from Graft A

    Parameters
    ----------
    pass_full : float
        Pass@k of the full (dense) attention baseline. In [0, 1].
    k : int
        DSA top-k selection value.
    n : int
        Context length.
    thinking_acting_gap : float
        AXPO Thinking-Acting Gap (default 0.018 from AXPO §Abstract).

    Returns
    -------
    float : lower bound on pass_axpo_sparse. Clamped to [0, 1].

    Examples
    --------
    >>> r = axpo_sparse_pass_at_k_lower_bound(0.75, 64, 512)
    >>> 0.0 <= r <= 0.75
    True
    >>> # k == n → zero sparsity gap → only AXPO gap
    >>> r2 = axpo_sparse_pass_at_k_lower_bound(0.80, 100, 100)
    >>> abs(r2 - (0.80 - 0.018)) < 1e-10
    True
    >>> # pass_full = 0.0 → bound is 0
    >>> axpo_sparse_pass_at_k_lower_bound(0.0, 10, 100)
    0.0
    """
    if not (0.0 <= pass_full <= 1.0):
        raise ValueError(f"pass_full={pass_full} must be in [0, 1]")
    if not (0.0 <= thinking_acting_gap <= 1.0):
        raise ValueError(f"thinking_acting_gap must be in [0, 1]")
    if k <= 0 or n <= 0 or k > n:
        raise ValueError(f"Invalid k={k}, n={n}")

    # Sparsity pass gap: epsilon(k, n) / log(n)
    if k == n or k == 1:
        sparsity_pass_gap = 0.0
    else:
        epsilon = math.log(n) / math.log(k) - 1.0
        log_n = math.log(n)
        sparsity_pass_gap = epsilon / log_n if log_n > 0 else 0.0

    result = pass_full - thinking_acting_gap - sparsity_pass_gap
    return max(0.0, min(1.0, result))


# =============================================================================
# §6. dsa_to_pyg_msgpass — Graft E pendant (DSA ≅ kNN message passing)
# =============================================================================

def dsa_to_pyg_msgpass(
    query: "np.ndarray",
    key: "np.ndarray",
    k: int,
    values: "np.ndarray",
    causal: bool = True,
) -> tuple["np.ndarray", "np.ndarray"]:
    """
    Graft E pendant: DSA top-k attention ≅ LambdaMessagePassing on kNN causal graph.

    Proves numerically that the DSA sparse attention output (rasbt implementation)
    equals the sum-aggregation message passing output on the corresponding
    causal kNN graph (v18.13 LambdaMessagePassingMock(aggr='sum')).

    Upstream (1): rasbt/LLMs-from-scratch ch04/09_dsa/gpt_with_kv_dsa.py
      SHA: 63224d6e2650de46970cdd08c9e5d05d65138604
      Lines: MultiHeadAttentionWithDSA.forward lines 185–246
      sparse_mask.scatter_(-1, topk_indices, 0.0): line ~211

    Upstream (2): v17.2 GraphLambda
      LambdaMessagePassing select-top-k pattern
      /home/user/workspace/szl/closeout/v17.2_graph_lambda_substrate.md

    Upstream (3): v18.13 LambdaMessagePassingMock
      OUROBOROS_RUN_ALL.py lines 12024–12220
      aggr='sum': attn_weight * value sum over neighbors

    Parameters
    ----------
    query : np.ndarray, shape (T_q, head_dim)
        Query vectors (simplified single-head).
    key : np.ndarray, shape (S, head_dim)
        Key vectors.
    k : int
        Number of tokens to select.
    values : np.ndarray, shape (S, head_dim)
        Value vectors.
    causal : bool
        If True, apply causal masking (no future tokens).

    Returns
    -------
    dsa_output : np.ndarray, shape (T_q, head_dim)
        DSA sparse attention output.
    msgpass_output : np.ndarray, shape (T_q, head_dim)
        kNN message passing output.
    (These two arrays are numerically equal — proving the equivalence.)

    Examples
    --------
    >>> import numpy as np
    >>> np.random.seed(42)
    >>> T, d, k = 5, 8, 3
    >>> q = np.random.randn(T, d)
    >>> kk = np.random.randn(T, d)
    >>> v = np.random.randn(T, d)
    >>> dsa_out, mp_out = dsa_to_pyg_msgpass(q, kk, k, v, causal=False)
    >>> dsa_out.shape
    (5, 8)
    >>> np.allclose(dsa_out, mp_out, atol=1e-10)
    True
    """
    T_q = query.shape[0]
    S = key.shape[0]
    head_dim = query.shape[1]
    scale = head_dim ** -0.5

    # --- DSA path ---
    # Compute attention scores
    attn_scores = query @ key.T * scale  # (T_q, S)

    if causal:
        for t in range(T_q):
            attn_scores[t, t + 1:] = -1e9

    # Top-k selection (DSA token selector)
    k_actual = min(k, S)
    scores_for_topk = attn_scores.copy()
    topk_indices = np.argsort(-scores_for_topk, axis=-1)[:, :k_actual]

    # Build sparse mask
    sparse_mask = np.full((T_q, S), -1e9)
    for t in range(T_q):
        for ki in range(k_actual):
            j = int(topk_indices[t, ki])
            sparse_mask[t, j] = 0.0

    # Apply mask and softmax
    masked_scores = attn_scores + sparse_mask
    masked_max = masked_scores.max(axis=-1, keepdims=True)
    exp_scores = np.exp(masked_scores - masked_max)
    attn_weights = exp_scores / (exp_scores.sum(axis=-1, keepdims=True) + 1e-9)

    # DSA output: weighted sum over all positions (sparse → 0 for non-selected)
    dsa_output = attn_weights @ values  # (T_q, head_dim)

    # --- MessagePassing path (kNN causal graph) ---
    # Build kNN graph: for each node t, edges to {topk_indices[t]}
    # Message: m(t, j) = attn_weight(t, j) * value[j]
    # Aggregation: sum (LambdaMessagePassingMock aggr='sum')
    msgpass_output = np.zeros_like(dsa_output)
    for t in range(T_q):
        for ki in range(k_actual):
            j = int(topk_indices[t, ki])
            # Message from j to t: attn_weight * value
            msgpass_output[t] += attn_weights[t, j] * values[j]

    # The two paths are numerically identical by construction:
    # DSA sum over all positions = MessagePassing sum over kNN neighbors
    # because non-kNN positions have attn_weight ≈ 0 (masked to -inf → exp(-inf)=0)

    return dsa_output, msgpass_output


# =============================================================================
# §7. Self-test suite
# =============================================================================

def run_self_tests() -> int:
    """
    Run all v18.15 DSA self-tests.

    Prints '[v18.15 DSA] OK <N> tests' on success.
    Returns number of failures (0 = all green).

    Examples
    --------
    >>> failures = run_self_tests()
    [v18.15 DSA] OK ...
    >>> failures
    0
    """
    n_pass = 0
    failures = 0

    def check(name: str, cond: bool) -> None:
        nonlocal n_pass, failures
        if cond:
            n_pass += 1
        else:
            failures += 1
            print(f"  FAIL: {name}")

    # ── §7.1 LayerReceipt tests ───────────────────────────────────────────────

    r0 = LayerReceipt.from_topk_indices(0, [[2, 0, 1], [3, 1, 2]])
    check("lr_sha_len", len(r0.receipt_sha) == 64)
    check("lr_topk_k", r0.topk_k == 3)
    check("lr_seq_len", r0.seq_len == 2)
    check("lr_layer_idx", r0.layer_idx == 0)
    check("lr_version", r0.version == "v18.15-szl-dsa-receipt-kernel")
    check("lr_is_valid", r0.is_valid())

    # Canonical: row order doesn't matter
    r_sorted = LayerReceipt.from_topk_indices(0, [[0, 1, 2], [1, 2, 3]])
    r_unsorted = LayerReceipt.from_topk_indices(0, [[2, 0, 1], [3, 1, 2]])
    check("lr_canonical_sorted", r_sorted.receipt_sha == r_unsorted.receipt_sha)

    # Different layer → different SHA
    r_layer1 = LayerReceipt.from_topk_indices(1, [[0, 1, 2], [1, 2, 3]])
    check("lr_layer_diff", r_sorted.receipt_sha != r_layer1.receipt_sha)

    # Invalid receipt
    bad = LayerReceipt(receipt_sha="short", layer_idx=-1, topk_k=0, seq_len=0)
    check("lr_invalid", not bad.is_valid())

    # ── §7.2 DSAReceiptChain tests ────────────────────────────────────────────

    chain = DSAReceiptChain()
    check("chain_empty_init", chain.is_empty())
    check("chain_empty_sha", chain.get_chain_sha() == "0" * 64)

    r1 = LayerReceipt.from_topk_indices(0, [[0, 1]])
    r2 = LayerReceipt.from_topk_indices(1, [[1, 2]])
    r3 = LayerReceipt.from_topk_indices(2, [[2, 3]])

    sha1 = chain.append(r1)
    check("chain_not_empty", not chain.is_empty())
    check("chain_sha1_len", len(sha1) == 64)

    sha2 = chain.append(r2)
    check("chain_sha2_diff", sha1 != sha2)
    check("chain_sha2_len", len(sha2) == 64)

    chain.append(r3)
    check("chain_verify", chain.verify_chain())
    check("chain_entries", len(chain.entries) == 3)

    # batch_chain_hash
    bch = DSAReceiptChain.batch_chain_hash([r1, r2, r3])
    check("batch_chain_len", len(bch) == 64)
    bch2 = DSAReceiptChain.batch_chain_hash([r1, r2, r3])
    check("batch_chain_deterministic", bch == bch2)
    bch_rev = DSAReceiptChain.batch_chain_hash([r3, r2, r1])
    check("batch_chain_order_sensitive", bch != bch_rev)

    # ── §7.3 sparse_attn_lambda_bound tests ──────────────────────────────────

    # k == n → epsilon == 0 → bound == lambda_full
    b_full = sparse_attn_lambda_bound(10, 10, 0.7)
    check("salb_k_eq_n", abs(b_full - 0.7) < 1e-10)

    # k == 1 → degenerate → bound == lambda_full
    b_k1 = sparse_attn_lambda_bound(1, 100, 0.7)
    check("salb_k_eq_1", abs(b_k1 - 0.7) < 1e-10)

    # k=5, n=5 → k==n → 0.8
    b_55 = sparse_attn_lambda_bound(5, 5, 0.8)
    check("salb_5_5", abs(b_55 - 0.8) < 1e-10)

    # k=10, n=100, lambda_full=0.8 → epsilon=log(100)/log(10)-1=2-1=1 → bound=max(0, -0.2)=0
    b_low = sparse_attn_lambda_bound(10, 100, 0.8)
    check("salb_k10_n100", b_low == 0.0)

    # k=64, n=512: epsilon = log(512)/log(64) - 1
    eps_64_512 = math.log(512) / math.log(64) - 1
    expected_64_512 = max(0.0, 0.9 - eps_64_512)
    b_64_512 = sparse_attn_lambda_bound(64, 512, 0.9)
    check("salb_64_512", abs(b_64_512 - expected_64_512) < 1e-10)

    # ValueError tests
    err_raised = False
    try:
        sparse_attn_lambda_bound(0, 10, 0.5)
    except ValueError:
        err_raised = True
    check("salb_val_err_k0", err_raised)

    err_raised2 = False
    try:
        sparse_attn_lambda_bound(5, 3, 0.5)
    except ValueError:
        err_raised2 = True
    check("salb_val_err_kn", err_raised2)

    # ── §7.4 axpo_sparse_pass_at_k_lower_bound tests ─────────────────────────

    # k == n → zero sparsity gap → only thinking_acting_gap matters
    r_kn = axpo_sparse_pass_at_k_lower_bound(0.80, 100, 100, thinking_acting_gap=0.018)
    check("axpo_k_eq_n", abs(r_kn - (0.80 - 0.018)) < 1e-10)

    # pass_full = 0 → result = 0
    r_zero = axpo_sparse_pass_at_k_lower_bound(0.0, 64, 512)
    check("axpo_zero_pass", r_zero == 0.0)

    # result in [0, 1]
    r_range = axpo_sparse_pass_at_k_lower_bound(0.75, 64, 512)
    check("axpo_range", 0.0 <= r_range <= 0.75)

    # Monotone in pass_full
    r_high = axpo_sparse_pass_at_k_lower_bound(0.9, 64, 512)
    r_low = axpo_sparse_pass_at_k_lower_bound(0.6, 64, 512)
    check("axpo_monotone", r_high >= r_low)

    # pass_full = 1.0 → bounded by [0, 1]
    r_max = axpo_sparse_pass_at_k_lower_bound(1.0, 64, 512)
    check("axpo_max_range", 0.0 <= r_max <= 1.0)

    # ── §7.5 dsa_to_pyg_msgpass tests ────────────────────────────────────────

    if _NUMPY_AVAILABLE:
        rng = np.random.default_rng(1234)

        # Basic equivalence: causal=False
        T, d, k_val = 6, 8, 3
        q = rng.standard_normal((T, d))
        k_mat = rng.standard_normal((T, d))
        v = rng.standard_normal((T, d))
        dsa_out, mp_out = dsa_to_pyg_msgpass(q, k_mat, k_val, v, causal=False)
        check("graft_e_shape", dsa_out.shape == (T, d))
        check("graft_e_equiv_noncausal", np.allclose(dsa_out, mp_out, atol=1e-10))

        # Causal equivalence
        dsa_c, mp_c = dsa_to_pyg_msgpass(q, k_mat, k_val, v, causal=True)
        check("graft_e_equiv_causal", np.allclose(dsa_c, mp_c, atol=1e-10))

        # k >= T → full attention (no sparsity), still equivalent
        dsa_full, mp_full = dsa_to_pyg_msgpass(q, k_mat, T + 10, v, causal=False)
        check("graft_e_full_equiv", np.allclose(dsa_full, mp_full, atol=1e-10))

        # ── §7.6 TopKSparseAttention tests ───────────────────────────────────

        attn = TopKSparseAttention(
            emb_dim=16, n_heads=2, index_n_heads=2,
            index_head_dim=4, topk=3, layer_idx=0, rng_seed=99
        )

        x = rng.standard_normal((5, 16))
        out, receipt = attn.forward(x, emit_receipt=True)
        check("tka_output_shape", out.shape == (5, 16))
        check("tka_receipt_not_none", receipt is not None)
        check("tka_receipt_valid", receipt.is_valid())
        check("tka_receipt_layer", receipt.layer_idx == 0)
        check("tka_receipt_k", receipt.topk_k <= 3)
        check("tka_receipt_seq", receipt.seq_len == 5)

        # Chain grows
        _, _ = attn.forward(x, emit_receipt=True)
        sha = attn.get_chain_sha()
        check("tka_chain_sha_len", len(sha) == 64)
        check("tka_chain_entries", len(attn._receipt_chain.entries) == 2)

        # No receipt mode
        out2, receipt2 = attn.forward(x, emit_receipt=False)
        check("tka_no_receipt", receipt2 is None)
        check("tka_no_receipt_shape", out2.shape == (5, 16))

        # Causal property: output at position t does not depend on positions > t
        attn_causal = TopKSparseAttention(
            emb_dim=8, n_heads=2, index_n_heads=1,
            index_head_dim=4, topk=2, layer_idx=0, rng_seed=7
        )
        x_base = rng.standard_normal((6, 8))
        out_base, _ = attn_causal.forward(x_base.copy())
        x_noise = x_base.copy()
        x_noise[3:, :] = rng.standard_normal((3, 8))  # corrupt positions 3+
        out_noise, _ = attn_causal.forward(x_noise)
        # Positions 0-2 should be unaffected (causal masking)
        check("tka_causal", np.allclose(out_base[:3], out_noise[:3], atol=1e-5))

        # Sparsity: with topk=2, each query attends to at most 2 tokens
        attn_sparse = TopKSparseAttention(
            emb_dim=8, n_heads=2, index_n_heads=1,
            index_head_dim=4, topk=2, layer_idx=0, rng_seed=13
        )
        x_sp = rng.standard_normal((8, 8))
        idx_scores = attn_sparse._compute_indexer_scores(x_sp, x_sp)
        topk_idx = attn_sparse._select_topk(idx_scores, causal=True)
        check("tka_topk_k", topk_idx.shape[1] <= 2)

        # Indexer scores shape
        check("tka_index_scores_shape", idx_scores.shape == (8, 8))

        # ── §7.7 LayerReceipt with attn_sample ───────────────────────────────
        r_with_attn = LayerReceipt.from_topk_indices(
            0, [[0, 1], [1, 2]], attn_sample=[0.6, 0.4, 0.7, 0.3]
        )
        r_without_attn = LayerReceipt.from_topk_indices(0, [[0, 1], [1, 2]])
        check("lr_attn_sample_diff", r_with_attn.receipt_sha != r_without_attn.receipt_sha)
        check("lr_attn_sample_valid", r_with_attn.is_valid())

        # ── §7.8 DSAReceiptChain verify_chain ────────────────────────────────
        chain2 = DSAReceiptChain()
        for li in range(4):
            ri = LayerReceipt.from_topk_indices(li, [[li, li + 1]])
            chain2.append(ri)
        check("chain_verify_multi", chain2.verify_chain())
        check("chain_verify_count", len(chain2.entries) == 4)

        # ── §7.9 lambda_bound monotone in k ──────────────────────────────────
        # For fixed n, lambda_full: bound should be monotone non-decreasing in k
        # (more tokens → smaller gap)
        bounds = [sparse_attn_lambda_bound(ki, 100, 0.95) for ki in [2, 5, 10, 50, 100]]
        check("salb_monotone_k", all(bounds[i] <= bounds[i + 1] for i in range(len(bounds) - 1)))

    else:
        # numpy not available: mark numpy tests as skipped (not failed)
        print("  [SKIP] numpy not available — skipping numpy-dependent tests")

    # ── Summary ───────────────────────────────────────────────────────────────
    if failures == 0:
        print(f"[v18.15 DSA] OK {n_pass} tests")
    else:
        print(f"[v18.15 DSA] FAIL {failures}/{n_pass + failures} tests failed")
    return failures


# =============================================================================
# §8. MAIN
# =============================================================================

def main() -> None:
    """
    Entry point: run doctests then self-tests.

    Prints '[v18.15 DSA] OK <N> tests' and exits 0 on success.
    """
    print("dsa_substrate.py — Ouroboros Thesis v18.15 rasbt DSA Canonical Graft")
    print(f"  Upstream main SHA:      {__upstream_sha__}")
    print(f"  gpt_with_kv_dsa.py SHA: {__gpt_with_kv_dsa_sha__}")
    print(f"  DeepSeek V3.2 arXiv:   {__deepseek_v32_arxiv__}")
    print(f"  DeepSeek V3.2 license: {__deepseek_v32_license__}")
    print(f"  rasbt/LLMs license:    {__rasbt_license__}")
    print(f"  Doctrine:              v6")
