# Authors: Xianjie Mo, Yang Xiang, Youcheng Pan, Yongshuai Hou, Ping Luo (PCL)
# Venue: Expert Systems with Applications Vol. 250 (2024)
# =============================================================================


class MGCoTStep:
    """Multi-Grained Contextual Transformer reasoning step.

    Pure-Python pendant of MGCoT's multi-grained context aggregation:
    - Word level: per-token context
    - Phrase level: sliding window n-gram aggregation
    - Sentence level: global segment pooling

    Emits a Λ-receipt per reasoning step.

    Source: MGCoT SHA 2b6c501656a6632d13bf378046af43a9e51a9bad
    https://github.com/Cedric-Mo/MGCoT
    DOI: 10.1016/j.eswa.2024.123742

    >>> tokens = ["the", "red", "bird", "has", "wings"]
    >>> step = MGCoTStep(tokens, window_size=2)
    >>> receipt = step.run()
    >>> receipt["granularity_levels"]
    ['word', 'phrase', 'sentence']
    >>> len(receipt["word_contexts"]) == len(tokens)
    True
    >>> len(receipt["phrase_contexts"]) > 0
    True
    >>> receipt["phrase_contexts"][0]
    ('the', 'red')
    >>> receipt["sentence_context"] == tuple(tokens)
    True
    >>> receipt["token_count"] == 5
    True
    >>> receipt["phrase_count"] == 4
    True
    >>> step2 = MGCoTStep(["a", "b"], window_size=2)
    >>> r2 = step2.run()
    >>> r2["phrase_count"] == 1
    True
    """

    SOURCE_SHA = "2b6c501656a6632d13bf378046af43a9e51a9bad"
    SOURCE_URL = "https://github.com/Cedric-Mo/MGCoT"
    PAPER_DOI = "10.1016/j.eswa.2024.123742"

    def __init__(self, tokens: list, window_size: int = 2):
        assert len(tokens) >= 1, "tokens must be non-empty"
        assert window_size >= 1, "window_size must be >= 1"
        self.tokens = list(tokens)
        self.window_size = window_size

    def word_level(self) -> list:
        """Word-level context: each token is its own context unit.

        >>> MGCoTStep(["a", "b", "c"]).word_level()
        ['a', 'b', 'c']
        """
        return list(self.tokens)

    def phrase_level(self) -> list:
        """Phrase-level context: sliding window n-gram tuples.

        >>> MGCoTStep(["a", "b", "c"], window_size=2).phrase_level()
        [('a', 'b'), ('b', 'c')]
        >>> MGCoTStep(["a", "b", "c", "d"], window_size=3).phrase_level()
        [('a', 'b', 'c'), ('b', 'c', 'd')]
        """
        n = len(self.tokens)
        w = self.window_size
        if w > n:
            return [tuple(self.tokens)]
        return [tuple(self.tokens[i:i+w]) for i in range(n - w + 1)]

    def sentence_level(self) -> tuple:
        """Sentence-level context: entire sequence as one unit.

        >>> MGCoTStep(["a", "b"]).sentence_level()
        ('a', 'b')
        """
        return tuple(self.tokens)

    def provenance_hash(self) -> str:
        """SHA-256 hash of token sequence for provenance tracking.

        >>> h = MGCoTStep(["a"]).provenance_hash()
        >>> len(h) == 64
        True
        """
        return hashlib.sha256(str(self.tokens).encode()).hexdigest()

    def run(self) -> dict:
        """Run full multi-grained aggregation and return Λ-receipt.

        >>> r = MGCoTStep(["x"]).run()
        >>> r["graft"]
        'B:MGCoTGraphReasoning'
        >>> "provenance_hash" in r
        True
        """
        wl = self.word_level()
        pl = self.phrase_level()
        sl = self.sentence_level()
        return {
            "graft": "B:MGCoTGraphReasoning",
            "version": "v18.17",
            "granularity_levels": ["word", "phrase", "sentence"],
            "word_contexts": wl,
            "phrase_contexts": pl,
            "sentence_context": sl,
            "token_count": len(self.tokens),
            "phrase_count": len(pl),
            "window_size": self.window_size,
            "provenance_hash": self.provenance_hash(),
            "source_sha": self.SOURCE_SHA,
            "source_url": self.SOURCE_URL,
            "paper_doi": self.PAPER_DOI,
            "paper_url": "https://www.sciencedirect.com/science/article/abs/pii/S0957417424006080",
            "authors": "Xianjie Mo, Yang Xiang, Youcheng Pan, Yongshuai Hou, Ping Luo",
            "venue": "Expert Systems with Applications Vol. 250 (2024)",
        }


class MGCoTReceipt:
    """Composite Λ-receipt for a full MGCoT reasoning pass over multiple steps.

    Source: MGCoT SHA 2b6c501656a6632d13bf378046af43a9e51a9bad
    https://github.com/Cedric-Mo/MGCoT
    DOI: 10.1016/j.eswa.2024.123742

    >>> tokens_list = [["red", "bird"], ["has", "wings"]]
    >>> receipt = MGCoTReceipt(tokens_list, window_size=2).run()
    >>> receipt["step_count"] == 2
    True
    >>> "graft" in receipt
    True
    >>> receipt["graft"]
    'B:MGCoTReceipt'
    >>> receipt["total_tokens"] == 4
    True
    >>> len(receipt["steps"]) == 2
    True
    >>> MGCoTReceipt([["a"]]).run()["step_count"]
    1
    """

    def __init__(self, tokens_list: list, window_size: int = 2):
        assert len(tokens_list) >= 1, "tokens_list must be non-empty"
        self.steps = [MGCoTStep(tl, window_size) for tl in tokens_list]

    def run(self) -> dict:
        """Run all steps and assemble composite receipt.

        >>> r = MGCoTReceipt([["a", "b"], ["c", "d", "e"]]).run()
        >>> r["total_tokens"] == 5
        True
        """
        step_receipts = [s.run() for s in self.steps]
        return {
            "graft": "B:MGCoTReceipt",
            "version": "v18.17",
            "step_count": len(self.steps),
            "steps": step_receipts,
            "total_tokens": sum(r["token_count"] for r in step_receipts),
            "total_phrases": sum(r["phrase_count"] for r in step_receipts),
            "source_sha": MGCoTStep.SOURCE_SHA,
            "paper_doi": MGCoTStep.PAPER_DOI,
        }


