# Lutar.LifelongEditLambda
#
# Source: ReFEdit repo SHA f1bfc6a8a08a45ab7bb87255d2a19ed30bb10ad3
# URL: https://github.com/Cedric-Mo/ReFEdit
# Paper: ReFEdit: Rehearsal-Free Lifelong Knowledge Editing for LLMs (Xianjie Mo)
# Codebase on MEMIT: https://github.com/kmeng01/memit
# Theorem: refedit_lambda_drift_bound
#   drift(N) ≤ √N · delta_per_edit
# Cross-ref: v15 DPO (szl/closeout/v15_dpo_feasibility_innovate.md)
# =============================================================================


class LifelongEditDriftBound:
    """Lutar.LifelongEditLambda — Λ-score drift bound for rehearsal-free edits.

    Theorem refedit_lambda_drift_bound:
    After N sequential rehearsal-free knowledge edits with per-edit orthogonality
    residual delta_per_edit, the total Λ-score degradation satisfies:
        drift(N) ≤ √N · delta_per_edit

    This follows from Cauchy-Schwarz inequality applied to the sequence of
    per-edit residuals {δ_i}: Σ δ_i ≤ √N · ‖δ‖_2 ≤ √N · √N · δ_max
    (practical bound uses the sub-Gaussian regime).

    Source: ReFEdit SHA f1bfc6a8a08a45ab7bb87255d2a19ed30bb10ad3
    https://github.com/Cedric-Mo/ReFEdit
    MEMIT base: https://github.com/kmeng01/memit
    Cross-ref: szl/closeout/v15_dpo_feasibility_innovate.md

    >>> bound = LifelongEditDriftBound(n_edits=100, delta_per_edit=0.01)
    >>> drift = bound.worst_case_drift()
    >>> abs(drift - 0.1) < 1e-6
    True
    >>> bound.lambda_floor(baseline=1.0) >= 0.9
    True
    >>> bound2 = LifelongEditDriftBound(n_edits=0, delta_per_edit=0.05)
    >>> bound2.worst_case_drift() == 0.0
    True
    >>> bound3 = LifelongEditDriftBound(n_edits=4, delta_per_edit=0.05)
    >>> abs(bound3.worst_case_drift() - 0.1) < 1e-9
    True
    >>> bound3.lambda_floor(1.0) >= 0.0
    True
    """

    SOURCE_SHA = "f1bfc6a8a08a45ab7bb87255d2a19ed30bb10ad3"
    SOURCE_URL = "https://github.com/Cedric-Mo/ReFEdit"
    MEMIT_URL = "https://github.com/kmeng01/memit"

    def __init__(self, n_edits: int, delta_per_edit: float):
        assert n_edits >= 0, "n_edits must be non-negative"
        assert delta_per_edit >= 0.0, "delta_per_edit must be non-negative"
        self.N = n_edits
        self.delta = delta_per_edit

    def worst_case_drift(self) -> float:
        """Upper bound on total Λ-drift: √N · delta_per_edit.

        >>> LifelongEditDriftBound(9, 1.0).worst_case_drift()
        3.0
        >>> LifelongEditDriftBound(1, 0.5).worst_case_drift()
        0.5
        """
        return math.sqrt(self.N) * self.delta

    def lambda_floor(self, baseline: float) -> float:
        """Lower bound on Λ-score after N edits.

        lambda_floor = baseline - worst_case_drift

        >>> LifelongEditDriftBound(4, 0.5).lambda_floor(2.0)
        1.0
        >>> LifelongEditDriftBound(1, 0.1).lambda_floor(1.0)
        0.9
        """
        return baseline - self.worst_case_drift()

    def per_edit_budget(self, total_budget: float) -> float:
        """Max per-edit residual given a total drift budget.

        Inverts worst_case_drift: delta = total_budget / √N.

        >>> b = LifelongEditDriftBound(4, 0.0)
        >>> b.per_edit_budget(0.2)
        0.1
        >>> b2 = LifelongEditDriftBound(100, 0.0)
        >>> abs(b2.per_edit_budget(1.0) - 0.1) < 1e-9
        True
        """
        if self.N == 0:
            return float('inf')
        return total_budget / math.sqrt(self.N)

    def n_edits_for_budget(self, budget: float) -> float:
        """Max edits before drift budget is exhausted.

        N_max = (budget / delta)^2

        >>> b = LifelongEditDriftBound(1, 0.1)
        >>> b.n_edits_for_budget(1.0)
        100.0
        """
        if self.delta == 0.0:
            return float('inf')
        return (budget / self.delta) ** 2

    def simulate_edits(self, residuals: list, baseline: float) -> list:
        """Simulate sequential edits and track Λ-score over time.

        Returns list of Λ-scores after each edit.

        >>> b = LifelongEditDriftBound(3, 0.1)
        >>> scores = b.simulate_edits([0.05, 0.03, 0.08], baseline=1.0)
        >>> len(scores) == 3
        True
        >>> scores[0] == 0.95
        True
        >>> abs(scores[1] - 0.92) < 1e-9
        True
        """
        scores = []
        current = baseline
        for r in residuals:
            current -= r
            scores.append(current)
        return scores

    def emit_receipt(self, baseline: float) -> dict:
        """Emit Λ-receipt for this drift bound configuration.

        >>> b = LifelongEditDriftBound(16, 0.025)
        >>> r = b.emit_receipt(1.0)
        >>> r["graft"]
        'C:LifelongEditLambda'
        >>> r["theorem"]
        'refedit_lambda_drift_bound'
        >>> r["source_sha"]
        'f1bfc6a8a08a45ab7bb87255d2a19ed30bb10ad3'
        """
        return {
            "graft": "C:LifelongEditLambda",
            "version": "v18.17",
            "n_edits": self.N,
            "delta_per_edit": self.delta,
            "worst_case_drift": self.worst_case_drift(),
            "lambda_floor": self.lambda_floor(baseline),
            "theorem": "refedit_lambda_drift_bound",
            "bound": "drift(N) <= sqrt(N) * delta_per_edit",
            "source_sha": self.SOURCE_SHA,
            "source_url": self.SOURCE_URL,
            "memit_base": self.MEMIT_URL,
            "cross_ref_v15_dpo": "szl/closeout/v15_dpo_feasibility_innovate.md",
            "paper": "ReFEdit: Rehearsal-Free Lifelong Knowledge Editing for LLMs",
            "paper_author": "Xianjie Mo (PCL)",
        }


