# GRAFT D — FGVCReceiptClassifier
# szl-fgvc-receipt-classifier
#
# Source: LS-for-FGVC SHA 07f4531d2ff2e5b479f8034eb4248a6888b98d27
# URL: https://github.com/Cedric-Mo/LS-for-FGVC
# Cross-ref: Pavlo Molchanov RADIO (v18.2/Hook B)
#   https://github.com/NVlabs/RADIO
#   szl/closeout/dev_pavlo_molchanov.md
# =============================================================================


def _softmax(scores: list) -> list:
    """Pure-Python softmax (no numpy/torch).

    >>> s = _softmax([1.0, 2.0, 3.0])
    >>> abs(sum(s) - 1.0) < 1e-9
    True
    >>> s[2] > s[1] > s[0]
    True
    >>> _softmax([0.0]) == [1.0]
    True
    """
    max_s = max(scores)
    exps = [math.exp(x - max_s) for x in scores]
    total = sum(exps)
    return [e / total for e in exps]


class FGVCReceiptClassifier:
    """Fine-grained visual classifier with per-inference Λ-receipts.

    Mock FGVC classifier integrating:
    1. Graft A (LabelSmoothCalibration) for ECE bounds
    2. OSME-style multi-part attention (mocked)
    3. Per-inference Λ-receipts with provenance

    Cross-ref: Pavlo Molchanov RADIO — universal visual foundation model
    for FGVC feature extraction (https://github.com/NVlabs/RADIO).

    Source: LS-for-FGVC SHA 07f4531d2ff2e5b479f8034eb4248a6888b98d27
    https://github.com/Cedric-Mo/LS-for-FGVC

    >>> clf = FGVCReceiptClassifier(num_classes=200, epsilon=0.1, nparts=2)
    >>> scores = [0.1] * 199 + [0.9]
    >>> receipt = clf.classify(image_id="img001", scores=scores)
    >>> receipt["predicted_class"] == 199
    True
    >>> 0.0 <= receipt["confidence"] <= 1.0
    True
    >>> "ece_bound" in receipt
    True
    >>> receipt["graft"]
    'D:FGVCReceiptClassifier'
    >>> receipt["nparts"] == 2
    True
    >>> clf2 = FGVCReceiptClassifier(5, 0.0, 1)
    >>> r2 = clf2.classify("x", [10.0, 0.0, 0.0, 0.0, 0.0])
    >>> r2["predicted_class"] == 0
    True
    """

    SOURCE_SHA = "07f4531d2ff2e5b479f8034eb4248a6888b98d27"
    SOURCE_URL = "https://github.com/Cedric-Mo/LS-for-FGVC"
    RADIO_URL = "https://github.com/NVlabs/RADIO"

    def __init__(self, num_classes: int, epsilon: float = 0.1, nparts: int = 2):
        assert num_classes >= 2
        assert 0.0 <= epsilon <= 1.0
        assert nparts >= 1
        self.K = num_classes
        self.epsilon = epsilon
        self.nparts = nparts
        self.calibrator = LabelSmoothCalibration(epsilon, num_classes)

    def classify(self, image_id: str, scores: list) -> dict:
        """Classify image and emit Λ-receipt.

        Args:
            image_id: identifier for the image
            scores: raw logit scores for each class (length = num_classes)

        Returns:
            Λ-receipt dict with prediction, confidence, ECE bound

        >>> clf = FGVCReceiptClassifier(3, 0.1, 2)
        >>> r = clf.classify("test", [1.0, 5.0, 2.0])
        >>> r["predicted_class"] == 1
        True
        >>> r["confidence"] > 0.5
        True
        """
        assert len(scores) == self.K, f"Expected {self.K} scores, got {len(scores)}"
        probs = _softmax(scores)
        pred_class = probs.index(max(probs))
        confidence = probs[pred_class]
        # Approximate ECE_vanilla from confidence-accuracy gap proxy
        ece_vanilla_approx = max(0.0, confidence - 0.9) * 0.2
        img_hash = hashlib.sha256(image_id.encode()).hexdigest()[:8]
        return {
            "graft": "D:FGVCReceiptClassifier",
            "version": "v18.17",
            "image_id": image_id,
            "image_hash": img_hash,
            "predicted_class": pred_class,
            "confidence": confidence,
            "num_classes": self.K,
            "epsilon": self.epsilon,
            "nparts": self.nparts,
            "lambda_noise": self.calibrator.lambda_noise(),
            "ece_bound": self.calibrator.calibration_bound(ece_vanilla_approx),
            "source_sha": self.SOURCE_SHA,
            "source_url": self.SOURCE_URL,
            "radio_ref": self.RADIO_URL,
            "radio_scout": "szl/closeout/dev_pavlo_molchanov.md",
        }

    def batch_classify(self, images: list) -> list:
        """Classify a batch of (image_id, scores) pairs.

        >>> clf = FGVCReceiptClassifier(3, 0.1, 1)
        >>> batch = [("a", [1.0, 5.0, 2.0]), ("b", [5.0, 1.0, 2.0])]
        >>> results = clf.batch_classify(batch)
        >>> len(results) == 2
        True
        >>> results[0]["predicted_class"] == 1
        True
        >>> results[1]["predicted_class"] == 0
        True
        """
        return [self.classify(img_id, scores) for img_id, scores in images]


