# GRAFT E — MGCoTPyGBridge
# szl-mgcot-pyg-bridge (optional bridge graft)
#
# Source: MGCoT SHA 2b6c501656a6632d13bf378046af43a9e51a9bad
# URL: https://github.com/Cedric-Mo/MGCoT
# DOI: 10.1016/j.eswa.2024.123742
# Cross-ref: v18.13 PyG LambdaMessagePassing
#   szl/closeout/szl_pyg_graft_design.md
#   https://github.com/pyg-team/pytorch_geometric
# =============================================================================


class MGCoTPyGBridge:
    """Bridge graft: MGCoT multi-grained reasoning → PyG heterogeneous graph.

    Maps MGCoT's three granularity levels (word, phrase, sentence) to a
    pure-Python representation of a heterogeneous graph with:
    - Node types: word, phrase, sentence
    - Edge types: word→phrase, phrase→sentence, sentence→word (feedback)

    This bridges v18.17 Cedric-Mo MGCoT with v18.13 PyG LambdaMessagePassing.

    Source: MGCoT SHA 2b6c501656a6632d13bf378046af43a9e51a9bad
    https://github.com/Cedric-Mo/MGCoT
    DOI: 10.1016/j.eswa.2024.123742
    PyG: https://github.com/pyg-team/pytorch_geometric
    PyG scout: szl/closeout/szl_pyg_graft_design.md

    >>> bridge = MGCoTPyGBridge(["tok1", "tok2", "tok3", "tok4"], window=2)
    >>> graph = bridge.build_hetero_graph()
    >>> set(graph["node_types"]) == {"word", "phrase", "sentence"}
    True
    >>> len(graph["word_nodes"]) == 4
    True
    >>> len(graph["phrase_nodes"]) == 3
    True
    >>> len(graph["sentence_nodes"]) == 1
    True
    >>> len(graph["word_to_phrase_edges"]) > 0
    True
    >>> graph["graft"]
    'E:MGCoTPyGBridge'
    """

    SOURCE_SHA = "2b6c501656a6632d13bf378046af43a9e51a9bad"
    SOURCE_URL = "https://github.com/Cedric-Mo/MGCoT"
    PAPER_DOI = "10.1016/j.eswa.2024.123742"
    PYG_URL = "https://github.com/pyg-team/pytorch_geometric"

    def __init__(self, tokens: list, window: int = 2):
        assert len(tokens) >= 1
        assert window >= 1
        self.tokens = list(tokens)
        self.window = window

    def build_hetero_graph(self) -> dict:
        """Build heterogeneous graph from token sequence.

        >>> b = MGCoTPyGBridge(["a", "b", "c"], window=2)
        >>> g = b.build_hetero_graph()
        >>> len(g["word_nodes"]) == 3
        True
        >>> len(g["phrase_nodes"]) == 2
        True
        >>> len(g["sentence_nodes"]) == 1
        True
        >>> ("word->phrase", "phrase->sentence", "sentence->word") == tuple(g["edge_types"])
        True
        """
        n = len(self.tokens)
        w = self.window
        word_nodes = list(range(n))
        phrase_count = max(1, n - w + 1) if w <= n else 1
        phrase_nodes = list(range(phrase_count))
        sentence_nodes = [0]

        # word -> phrase: word i participates in phrase p if i in [p, p+w)
        wp_edges = []
        for p in range(len(phrase_nodes)):
            for i in range(p, min(p + w, n)):
                wp_edges.append((i, p))

        # phrase -> sentence: all phrases connect to global sentence node
        ps_edges = [(p, 0) for p in range(len(phrase_nodes))]

        # sentence -> word: top-down feedback
        sw_edges = [(0, i) for i in range(n)]

        return {
            "graft": "E:MGCoTPyGBridge",
            "version": "v18.17",
            "node_types": ["word", "phrase", "sentence"],
            "word_nodes": word_nodes,
            "phrase_nodes": phrase_nodes,
            "sentence_nodes": sentence_nodes,
            "edge_types": ("word->phrase", "phrase->sentence", "sentence->word"),
            "word_to_phrase_edges": wp_edges,
            "phrase_to_sentence_edges": ps_edges,
            "sentence_to_word_edges": sw_edges,
            "tokens": self.tokens,
            "window": self.window,
            "source_sha": self.SOURCE_SHA,
            "mgcot_doi": self.PAPER_DOI,
            "pyg_ref": self.PYG_URL,
            "pyg_scout": "szl/closeout/szl_pyg_graft_design.md",
        }

    def lambda_message_pass(self, word_feats: list) -> dict:
        """Mock one round of Λ-message passing on the hetero graph.

        Word features propagate to phrase nodes (average aggregation),
        then phrase features propagate to sentence node (average),
        then sentence broadcasts back to words.

        Returns updated features and a Λ-receipt.

        >>> bridge = MGCoTPyGBridge(["a", "b", "c", "d"], window=2)
        >>> feats = [1.0, 2.0, 3.0, 4.0]
        >>> result = bridge.lambda_message_pass(feats)
        >>> "phrase_feats" in result
        True
        >>> "sentence_feat" in result
        True
        >>> "receipt" in result
        True
        >>> result["receipt"]["graft"]
        'E:MGCoTPyGBridge'
        """
        graph = self.build_hetero_graph()
        n_words = len(graph["word_nodes"])
        n_phrases = len(graph["phrase_nodes"])
        assert len(word_feats) == n_words, f"Expected {n_words} word feats"

        # Aggregate word→phrase
        phrase_accum = [0.0] * n_phrases
        phrase_count = [0] * n_phrases
        for (wi, pi) in graph["word_to_phrase_edges"]:
            phrase_accum[pi] += word_feats[wi]
            phrase_count[pi] += 1
        phrase_feats = [
            phrase_accum[p] / phrase_count[p] if phrase_count[p] > 0 else 0.0
            for p in range(n_phrases)
        ]

        # Aggregate phrase→sentence
        sentence_feat = sum(phrase_feats) / len(phrase_feats) if phrase_feats else 0.0

        # Broadcast sentence→word (add global context)
        updated_word_feats = [wf + 0.1 * sentence_feat for wf in word_feats]

        receipt = {
            "graft": "E:MGCoTPyGBridge",
            "version": "v18.17",
            "n_words": n_words,
            "n_phrases": n_phrases,
            "source_sha": self.SOURCE_SHA,
            "pyg_ref": self.PYG_URL,
        }
        return {
            "phrase_feats": phrase_feats,
            "sentence_feat": sentence_feat,
            "updated_word_feats": updated_word_feats,
            "receipt": receipt,
        }


