def _test_graft_a() -> None:
    """Tests for Graft A: LabelSmoothCalibration."""
    # Basic construction
    lsc = LabelSmoothCalibration(epsilon=0.1, num_classes=5)
    _assert(lsc.epsilon == 0.1, "A1: epsilon")
    _assert(lsc.K == 5, "A2: num_classes")

    # smooth_distribution sums to 1
    dist = lsc.smooth_distribution(2)
    _assert(abs(sum(dist) - 1.0) < 1e-9, "A3: sum(dist)==1")
    _assert(dist[2] > dist[0], "A4: true class has higher mass")
    _assert(abs(dist[0] - 0.02) < 1e-9, "A5: wrong class mass = eps/K = 0.02")
    _assert(abs(dist[2] - 0.92) < 1e-9, "A6: true class mass = 0.9 + 0.02 = 0.92")

    # lambda_noise
    _assert(abs(lsc.lambda_noise() - 0.08) < 1e-9, "A7: lambda_noise = 0.1*4/5 = 0.08")

    # calibration_bound
    _assert(abs(lsc.calibration_bound(0.05) - 0.13) < 1e-9, "A8: bound = 0.05 + 0.08 = 0.13")

    # Zero smoothing
    lsc0 = LabelSmoothCalibration(0.0, 10)
    _assert(abs(lsc0.lambda_noise()) < 1e-9, "A9: zero epsilon → zero noise")
    dist0 = lsc0.smooth_distribution(3)
    _assert(abs(dist0[3] - 1.0) < 1e-9, "A10: zero eps → one-hot")

    # Full smoothing
    lsc1 = LabelSmoothCalibration(1.0, 4)
    dist1 = lsc1.smooth_distribution(1)
    _assert(abs(sum(dist1) - 1.0) < 1e-9, "A11: full smooth sums to 1")
    _assert(all(abs(x - 0.25) < 1e-9 for x in dist1), "A12: full smooth → uniform")

    # ECE computation
    confs = [0.9, 0.8, 0.7, 0.6, 0.5]
    corr = [True, True, False, True, False]
    ece = lsc.compute_ece(confs, corr)
    _assert(0.0 <= ece <= 1.0, "A13: ECE in [0,1]")

    # Receipt
    r = lsc.emit_receipt(2, 0.05)
    _assert(r["graft"] == "A:LabelSmoothLambda", "A14: graft tag")
    _assert(r["version"] == "v18.17", "A15: version")
    _assert(r["source_sha"] == "07f4531d2ff2e5b479f8034eb4248a6888b98d27", "A16: sha")
    _assert("source_url" in r, "A17: source_url present")
    _assert(r["theorem"] == "label_smooth_lambda_calibration_bound", "A18: theorem name")

    # Monotonicity: larger epsilon → larger lambda_noise
    lsc_a = LabelSmoothCalibration(0.1, 10)
    lsc_b = LabelSmoothCalibration(0.2, 10)
    _assert(lsc_b.lambda_noise() > lsc_a.lambda_noise(), "A19: larger eps → larger noise")

    # Symmetry: wrong classes all get same mass
    lsc_sym = LabelSmoothCalibration(0.3, 6)
    d = lsc_sym.smooth_distribution(0)
    wrong_masses = [d[i] for i in range(1, 6)]
    _assert(all(abs(m - wrong_masses[0]) < 1e-9 for m in wrong_masses), "A20: uniform wrong class mass")


def _test_graft_b() -> None:
    """Tests for Graft B: MGCoTStep + MGCoTReceipt."""
