def run_integration_tests() -> int:
    """Run integration tests across graft components.

    Tests cross-graft interactions.
    Returns 0 if all pass, 1 if any fail.
    """
    global _PASS_COUNT, _FAIL_COUNT
    local_pass = 0
    local_fail = 0

    def check(cond: bool, msg: str) -> None:
        nonlocal local_pass, local_fail
        global _PASS_COUNT, _FAIL_COUNT
        if cond:
            local_pass += 1
            _PASS_COUNT += 1
        else:
            local_fail += 1
            _FAIL_COUNT += 1
            print(f"  INTEGRATION FAIL: {msg}")

    print("[v18.17 Cedric-Mo] Running integration tests...")

    # A + D: LabelSmoothCalibration embedded in FGVCReceiptClassifier
    clf = FGVCReceiptClassifier(10, epsilon=0.2, nparts=3)
    scores = [1.0] * 9 + [5.0]
    r = clf.classify("integrate_test", scores)
    check("lambda_noise" in r, "INT1: lambda_noise from A in D receipt")
    check("ece_bound" in r, "INT2: ece_bound from A in D receipt")
    check(r["lambda_noise"] > 0.0, "INT3: positive lambda_noise")

    # B + E: MGCoT tokens fed to PyG bridge
    tokens = ["the", "red", "bird", "has", "wings"]
    step = MGCoTStep(tokens, window_size=2)
    sr = step.run()
    bridge = MGCoTPyGBridge(tokens, window=2)
    graph = bridge.build_hetero_graph()
    check(
        len(graph["word_nodes"]) == len(sr["word_contexts"]),
        "INT4: word nodes in PyG = word contexts in MGCoT"
    )
    check(
        len(graph["phrase_nodes"]) == sr["phrase_count"],
        "INT5: phrase nodes in PyG = phrase count in MGCoT"
    )

    # C: drift bound with realistic parameters
    n_edits = 1000
    delta = 0.001
    b = LifelongEditDriftBound(n_edits, delta)
    drift = b.worst_case_drift()
    check(drift < 0.1, "INT6: 1000 edits with delta=0.001 → drift < 0.1")
    check(b.lambda_floor(1.0) > 0.9, "INT7: floor > 0.9 for realistic params")

    # A + C: calibration bound grows with smoothing; drift grows with edits
    lsc = LabelSmoothCalibration(0.15, 100)
    check(lsc.lambda_noise() > 0.1, "INT8: eps=0.15, K=100 → noise > 0.1")
    b2 = LifelongEditDriftBound(10000, 0.001)
    check(b2.worst_case_drift() == 0.1, "INT9: sqrt(10000)*0.001 = 0.1")

    # Full pipeline: tokens → MGCoT receipt → PyG bridge → message pass
    toks = ["table", "header", "row", "cell"]
    cot = MGCoTReceipt([toks[:2], toks[2:]], window_size=2).run()
    br = MGCoTPyGBridge(toks, window=2)
    mp = br.lambda_message_pass([1.0, 2.0, 3.0, 4.0])
    check(cot["step_count"] == 2, "INT10: 2 MGCoT steps")
    check(len(mp["phrase_feats"]) == 3, "INT11: 3 phrase feats for 4 tokens, w=2")
    check(mp["sentence_feat"] > 0.0, "INT12: positive sentence feature")

    if local_fail == 0:
        print(f"[v18.17 Cedric-Mo] Integration: OK {local_pass} tests")
        return 0
    else:
        print(f"[v18.17 Cedric-Mo] Integration: FAIL {local_fail}/{local_pass+local_fail}")
        return 1


