def compute_lambda_score(vector: List[float]) -> float:
    """Geometric mean of a 9-element Λ-vector.

    Formula: Λ(x₁,...,x₉) = ∏ xᵢ^(1/9), equivalent to geometric mean.
    Source: Ouroboros Thesis v18, https://doi.org/10.5281/zenodo.20431181

    >>> abs(compute_lambda_score([1.0] * 9) - 1.0) < 1e-9
    True
    >>> compute_lambda_score([0.0] + [1.0] * 8) == 0.0
    True
    >>> abs(compute_lambda_score([0.5] * 9) - 0.5) < 1e-9
    True
    >>> compute_lambda_score([0.9, 0.95, 0.85, 0.9, 0.9, 0.99, 0.99, 0.97, 0.95]) > 0.9
    True
    """
    assert len(vector) == 9, f"Λ-vector must have 9 axes, got {len(vector)}"
    product = 1.0
    for x in vector:
        product *= max(0.0, min(1.0, x))
    return product ** (1.0 / 9.0)


@dataclass
class LambdaAxisSpec:
    """9-axis Λ specification parsed from .mdc frontmatter.

    >>> spec = LambdaAxisSpec.from_dict({
    ...     'moralGrounding': 0.98,
    ...     'measurabilityHonesty': 0.97,
    ...     'reversibility': 0.85,
    ...     'scopeBoundedness': 0.95,
    ...     'convergenceSignal': 0.90,
    ...     'auditTrailIntegrity': 0.99,
    ...     'doctrineCompliance': 0.99,
    ...     'stakeholderTransparency': 0.97,
    ...     'informationBoundedness': 0.95,
    ... })
    >>> len(spec.as_vector()) == 9
    True
    >>> spec.moralGrounding == 0.98
    True
    """
    moralGrounding: float = 0.95
    measurabilityHonesty: float = 0.95
    reversibility: float = 1.0
    scopeBoundedness: float = 0.95
    convergenceSignal: float = 0.90
    auditTrailIntegrity: float = 0.95
    doctrineCompliance: float = 0.95
    stakeholderTransparency: float = 0.95
    informationBoundedness: float = 0.95

    def as_vector(self) -> List[float]:
        """Return 9-element list in canonical axis order.

        >>> spec = LambdaAxisSpec()
        >>> len(spec.as_vector()) == 9
        True
        """
        return [
            self.moralGrounding,
            self.measurabilityHonesty,
            self.reversibility,
            self.scopeBoundedness,
            self.convergenceSignal,
            self.auditTrailIntegrity,
            self.doctrineCompliance,
            self.stakeholderTransparency,
            self.informationBoundedness,
        ]

    def validate(self) -> Tuple[bool, str]:
        """Validate floors and range. Returns (ok, message).

        >>> LambdaAxisSpec().validate()[0]
        True
        >>> bad = LambdaAxisSpec(moralGrounding=0.80)
        >>> bad.validate()[0]
        False
        >>> 'moralGrounding' in bad.validate()[1]
        True
        """
        v = self.as_vector()
        if self.moralGrounding < LAMBDA_FLOOR_MORAL:
            return False, f"moralGrounding {self.moralGrounding} < floor {LAMBDA_FLOOR_MORAL}"
        if self.measurabilityHonesty < LAMBDA_FLOOR_MORAL:
            return False, f"measurabilityHonesty {self.measurabilityHonesty} < floor {LAMBDA_FLOOR_MORAL}"
        for label, val in zip(LAMBDA_AXIS_LABELS, v):
            if not (0.0 <= val <= 1.0):
                return False, f"{label} {val} not in [0, 1]"
        score = compute_lambda_score(v)
        if score < LAMBDA_FLOOR_GENERAL:
            return False, f"Λ-score {score:.4f} < threshold {LAMBDA_FLOOR_GENERAL}"
        return True, "OK"

    @classmethod
    def from_dict(cls, d: Dict[str, float]) -> "LambdaAxisSpec":
        """Parse from YAML-like dict.

        >>> d = {k: 0.96 for k in [
        ...     'moralGrounding', 'measurabilityHonesty', 'reversibility',
        ...     'scopeBoundedness', 'convergenceSignal', 'auditTrailIntegrity',
        ...     'doctrineCompliance', 'stakeholderTransparency', 'informationBoundedness'
        ... ]}
        >>> spec = LambdaAxisSpec.from_dict(d)
        >>> spec.reversibility == 0.96
        True
        """
        return cls(
            moralGrounding=d.get("moralGrounding", 0.95),
            measurabilityHonesty=d.get("measurabilityHonesty", 0.95),
            reversibility=d.get("reversibility", 1.0),
            scopeBoundedness=d.get("scopeBoundedness", 0.95),
            convergenceSignal=d.get("convergenceSignal", 0.90),
            auditTrailIntegrity=d.get("auditTrailIntegrity", 0.95),
            doctrineCompliance=d.get("doctrineCompliance", 0.95),
            stakeholderTransparency=d.get("stakeholderTransparency", 0.95),
            informationBoundedness=d.get("informationBoundedness", 0.95),
        )


@dataclass
class CursorRule:
    """Parsed .mdc Cursor Rule with optional lambda_axis: frontmatter.

    Represents a Cursor Rule file (.cursor/rules/*.mdc).
    Standard frontmatter fields: description, globs, alwaysApply.
    SZL extension: lambda_axis, lambda_threshold, emit_receipt, receipt_chain.

    Attribution:
    - .mdc format: Cursor (https://forum.cursor.com/t/my-take-on-cursor-rules/67535)
    - lambda_axis extension: SZL Holdings (NEW — v18.18)
    - CursorBench: https://cursor.com/blog/cursorbench

    >>> _mdc = chr(10).join(["---", 'description: "Test rule"', 'globs: ["**/*.py"]', "alwaysApply: false", "lambda_axis:", "  moralGrounding: 0.98", "  measurabilityHonesty: 0.97", "  reversibility: 0.85", "  scopeBoundedness: 0.95", "  convergenceSignal: 0.90", "  auditTrailIntegrity: 0.99", "  doctrineCompliance: 0.99", "  stakeholderTransparency: 0.97", "  informationBoundedness: 0.95", "lambda_threshold: 0.90", "emit_receipt: true", "---", "Never force-push to main."])
    >>> rule = CursorRule.parse(_mdc)
    >>> rule.description == "Test rule"
    True
    >>> rule.lambda_axis is not None
    True
    >>> rule.body.strip() == "Never force-push to main."
    True
    >>> rule.validate()[0]
    True
    """

    # Standard Cursor fields
    description: str = ""
    globs: List[str] = field(default_factory=list)
    always_apply: bool = False
    body: str = ""

    # SZL extension fields
    lambda_axis: Optional[LambdaAxisSpec] = None
    lambda_threshold: float = 0.90
    emit_receipt: bool = False
    receipt_chain: str = ""

    def validate(self) -> Tuple[bool, str]:
        """Validate the rule. If lambda_axis present, validate it too.

        >>> r = CursorRule(description="ok", lambda_axis=LambdaAxisSpec())
        >>> r.validate()[0]
        True
        >>> r2 = CursorRule(description="bad", lambda_axis=LambdaAxisSpec(moralGrounding=0.50))
        >>> r2.validate()[0]
        False
        """
        if not self.description:
            return False, "description is required"
        if self.lambda_axis is not None:
            ok, msg = self.lambda_axis.validate()
            if not ok:
                return False, f"lambda_axis invalid: {msg}"
        return True, "OK"

    def lambda_score(self) -> Optional[float]:
        """Compute Λ-score from lambda_axis if present.

        >>> r = CursorRule(lambda_axis=LambdaAxisSpec())
        >>> r.lambda_score() is not None
        True
        >>> r.lambda_score() >= 0.90
        True
        >>> CursorRule().lambda_score() is None
        True
        """
        if self.lambda_axis is None:
            return None
        return compute_lambda_score(self.lambda_axis.as_vector())

    @classmethod
    def parse(cls, text: str) -> "CursorRule":
        """Parse .mdc text (YAML frontmatter + body).

        Handles both simple scalar values and nested lambda_axis blocks.
        Source for .mdc format: https://forum.cursor.com/t/my-take-on-cursor-rules/67535

        >>> _s = chr(10).join(["---", 'description: "Hello"', "---", "Body text."])
        >>> r = CursorRule.parse(_s)
        >>> r.description == "Hello"
        True
        >>> r.body.strip() == "Body text."
        True
        >>> r2 = CursorRule.parse('No frontmatter here.')
        >>> r2.body.strip() == "No frontmatter here."
        True
        """
        rule = cls()
        if not text.startswith("---"):
            rule.body = text
            return rule

        # Split on second ---
        parts = re.split("\\n---\\n", text, maxsplit=1)
        if len(parts) == 1:
            rule.body = text
            return rule

        frontmatter_raw = parts[0].lstrip("-").strip()
        rule.body = parts[1] if len(parts) > 1 else ""

        # Simple YAML parser (no external deps)
        lambda_lines: List[str] = []
        in_lambda = False
        lambda_axis_dict: Dict[str, float] = {}

        for line in frontmatter_raw.splitlines():
            stripped = line.strip()
            if stripped.startswith("lambda_axis:"):
                in_lambda = True
                continue
            if in_lambda:
                if stripped and not stripped.startswith("#"):
                    if re.match(r"^\w+:\s", stripped):
                        kv = stripped.split(":", 1)
                        if len(kv) == 2:
                            key = kv[0].strip()
                            val_str = kv[1].strip()
                            try:
                                lambda_axis_dict[key] = float(val_str)
                            except ValueError:
                                pass
                    elif re.match(r"^[a-z]", stripped) and ":" not in stripped:
                        # End of lambda block
                        in_lambda = False
                continue

            if stripped.startswith("description:"):
                val = stripped[len("description:"):].strip().strip('"').strip("'")
                rule.description = val
            elif stripped.startswith("alwaysApply:"):
                val = stripped[len("alwaysApply:"):].strip().lower()
                rule.always_apply = (val == "true")
            elif stripped.startswith("lambda_threshold:"):
                try:
                    rule.lambda_threshold = float(stripped.split(":", 1)[1].strip())
                except ValueError:
                    pass
            elif stripped.startswith("emit_receipt:"):
                val = stripped.split(":", 1)[1].strip().lower()
                rule.emit_receipt = (val == "true")
            elif stripped.startswith("receipt_chain:"):
                rule.receipt_chain = stripped.split(":", 1)[1].strip().strip('"')
            elif stripped.startswith("globs:"):
                globs_str = stripped[len("globs:"):].strip()
                if globs_str.startswith("["):
                    items = re.findall(r'"([^"]*)"', globs_str)
                    rule.globs = items

        if lambda_axis_dict:
            rule.lambda_axis = LambdaAxisSpec.from_dict(lambda_axis_dict)

        return rule


