# GRAFT B — ClaudeCodeSubAgent
# Parser and invoker pendant for .claude/agents/*.md files.
# Attribution: Claude Code subagents: https://docs.anthropic.com/en/docs/claude-code/sub-agents
# Innovation: doctrine-v6 subagent pattern (SZL Holdings, NEW — v18.18)
# ─────────────────────────────────────────────────────────────────────────────

@dataclass
class ClaudeCodeSubAgent:
    """Parsed .claude/agents/*.md subagent definition.

    Represents a Claude Code custom subagent specification.
    Required fields per spec: name, description.
    Optional: tools, model, permissionMode, maxTurns, memory, background, etc.

    Attribution:
    - Subagent format: https://docs.anthropic.com/en/docs/claude-code/sub-agents
    - Graft B: a11oy-doctrine-v6 subagent (SZL Holdings, NEW)

    >>> _agmd = chr(10).join(["---", "name: a11oy-doctrine-v6", 'description: "SZL doctrine-v6 governance subagent"', "tools: Read, Glob, Grep, Bash", "model: claude-opus-4-8", "permissionMode: plan", "maxTurns: 20", "memory: project", "effort: high", "---", "You are the governance subagent."])
    >>> agent = ClaudeCodeSubAgent.parse(_agmd)
    >>> agent.name == "a11oy-doctrine-v6"
    True
    >>> agent.model == "claude-opus-4-8"
    True
    >>> "Read" in agent.tools
    True
    >>> agent.max_turns == 20
    True
    >>> agent.validate()[0]
    True
    """

    name: str = ""
    description: str = ""
    tools: List[str] = field(default_factory=list)
    disallowed_tools: List[str] = field(default_factory=list)
    model: str = "inherit"
    permission_mode: str = "default"
    max_turns: int = 0       # 0 = unlimited
    memory: str = ""
    background: bool = False
    effort: str = ""
    isolation: str = ""
    color: str = ""
    body: str = ""           # The system prompt (Markdown body)

    def validate(self) -> Tuple[bool, str]:
        """Validate required fields per Claude Code subagent spec.

        >>> ClaudeCodeSubAgent(name="test", description="desc").validate()[0]
        True
        >>> ClaudeCodeSubAgent(name="", description="desc").validate()[0]
        False
        >>> ClaudeCodeSubAgent(name="test", description="").validate()[0]
        False
        >>> ClaudeCodeSubAgent(name="Bad Name", description="ok").validate()[0]
        False
        """
        if not self.name:
            return False, "name is required"
        if not self.description:
            return False, "description is required"
        # name must be lowercase letters and hyphens only
        if not re.match(r"^[a-z][a-z0-9-]*$", self.name):
            return False, f"name '{self.name}' must be lowercase letters, digits, hyphens"
        return True, "OK"

    def invoke_description(self) -> str:
        """Return a description suitable for Claude delegation prompt.

        >>> a = ClaudeCodeSubAgent(name="audit", description="Runs audit checks")
        >>> "audit" in a.invoke_description()
        True
        """
        tools_str = ", ".join(self.tools) if self.tools else "all tools"
        model_str = self.model if self.model != "inherit" else "session default"
        lines_out = [
            f"Subagent: @{self.name}",
            f"Description: {self.description}",
            f"Tools: {tools_str}",
            f"Model: {model_str}",
            f"Permission mode: {self.permission_mode}",
        ]
        return chr(10).join(lines_out) + chr(10)

    @classmethod
    def parse(cls, text: str) -> "ClaudeCodeSubAgent":
        """Parse .md file with YAML frontmatter.

        Source: https://docs.anthropic.com/en/docs/claude-code/sub-agents

        >>> _sa = chr(10).join(["---", "name: test-agent", 'description: "Testing"', "---", "Body."])
        >>> a = ClaudeCodeSubAgent.parse(_sa)
        >>> a.name == "test-agent"
        True
        >>> a.body.strip() == "Body."
        True
        >>> a2 = ClaudeCodeSubAgent.parse('No frontmatter.')
        >>> a2.name == ""
        True
        >>> a2.body.strip() == "No frontmatter."
        True
        """
        agent = cls()
        if not text.startswith("---"):
            agent.body = text
            return agent

        parts = re.split("\\n---\\n", text, maxsplit=1)
        if len(parts) == 1:
            agent.body = text
            return agent

        frontmatter_raw = parts[0].lstrip("-").strip()
        agent.body = parts[1] if len(parts) > 1 else ""

        for line in frontmatter_raw.splitlines():
            stripped = line.strip()
            if ":" not in stripped:
                continue
            key, _, val = stripped.partition(":")
            key = key.strip()
            val = val.strip().strip('"').strip("'")

            if key == "name":
                agent.name = val
            elif key == "description":
                agent.description = val
            elif key == "tools":
                agent.tools = [t.strip() for t in val.split(",") if t.strip()]
            elif key == "disallowedTools":
                agent.disallowed_tools = [t.strip() for t in val.split(",") if t.strip()]
            elif key == "model":
                agent.model = val
            elif key == "permissionMode":
                agent.permission_mode = val
            elif key == "maxTurns":
                try:
                    agent.max_turns = int(val)
                except ValueError:
                    pass
            elif key == "memory":
                agent.memory = val
            elif key == "background":
                agent.background = (val.lower() == "true")
            elif key == "effort":
                agent.effort = val
            elif key == "isolation":
                agent.isolation = val
            elif key == "color":
                agent.color = val

        return agent


