# GRAFT C — composer_receipt_chain
# Runtime pendant for Lutar.AgenticIDELambda theorem.
# Produces and verifies SHA-256 receipt chains over agentic-IDE edits.
# Attribution: Wheeler chain — https://doi.org/10.5281/zenodo.20431181 (v17 §4)
# Innovation: AgenticEdit struct + chain builder (SZL Holdings, NEW — v18.18)
# ─────────────────────────────────────────────────────────────────────────────

@dataclass
class AgenticEdit:
    """One agentic-IDE edit wrapped in a receipt.

    Corresponds to Lutar.AgenticIDELambda.AgenticEdit (Lean 4 struct).
    Source: szl_cursor_claude_graft_design.md Graft C.

    >>> e = AgenticEdit(
    ...     edit_id="e1",
    ...     session_id="s1",
    ...     tool_name="Edit",
    ...     path="/foo/bar.py",
    ...     sha256_before=b'a' * 32,
    ...     sha256_after=b'b' * 32,
    ...     lambda_score=0.95,
    ...     timestamp_ms=1000,
    ... )
    >>> e.tool_name == "Edit"
    True
    >>> e.lambda_score >= 0.90
    True
    """
    edit_id: str
    session_id: str
    tool_name: str          # "Edit" | "Write" | "NotebookEdit"
    path: str
    sha256_before: bytes    # SHA-256 of file before edit
    sha256_after: bytes     # SHA-256 of file after edit
    lambda_score: float     # Λ-score at time of edit (should be ≥ 0.90)
    timestamp_ms: int
    receipt_sha: bytes = field(default_factory=bytes)    # SHA-256 of canonical fields
    chain_root: bytes = field(default_factory=bytes)     # SHA-256(prev.receipt_sha ++ this.receipt_sha)

    def canonical_fields(self) -> bytes:
        """Return canonical bytes for receipt hashing.

        >>> e = AgenticEdit("eid","sid","Edit","/f.py",b'x'*32,b'y'*32,0.95,1000)
        >>> isinstance(e.canonical_fields(), bytes)
        True
        >>> len(e.canonical_fields()) > 0
        True
        """
        return json.dumps({
            "edit_id": self.edit_id,
            "session_id": self.session_id,
            "tool_name": self.tool_name,
            "path": self.path,
            "sha256_before": self.sha256_before.hex(),
            "sha256_after": self.sha256_after.hex(),
            "lambda_score": self.lambda_score,
            "timestamp_ms": self.timestamp_ms,
        }, sort_keys=True).encode("utf-8")


def compute_receipt_sha(edit: AgenticEdit) -> bytes:
    """Compute SHA-256 of canonical fields.

    >>> e = AgenticEdit("e1","s1","Edit","/f.py",b'a'*32,b'b'*32,0.95,1000)
    >>> sha = compute_receipt_sha(e)
    >>> len(sha) == 32
    True
    >>> sha2 = compute_receipt_sha(e)
    >>> sha == sha2
    True
    """
    return hashlib.sha256(edit.canonical_fields()).digest()


def compute_chain_root(prev_receipt_sha: bytes, this_receipt_sha: bytes) -> bytes:
    """Compute chain root: SHA-256(prev ++ this).

    This implements the Wheeler receipt chain link.
    Source: https://doi.org/10.5281/zenodo.20431181 (v17 §4)

    >>> prev = b'p' * 32
    >>> this = b't' * 32
    >>> root = compute_chain_root(prev, this)
    >>> len(root) == 32
    True
    >>> root != prev
    True
    >>> root != this
    True
    """
    return hashlib.sha256(prev_receipt_sha + this_receipt_sha).digest()


def composer_receipt_chain(edits: List[AgenticEdit]) -> List[AgenticEdit]:
    """Build a SHA-256 receipt chain over a sequence of agentic-IDE edits.

    Returns the same edits with receipt_sha and chain_root populated.
    The chain is a total order: edit i precedes edit j iff i < j in the list,
    enforced cryptographically by the SHA-chain.

    This is the Python runtime pendant of Lutar.AgenticIDELambda.composer_receipt_chain_total_order.
    Source: szl_cursor_claude_graft_design.md Graft C.
    Wheeler chain DOI: https://doi.org/10.5281/zenodo.20431181

    >>> e1 = AgenticEdit("e1","s1","Edit","/f.py",b'a'*32,b'b'*32,0.95,1000)
    >>> e2 = AgenticEdit("e2","s1","Write","/g.py",b'c'*32,b'd'*32,0.92,2000)
    >>> chain = composer_receipt_chain([e1, e2])
    >>> len(chain) == 2
    True
    >>> len(chain[0].receipt_sha) == 32
    True
    >>> len(chain[1].chain_root) == 32
    True
    >>> chain[1].chain_root == compute_chain_root(chain[0].receipt_sha, chain[1].receipt_sha)
    True
    >>> chain[0].chain_root == chain[0].receipt_sha
    True
    """
    GENESIS = bytes(32)  # 32 zero bytes = genesis receipt_sha for the chain
    prev_receipt_sha = GENESIS
    result = []

    for edit in edits:
        # Compute receipt_sha from canonical fields
        receipt_sha = compute_receipt_sha(edit)
        # Compute chain_root = SHA256(prev_receipt_sha ++ receipt_sha)
        if prev_receipt_sha == GENESIS:
            chain_root = receipt_sha  # First edit: chain_root = receipt_sha
        else:
            chain_root = compute_chain_root(prev_receipt_sha, receipt_sha)

        import copy
        updated = copy.copy(edit)
        updated.receipt_sha = receipt_sha
        updated.chain_root = chain_root
        result.append(updated)
        prev_receipt_sha = receipt_sha

    return result


def verify_receipt_chain(chain: List[AgenticEdit]) -> Tuple[bool, str]:
    """Verify that a receipt chain is well-formed (no tampering).

    Checks:
    1. receipt_sha = SHA256(canonical_fields) for each edit
    2. chain_root[i] = SHA256(receipt_sha[i-1] ++ receipt_sha[i]) for i > 0
    3. chain_root[0] = receipt_sha[0]

    >>> e1 = AgenticEdit("e1","s1","Edit","/f.py",b'a'*32,b'b'*32,0.95,1000)
    >>> e2 = AgenticEdit("e2","s1","Write","/g.py",b'c'*32,b'd'*32,0.92,2000)
    >>> chain = composer_receipt_chain([e1, e2])
    >>> verify_receipt_chain(chain)[0]
    True
    >>> # Tamper with an edit
    >>> import copy
    >>> bad = list(chain)
    >>> bad_edit = copy.copy(chain[0])
    >>> bad_edit.lambda_score = 0.01  # Tampering
    >>> bad[0] = bad_edit
    >>> verify_receipt_chain(bad)[0]
    False
    """
    if not chain:
        return True, "empty chain is trivially valid"

    for i, edit in enumerate(chain):
        expected_receipt = compute_receipt_sha(edit)
        if edit.receipt_sha != expected_receipt:
            return False, f"receipt_sha mismatch at index {i}: tampering detected"

        if i == 0:
            if edit.chain_root != edit.receipt_sha:
                return False, f"chain_root mismatch at index 0"
        else:
            expected_root = compute_chain_root(chain[i-1].receipt_sha, edit.receipt_sha)
            if edit.chain_root != expected_root:
                return False, f"chain_root mismatch at index {i}: chain broken"

    return True, "OK"


