def run_self_tests() -> int:
    """Run all self-tests. Returns 0 on success, positive int on failure.

    Emits: [v18.18 Cursor+Claude] OK <N> tests
    """
    import doctest
    import sys

    failures = 0
    test_count = 0

    # ── SECTION A: CursorRule ────────────────────────────────────────────────

    # A1: Parse minimal rule (no lambda_axis)
    r = CursorRule.parse(chr(10).join(["---", 'description: "simple"', "---", "Body text."]))
    assert r.description == "simple", f"A1 fail: {r.description}"
    assert r.body.strip() == "Body text.", f"A1 body fail: {r.body}"
    test_count += 1

    # A2: Parse rule with globs
    r2 = CursorRule.parse(chr(10).join(["---", 'description: "with globs"', 'globs: ["**/*.py"]', "---", "body"]))
    assert "**/*.py" in r2.globs, f"A2 fail: {r2.globs}"
    test_count += 1

    # A3: Parse rule without frontmatter
    r3 = CursorRule.parse("Just a body.")
    assert r3.description == "", f"A3 fail: {r3.description}"
    assert "Just a body" in r3.body, f"A3 body fail: {r3.body}"
    test_count += 1

    # A4: Validate rule with valid lambda_axis
    r4 = CursorRule(
        description="test",
        lambda_axis=LambdaAxisSpec(
            moralGrounding=0.97, measurabilityHonesty=0.97,
            reversibility=0.90, scopeBoundedness=0.95,
            convergenceSignal=0.92, auditTrailIntegrity=0.99,
            doctrineCompliance=0.99, stakeholderTransparency=0.97,
            informationBoundedness=0.95,
        )
    )
    ok, msg = r4.validate()
    assert ok, f"A4 fail: {msg}"
    test_count += 1

    # A5: Validate rule with bad moralGrounding
    r5 = CursorRule(description="bad", lambda_axis=LambdaAxisSpec(moralGrounding=0.80))
    ok5, msg5 = r5.validate()
    assert not ok5, f"A5 fail: expected failure"
    assert "moralGrounding" in msg5, f"A5 fail: {msg5}"
    test_count += 1

    # A6: lambda_score returns None without lambda_axis
    r6 = CursorRule(description="no lambda")
    assert r6.lambda_score() is None, "A6 fail: expected None"
    test_count += 1

    # A7: lambda_score correct value
    vec = [0.97] * 9
    r7 = CursorRule(description="ok", lambda_axis=LambdaAxisSpec.from_dict({k: 0.97 for k in LAMBDA_AXIS_LABELS}))
    expected = compute_lambda_score(vec)
    assert abs(r7.lambda_score() - expected) < 1e-9, f"A7 fail: {r7.lambda_score()} vs {expected}"
    test_count += 1

    # ── SECTION B: ClaudeCodeSubAgent ────────────────────────────────────────

    MD = """---
name: a11oy-doctrine-v6
description: "SZL doctrine-v6 governance subagent"
tools: Read, Glob, Grep
model: claude-opus-4-8
permissionMode: plan
maxTurns: 20
memory: project
effort: high
---
You are the governance subagent."""

    # B1: Parse subagent
    a = ClaudeCodeSubAgent.parse(MD)
    assert a.name == "a11oy-doctrine-v6", f"B1 fail: {a.name}"
    test_count += 1

    # B2: Tools parsed
    assert "Read" in a.tools, f"B2 fail: {a.tools}"
    assert "Grep" in a.tools, f"B2 fail: {a.tools}"
    test_count += 1

    # B3: Model parsed
    assert a.model == "claude-opus-4-8", f"B3 fail: {a.model}"
    test_count += 1

    # B4: maxTurns parsed
    assert a.max_turns == 20, f"B4 fail: {a.max_turns}"
    test_count += 1

    # B5: Validate passes
    ok_b, msg_b = a.validate()
    assert ok_b, f"B5 fail: {msg_b}"
    test_count += 1

    # B6: Invalid name fails
    bad_agent = ClaudeCodeSubAgent(name="Bad Name", description="ok")
    ok_bad, _ = bad_agent.validate()
    assert not ok_bad, "B6 fail: expected validation failure"
    test_count += 1

    # B7: Empty name fails
    empty_agent = ClaudeCodeSubAgent(name="", description="ok")
    ok_empty, _ = empty_agent.validate()
    assert not ok_empty, "B7 fail"
    test_count += 1

    # B8: invoke_description contains name
    desc = a.invoke_description()
    assert "a11oy-doctrine-v6" in desc, f"B8 fail: {desc}"
    test_count += 1

    # B9: Parse no-frontmatter
    a9 = ClaudeCodeSubAgent.parse("No frontmatter at all.")
    assert a9.name == "", f"B9 fail: {a9.name}"
    assert "No frontmatter" in a9.body, f"B9 body fail: {a9.body}"
    test_count += 1

    # ── SECTION C: composer_receipt_chain ────────────────────────────────────

    e1 = AgenticEdit("e1", "s1", "Edit", "/f.py", b"a" * 32, b"b" * 32, 0.95, 1000)
    e2 = AgenticEdit("e2", "s1", "Write", "/g.py", b"c" * 32, b"d" * 32, 0.92, 2000)
    e3 = AgenticEdit("e3", "s1", "Edit", "/h.py", b"e" * 32, b"f" * 32, 0.97, 3000)

    # C1: Chain has correct length
    chain = composer_receipt_chain([e1, e2, e3])
    assert len(chain) == 3, f"C1 fail: {len(chain)}"
    test_count += 1

    # C2: All receipts have non-empty sha
    for i, ce in enumerate(chain):
        assert len(ce.receipt_sha) == 32, f"C2 fail at {i}"
    test_count += 1

    # C3: Chain root of index 0 == receipt_sha of index 0
    assert chain[0].chain_root == chain[0].receipt_sha, "C3 fail"
    test_count += 1

    # C4: Chain root of index 1 = SHA256(receipt_sha[0] ++ receipt_sha[1])
    expected_root_1 = compute_chain_root(chain[0].receipt_sha, chain[1].receipt_sha)
    assert chain[1].chain_root == expected_root_1, "C4 fail"
    test_count += 1

    # C5: Verification passes
    ok_c, msg_c = verify_receipt_chain(chain)
    assert ok_c, f"C5 fail: {msg_c}"
    test_count += 1

    # C6: Tampered chain fails verification
    import copy as _copy
    bad_chain = list(chain)
    bad_e = _copy.copy(chain[1])
    bad_e.lambda_score = 0.01  # Tamper
    bad_chain[1] = bad_e
    ok_bad_c, _ = verify_receipt_chain(bad_chain)
    assert not ok_bad_c, "C6 fail: expected chain verification failure"
    test_count += 1

    # C7: Empty chain verification
    ok_empty_c, _ = verify_receipt_chain([])
    assert ok_empty_c, "C7 fail: empty chain should be valid"
    test_count += 1

    # C8: compute_receipt_sha is deterministic
    sha1 = compute_receipt_sha(e1)
    sha2 = compute_receipt_sha(e1)
    assert sha1 == sha2, "C8 fail: receipt_sha not deterministic"
    test_count += 1

    # ── SECTION D: MCPLambdaServer ───────────────────────────────────────────

    server = MCPLambdaServer(lambda_threshold=0.90)

    # D1: list_tools returns 5 tools
    tools = server.list_tools()
    assert len(tools) == 5, f"D1 fail: {len(tools)}"
    test_count += 1

    # D2: lambda_check admit on good vector
    receipt = server.a11oy__lambda_check("Read", {}, [0.97] * 9)
    assert receipt.gate_decision == "admit", f"D2 fail: {receipt.gate_decision}"
    test_count += 1

    # D3: lambda_check halt on bad moral grounding
