def _lambda_gate(grade_vec: dict) -> float:
    """Reference software Λ-gate (doctrine v6 canonical form).

    Computes the SZL Λ-gate value from a 9-axis grade vector.
    Each axis_i ∈ [0.0, 1.0]. Returns float in [0.0, 1.0].
    Formula: geometric mean of (min_axis, equal-weight harmonic mean).

    >>> abs(_lambda_gate({f'axis_{i}': 1.0 for i in range(1,10)}) - 1.0) < 1e-9
    True
    >>> _lambda_gate({'axis_1': 0.0, **{f'axis_{i}': 1.0 for i in range(2,10)}}) == 0.0
    True
    >>> v = _lambda_gate({'axis_1': 0.6, 'axis_2': 0.7, 'axis_3': 0.8,
    ...     'axis_4': 0.9, 'axis_5': 0.5, 'axis_6': 0.8,
    ...     'axis_7': 0.75, 'axis_8': 0.85, 'axis_9': 0.9})
    >>> 0.0 < v < 1.0
    True
    """
    axes = [float(grade_vec.get(f"axis_{i}", 0.0)) for i in range(1, 10)]
    min_axis = min(axes)
    if min_axis <= 0.0:
        return 0.0
    wh_mean = 9.0 / sum(1.0 / max(a, 1e-12) for a in axes)
    return math.sqrt(min_axis * wh_mean)


def _utc_now() -> str:
    """Return current UTC time as ISO-8601 string.

    >>> import re
    >>> bool(re.match(r'\\d{4}-\\d{2}-\\d{2}T', _utc_now()))
    True
    """
    return datetime.now(timezone.utc).isoformat()


def _sha256_str(s: str) -> str:
    """SHA-256 hex digest of a UTF-8 string.

    >>> len(_sha256_str('hello')) == 64
    True
    >>> _sha256_str('hello') != _sha256_str('world')
    True
    """
    return hashlib.sha256(s.encode()).hexdigest()


def _sha256_dict(d: dict) -> str:
    """SHA-256 hex digest of a canonical JSON serialisation of a dict.

    >>> len(_sha256_dict({'a': 1, 'b': 2})) == 64
    True
    >>> _sha256_dict({'a': 1}) == _sha256_dict({'a': 1})
    True
    >>> _sha256_dict({'a': 1}) != _sha256_dict({'a': 2})
    True
    """
    canonical = json.dumps(d, sort_keys=True, separators=(',', ':'))
    return hashlib.sha256(canonical.encode()).hexdigest()


