@dataclass
class BinaryArtifact:
    """An abstract binary artifact subject to dual-witness analysis.

    >>> b = BinaryArtifact('a'*64, 1024, 'PE32')
    >>> len(b.sha256) == 64
    True
    >>> b.size_bytes > 0
    True
    """
    sha256: str
    size_bytes: int
    artifact_type: str  # e.g., 'PE32', 'ELF64', 'Mach-O', 'container-layer'


@dataclass
class BinaryDualWitnessClassifier:
    """Dual-witness binary malware classifier: classifier + threat-repo lookup.

    Implements Lutar.BinaryDualWitness theorem:
    `binary_decomp_dual_witness_precision`: DW FPR = clf_fpr * repo_fpr < clf_fpr.
    Two independent detection paths (ML classifier + repository lookup) yield
    strictly lower false-positive rate than either individual detector.

    Upstream: ReversingLabs IQT partnership Feb 2012:
    https://www.reversinglabs.com/press-releases/reversinglabs-and-iqt-enter-strategic-partnership
    MIT SDK: https://github.com/reversinglabs (reversinglabs-sdk-py3)
    MIT YARA rules: https://github.com/reversinglabs (reversinglabs-yara-rules)
    TitaniumCore binary engine: [LICENSE-RESTRICTED] — pattern only.
    Derives from: v15 PACBayes, v18.11 xdr_correlated_detection. 0 new axioms.

    Attributes:
        classifier_fpr: False-positive rate of ML classifier channel (0 < fpr < 1).
        repo_fpr: False-positive rate of repository lookup channel (0 < fpr < 1).
        repo_size: Size of threat repository (ReversingLabs: 422B+ files).

    >>> clf = BinaryDualWitnessClassifier(classifier_fpr=0.05, repo_fpr=0.02, repo_size=422_000_000_000)
    >>> clf.dual_fpr()
    0.001
    >>> clf.dual_fpr() < clf.classifier_fpr
    True
    >>> clf.dual_fpr() < clf.repo_fpr
    True
    >>> clf.precision_lb() > 0.5
    True
    """
    classifier_fpr: float
    repo_fpr: float
    repo_size: int  # ReversingLabs: 422B+ files as of 2024

    def __post_init__(self) -> None:
        assert 0 < self.classifier_fpr < 1, "classifier_fpr must be in (0,1)"
        assert 0 < self.repo_fpr < 1, "repo_fpr must be in (0,1)"
        assert self.repo_size > 0, "repo_size must be positive"

    def dual_fpr(self) -> float:
        """Dual-witness FPR: product of independent channel FPRs.

        Implements binary_decomp_dual_witness_precision:
        FPR(DW) = classifier_fpr * repo_fpr < classifier_fpr (when repo_fpr < 1).

        >>> clf = BinaryDualWitnessClassifier(0.1, 0.05, 1_000_000)
        >>> clf.dual_fpr()
        0.005
        >>> clf.dual_fpr() < clf.classifier_fpr
        True
        """
        return round(self.classifier_fpr * self.repo_fpr, 10)

    def precision_lb(self) -> float:
        """Lower bound on precision from dual-witness combination.

        Precision = TP / (TP + FP). With dual FPR = clf_fpr * repo_fpr,
        precision lower bound = 1 - dual_fpr (assuming TP rate ≥ 0.5).

        >>> clf = BinaryDualWitnessClassifier(0.05, 0.02, 1_000_000)
        >>> clf.precision_lb() > 0.5
        True
        >>> clf.precision_lb() > 0.99
        True
        """
        return 1.0 - self.dual_fpr()

    def classify(self, artifact: BinaryArtifact) -> Dict:
        """Produce a dual-witness classification receipt for an artifact.

        Returns a dict with classifier verdict, repo verdict, DW verdict,
        FPR details, and a Λ-receipt hash.

        >>> clf = BinaryDualWitnessClassifier(0.05, 0.02, 422_000_000_000)
        >>> b = BinaryArtifact('deadbeef'*8, 2048, 'PE32')
        >>> r = clf.classify(b)
        >>> 'lambda_receipt' in r
        True
        >>> 'dual_fpr' in r
        True
        >>> r['precision_lb'] > 0.5
        True
        """
        # Deterministic mock classification based on SHA prefix
        sha_prefix_val = int(artifact.sha256[:4], 16) if len(artifact.sha256) >= 4 else 0
        clf_verdict = sha_prefix_val % 7 == 0  # ~14% positives
        repo_verdict = sha_prefix_val % 13 == 0  # ~8% positives
        dw_verdict = clf_verdict and repo_verdict
        payload = {
            "artifact_sha256": artifact.sha256,
            "artifact_type": artifact.artifact_type,
            "classifier_verdict": clf_verdict,
            "repo_verdict": repo_verdict,
            "dual_witness_verdict": dw_verdict,
            "classifier_fpr": self.classifier_fpr,
            "repo_fpr": self.repo_fpr,
            "dual_fpr": self.dual_fpr(),
            "precision_lb": round(self.precision_lb(), 6),
            "repo_size": self.repo_size,
            "timestamp": _utc_now(),
            "upstream_ref": "ReversingLabs IQT 2012; MIT SDK; TitaniumCore [LICENSE-RESTRICTED]",
        }
        payload["lambda_receipt"] = _sha256_dict(payload)
        return payload


