@dataclass
class NLPClaimReceipt:
    """A single NLP claim with Λ-receipt, anchored to an evidence span.

    Models the Primer `primer_quicksilver` claim structure:
    entity → claim → span citation → Λ-receipt.

    Primer AI IQT investment Oct 2017:
    https://www.iqt.org/library/primer-announces-strategic-investment-agreement-with-in-q-tel
    primer_quicksilver Apache-2.0: https://github.com/primerai
    Primer Engines API: https://primer.ai

    Attributes:
        text: The claim text (natural language assertion).
        source_doc: Document identifier (URL, file path, or UUID).
        span_start: Character offset start in source document.
        span_end: Character offset end (exclusive) in source document.
        model_version: NLP model version that generated the claim.
        confidence: Model confidence in [0.0, 1.0].
        timestamp: Unix epoch seconds of claim generation.

    >>> c = NLPClaimReceipt('Market share grew 15%', 'doc-abc123', 42, 63, 'primer-v3.1', 0.92, 1748390400)
    >>> c.is_valid()
    True
    >>> len(c.lambda_receipt()) == 64
    True
    >>> c.evidence_span_address()
    'doc-abc123[42:63]'
    """
    text: str
    source_doc: str
    span_start: int
    span_end: int
    model_version: str
    confidence: float
    timestamp: int  # Unix epoch seconds

    def is_valid(self) -> bool:
        """Check that the claim has a non-empty evidence span.

        Implements claim_valid predicate from Lutar.ClaimReceiptChain.

        >>> NLPClaimReceipt('x', 'doc', 0, 5, 'v1', 0.9, 0).is_valid()
        True
        >>> NLPClaimReceipt('x', 'doc', 5, 5, 'v1', 0.9, 0).is_valid()
        False
        >>> NLPClaimReceipt('x', 'doc', 6, 3, 'v1', 0.9, 0).is_valid()
        False
        """
        return self.span_end > self.span_start

    def evidence_span_address(self) -> str:
        """Return a canonical evidence span address string.

        Implements the EvidenceSpan function from Lutar.ClaimReceiptChain.

        >>> c = NLPClaimReceipt('test', 'doc-001', 10, 20, 'v1', 0.8, 0)
        >>> c.evidence_span_address()
        'doc-001[10:20]'
        """
        return f"{self.source_doc}[{self.span_start}:{self.span_end}]"

    def lambda_receipt(self) -> str:
        """Compute SHA-256 Λ-receipt for this claim.

        Receipt = SHA-256(text | evidence_span | model_version).
        Verifiable against the source document via span address.

        >>> c = NLPClaimReceipt('GDP grew 3%', 'report-2025', 0, 11, 'primer-v3', 0.91, 1748000000)
        >>> len(c.lambda_receipt()) == 64
        True
        >>> c.lambda_receipt() == c.lambda_receipt()
        True
        """
        payload = f"{self.text}|{self.evidence_span_address()}|{self.model_version}"
        return _sha256_str(payload)


@dataclass
class ClaimReceiptChain:
    """An ordered chain of NLP claim receipts (consistent iff all valid and temporally ordered).

    Implements Lutar.ClaimReceiptChain theorems:
    - nlp_claim_receipt_chain_consistency: chain consistent iff every claim valid + ordered
    - chain_prepend_consistent: prepending earlier valid claim preserves consistency
    Axiom: claim_evidence_span_uniqueness (each span address uniquely identifies a region).

    Primer AI IQT investment Oct 2017:
    https://www.iqt.org/library/primer-announces-strategic-investment-agreement-with-in-q-tel
    Cross-ref: v18.9 Palantir ontology (claim provenance), v18.16 AIMS@COLM26 (eval evidence).

    Attributes:
        claims: List of NLPClaimReceipt in ascending timestamp order.
        chain_sha256: SHA-256 of the ordered receipt sequence.

    >>> c1 = NLPClaimReceipt('Claim A', 'doc-1', 0, 10, 'v1', 0.9, 1000)
    >>> c2 = NLPClaimReceipt('Claim B', 'doc-1', 11, 25, 'v1', 0.85, 2000)
    >>> chain = ClaimReceiptChain.build([c1, c2])
    >>> chain.is_consistent()
    True
    >>> len(chain.chain_sha256) == 64
    True
    """
    claims: List[NLPClaimReceipt]
    chain_sha256: str

    @classmethod
    def build(cls, claims: List[NLPClaimReceipt]) -> "ClaimReceiptChain":
        """Build a claim chain from a list, sorted by timestamp.

        Implements base + induction of chain_consistent.

        >>> c = NLPClaimReceipt('test', 'doc', 0, 4, 'v1', 0.8, 100)
        >>> chain = ClaimReceiptChain.build([c])
        >>> chain.is_consistent()
        True
        """
        sorted_claims = sorted(claims, key=lambda c: c.timestamp)
        receipts = [c.lambda_receipt() for c in sorted_claims]
        chain_sha = _sha256_str("|".join(receipts))
        return cls(claims=sorted_claims, chain_sha256=chain_sha)

    def is_consistent(self) -> bool:
        """Return True iff all claims are valid and timestamps are non-decreasing.

        Implements chain_consistent predicate from Lutar.ClaimReceiptChain.

        >>> c1 = NLPClaimReceipt('A', 'doc', 0, 1, 'v1', 0.9, 100)
        >>> c2 = NLPClaimReceipt('B', 'doc', 2, 5, 'v1', 0.9, 200)
        >>> ClaimReceiptChain.build([c1, c2]).is_consistent()
        True
        >>> bad = NLPClaimReceipt('C', 'doc', 3, 3, 'v1', 0.9, 300)  # invalid span
        >>> ClaimReceiptChain.build([c1, bad]).is_consistent()
        False
        """
        if not all(c.is_valid() for c in self.claims):
            return False
        for i in range(len(self.claims) - 1):
            if self.claims[i].timestamp > self.claims[i + 1].timestamp:
                return False
        return True

    def prepend(self, claim: NLPClaimReceipt) -> "ClaimReceiptChain":
        """Return a new chain with claim prepended (must be earlier).

        Implements chain_prepend_consistent: if claim.timestamp ≤ all existing
        claims' timestamps, the result is consistent.

        >>> c2 = NLPClaimReceipt('Later', 'doc', 5, 10, 'v1', 0.9, 2000)
        >>> c1 = NLPClaimReceipt('Earlier', 'doc', 0, 4, 'v1', 0.9, 1000)
        >>> chain = ClaimReceiptChain.build([c2])
        >>> chain2 = chain.prepend(c1)
        >>> chain2.is_consistent()
        True
        """
        return ClaimReceiptChain.build([claim] + self.claims)


