def run_self_tests() -> int:
    """Run all v18.19 IQT substrate self-tests.

    Executes doctests for all 6 graft pendants + standalone assertions.
    Prints [v18.19 IQT] OK <N> tests on success.
    Returns 0 on all pass, 1 on any failure.
    """
    failures = 0

    # ── Doctest runner ──────────────────────────────────────────────
    print("[v18.19 IQT] Running doctests…")
    results = doctest.testmod(verbose=False)
    if results.failed > 0:
        print(f"[v18.19 IQT] DOCTEST FAILURES: {results.failed}")
        failures += results.failed
    else:
        print(f"[v18.19 IQT] Doctests: {results.attempted} attempted, 0 failed")

    # ── Standalone assertions ────────────────────────────────────────
    assertion_count = 0

    # ── Graft A assertions ───────────────────────────────────────────
    c1 = SBOMComponent("openssl", "3.0.2", "a" * 64, "b" * 64)
    c2 = SBOMComponent("zlib", "1.2.11", "c" * 64, "d" * 64)
    c3 = SBOMComponent("openssl", "3.0.9", "x" * 64, "y" * 64)

    # Total order: totality holds
    assert c1 <= c2 or c2 <= c1, "FAIL: sbom total order totality"
    assertion_count += 1

    # Reflexivity
    assert c1 <= c1, "FAIL: sbom total order reflexivity"
    assertion_count += 1

    # Distinct components have distinct receipts (collision-resistance assumption)
    assert c1.lambda_receipt() != c2.lambda_receipt(), "FAIL: distinct sbom receipts"
    assertion_count += 1

    # Chain build + sort
    chain = SBOMReceiptChain.build([c2, c1])
    assert len(chain.components) == 2, "FAIL: chain length"
    assertion_count += 1
    assert chain.components[0] <= chain.components[1], "FAIL: chain ordering"
    assertion_count += 1
    assert len(chain.sbom_sha256) == 64, "FAIL: chain sha256 length"
    assertion_count += 1

    # Drift detection: dual-witness
    chain_v2 = SBOMReceiptChain.build([c3, c2])
    drift = chain.detect_drift(chain_v2, {"openssl": ["CVE-2024-9999"]})
    assert len(drift) >= 1, "FAIL: drift not detected"
    assertion_count += 1
    drifted_names = {d["component_name"] for d in drift}
    assert "openssl" in drifted_names, "FAIL: openssl drift not found"
    assertion_count += 1
    for d in drift:
        if d["component_name"] == "openssl":
            assert d["sha_witness"] is True, "FAIL: sha_witness not True"
            assertion_count += 1
            assert d["grype_witness"] is True, "FAIL: grype_witness not True"
            assertion_count += 1
            assert d["precision_lb"] > 0.5, "FAIL: precision_lb not > 0.5"
            assertion_count += 1

    # ── Graft B assertions ───────────────────────────────────────────
    clf = BinaryDualWitnessClassifier(classifier_fpr=0.05, repo_fpr=0.02, repo_size=422_000_000_000)
    assert clf.dual_fpr() < clf.classifier_fpr, "FAIL: DW FPR not < clf_fpr"
    assertion_count += 1
    assert clf.dual_fpr() < clf.repo_fpr, "FAIL: DW FPR not < repo_fpr"
    assertion_count += 1
    assert clf.dual_fpr() == 0.001, "FAIL: DW FPR != 0.05*0.02"
    assertion_count += 1
    assert clf.precision_lb() > 0.99, "FAIL: precision_lb not > 0.99"
    assertion_count += 1

    # Classify an artifact
    b = BinaryArtifact("deadbeef" * 8, 2048, "PE32")
    receipt = clf.classify(b)
    assert "lambda_receipt" in receipt, "FAIL: no lambda_receipt in classify result"
    assertion_count += 1
    assert receipt["precision_lb"] > 0.5, "FAIL: classify precision_lb not > 0.5"
    assertion_count += 1
    assert receipt["repo_size"] == 422_000_000_000, "FAIL: repo_size wrong"
    assertion_count += 1

    # ── Graft C assertions ───────────────────────────────────────────
    cr1 = NLPClaimReceipt("GDP grew 3%", "report-2025", 0, 10, "primer-v3.1", 0.91, 1000)
    cr2 = NLPClaimReceipt("Exports rose", "report-2025", 11, 22, "primer-v3.1", 0.87, 2000)
    bad_cr = NLPClaimReceipt("bad span", "report", 5, 5, "v1", 0.9, 3000)

    assert cr1.is_valid(), "FAIL: cr1 should be valid"
    assertion_count += 1
    assert not bad_cr.is_valid(), "FAIL: bad_cr should be invalid"
    assertion_count += 1
    assert cr1.evidence_span_address() == "report-2025[0:10]", "FAIL: span address"
    assertion_count += 1

    chain_c = ClaimReceiptChain.build([cr1, cr2])
    assert chain_c.is_consistent(), "FAIL: claim chain not consistent"
    assertion_count += 1
    assert len(chain_c.chain_sha256) == 64, "FAIL: chain sha256 length"
    assertion_count += 1

    bad_chain = ClaimReceiptChain.build([cr1, bad_cr])
    assert not bad_chain.is_consistent(), "FAIL: bad chain should be inconsistent"
    assertion_count += 1

    # Prepend earlier claim
    cr0 = NLPClaimReceipt("Earlier claim", "report-2025", 0, 5, "v1", 0.8, 500)
    chain_prepended = chain_c.prepend(cr0)
    assert chain_prepended.is_consistent(), "FAIL: prepended chain inconsistent"
    assertion_count += 1
    assert len(chain_prepended.claims) == 3, "FAIL: prepended chain length wrong"
    assertion_count += 1

    # ── Graft D assertions ───────────────────────────────────────────
    asset = InternetAssetLambda("192.0.2.10", 5, 0.75, ["nginx/1.24", "ssh-2.0"])
    assert asset.lambda_score() >= asset.censys_discovery_rate, "FAIL: lambda_bound"
    assertion_count += 1
    assert asset.lambda_score() <= 1.0, "FAIL: lambda_score > 1"
    assertion_count += 1
    assert asset.lambda_bound_holds(), "FAIL: lambda_bound_holds"
    assertion_count += 1

    asset_zero = InternetAssetLambda("0.0.0.0", 0, 0.0, [])
    assert asset_zero.lambda_score() == 0.0, "FAIL: zero asset score"
    assertion_count += 1

    asset_saturated = InternetAssetLambda("1.1.1.1", 200, 0.5, [])
    assert asset_saturated.lambda_score() == 1.0, "FAIL: saturated asset score"
    assertion_count += 1

    receipt_d = asset.to_receipt()
    assert "lambda_receipt" in receipt_d, "FAIL: no lambda_receipt in asset receipt"
    assertion_count += 1
    assert receipt_d["lambda_score"] >= receipt_d["censys_discovery_rate"], "FAIL: receipt bound"
    assertion_count += 1

    # ── Graft E assertions ───────────────────────────────────────────
    now_epoch = 1748390400
    tr1 = ThreatIntelReceipt("evil.com", "domain", "https://rf.example", now_epoch - 100, 90, 3600)
    tr2 = ThreatIntelReceipt("1.2.3.4", "ip", "https://rf.example", now_epoch - 200, 75, 7200)

    assert tr1.is_fresh(now_epoch), "FAIL: tr1 should be fresh"
    assertion_count += 1
    assert not tr1.is_fresh(now_epoch + 4000), "FAIL: tr1 should be expired"
    assertion_count += 1
    assert len(tr1.lambda_receipt()) == 64, "FAIL: threat receipt length"
    assertion_count += 1
    assert tr1.lambda_receipt() == tr1.lambda_receipt(), "FAIL: receipt not deterministic"
    assertion_count += 1

    chain_e = [tr2, tr1]  # newest first (tr2 has earlier timestamp, but tr1 is newer)
    # Reorder for newest-first: tr1 timestamp is now_epoch-100, tr2 is now_epoch-200
    # Ordered means timestamps non-increasing; tr1 > tr2, so ordered is [tr1, tr2]
    chain_ordered = [tr1, tr2]
    assert ThreatIntelReceipt.chain_is_ordered(chain_ordered), "FAIL: chain should be ordered"
    assertion_count += 1
    assert ThreatIntelReceipt.chain_is_freshness_bounded([tr1, tr2], now_epoch), "FAIL: chain not fresh"
    assertion_count += 1
    assert not ThreatIntelReceipt.chain_is_freshness_bounded([tr1, tr2], now_epoch + 100000), "FAIL: should be stale"
    assertion_count += 1

    # ── Graft F assertions ───────────────────────────────────────────
    bus = IQTLabsFedAuditBus()
    assert bus.federated_lambda_score() == 0.0, "FAIL: empty bus score"
    assertion_count += 1

    # Emit from all 5 feeds
    r_gamut = bus.emit("gamutRF", {"freq_mhz": 915.0, "signal_class": "wifi", "snr_db": 12.4})
    assert r_gamut["feed_source"] == "gamutRF", "FAIL: gamutRF source"
    assertion_count += 1
    assert r_gamut["upstream_sha"] == "bdef5c6b", "FAIL: gamutRF SHA"
    assertion_count += 1
    assert "lambda_receipt" in r_gamut, "FAIL: gamutRF receipt missing"
    assertion_count += 1

    r_edge = bus.emit("edgetech-core", {"topic": "sensor/temperature", "value": 22.7, "unit": "C"})
    assert r_edge["upstream_sha"] == "085e5cda", "FAIL: edgetech SHA"
    assertion_count += 1

    r_snow = bus.emit("snowglobe", {"scenario": "cyber_escalation", "turn": 4, "player": "Aggressor"})
    assert r_snow["upstream_sha"] == "5af669ca", "FAIL: snowglobe SHA"
    assertion_count += 1

    r_daisy = bus.emit("daisybell", {"model": "roberta-base", "bias_metric": "AIR", "score": 0.03})
    assert r_daisy["upstream_sha"] == "a585651d", "FAIL: daisybell SHA"
    assertion_count += 1

    r_fake = bus.emit("FakeFinder", {"model": "selimsef", "verdict": "real", "confidence": 0.97})
    assert r_fake["upstream_sha"] == "780839f2", "FAIL: FakeFinder SHA"
    assertion_count += 1

    # All 5 feeds emitted
    assert len(bus.receipts()) == 5, "FAIL: should have 5 receipts"
    assertion_count += 1

    # Federated score is in valid range
    fed_score = bus.federated_lambda_score()
    assert 0.0 < fed_score <= 1.0, f"FAIL: federated score out of range: {fed_score}"
    assertion_count += 1

    # Chain SHA is deterministic
    sha1 = bus.chain_sha256()
    sha2 = bus.chain_sha256()
    assert sha1 == sha2, "FAIL: chain SHA not deterministic"
    assertion_count += 1
    assert len(sha1) == 64, "FAIL: chain SHA length"
    assertion_count += 1

    # Feed summary
    summary = bus.feed_summary()
    assert summary["gamutRF"] == 1, "FAIL: gamutRF count"
    assertion_count += 1
    assert summary["snowglobe"] == 1, "FAIL: snowglobe count"
    assertion_count += 1

    # ── All upstream SHAs verifiable ────────────────────────────────
    for source, sha in UPSTREAM_SHAS.items():
        assert len(sha) == 8, f"FAIL: {source} SHA not 8 chars: {sha}"
        assertion_count += 1

    # ── Lambda gate boundary conditions ─────────────────────────────
    assert _lambda_gate({f"axis_{i}": 1.0 for i in range(1, 10)}) == 1.0, "FAIL: all-1 gate"
    assertion_count += 1
    assert _lambda_gate({"axis_1": 0.0, **{f"axis_{i}": 1.0 for i in range(2, 10)}}) == 0.0, "FAIL: zero gate"
    assertion_count += 1

    total_tests = results.attempted + assertion_count
    print(f"[v18.19 IQT] OK {total_tests} tests ({results.attempted} doctests + {assertion_count} assertions)")
    return failures


def main() -> None:
    """Entry point — run self-tests and exit with appropriate code."""
    print("=" * 70)
    print("iqt_substrate.py — Ouroboros Thesis v18.19 IQT Sovereign-AI Graft")
    print("Author: Lutar, Stephen P. — ORCID 0009-0001-0110-4173")
    print("Doctrine: v6 — governance/observability/eval/provenance lanes only")
    print("=" * 70)
    failures = run_self_tests()
    if failures == 0:
        print(chr(10) + "GREEN — all tests pass (iqt_substrate.py v18.19)")
        sys.exit(0)
    else:
        print(chr(10) + f"RED — {failures} failure(s) (iqt_substrate.py v18.19)")
        sys.exit(1)


if __name__ == "__main__":
    main()
